-- ==========================================
-- Tabela: user_profiles
-- ==========================================

DROP TABLE IF EXISTS `user_profiles`;
CREATE TABLE `user_profiles` (
  `google_id` varchar(128) NOT NULL,
  `email` varchar(255) NOT NULL,
  `nome` varchar(255) DEFAULT '',
  `avatar_url` varchar(512) DEFAULT NULL,
  `role` enum('professor','admin') DEFAULT 'professor',
  `disciplinas` longtext CHARACTER SET utf8mb4 COLLATE utf8mb4_bin DEFAULT NULL CHECK (json_valid(`disciplinas`)),
  `instituicoes` longtext CHARACTER SET utf8mb4 COLLATE utf8mb4_bin DEFAULT NULL CHECK (json_valid(`instituicoes`)),
  `session_token` varchar(128) DEFAULT NULL,
  `session_expires` datetime DEFAULT NULL,
  `created_at` datetime DEFAULT current_timestamp(),
  `updated_at` datetime DEFAULT current_timestamp() ON UPDATE current_timestamp(),
  PRIMARY KEY (`google_id`),
  KEY `idx_session` (`session_token`),
  KEY `idx_email` (`email`)
) ENGINE=InnoDB DEFAULT CHARSET=utf8mb4 COLLATE=utf8mb4_unicode_ci;


-- ==========================================
-- Tabela: questions
-- ==========================================

DROP TABLE IF EXISTS `questions`;
CREATE TABLE `questions` (
  `id` varchar(64) NOT NULL,
  `created_at` datetime NOT NULL,
  `updated_at` datetime NOT NULL,
  `disciplina` varchar(120) DEFAULT NULL,
  `assunto` varchar(180) DEFAULT NULL,
  `tipo` varchar(50) DEFAULT NULL,
  `dificuldade` varchar(50) DEFAULT NULL,
  `gabarito_mcq` enum('A','B','C','D','E') DEFAULT NULL,
  `gabarito_tf` enum('C','E') DEFAULT NULL,
  `rubric` text DEFAULT NULL,
  `source_kind` enum('original','concurso') DEFAULT NULL,
  `source_concurso` varchar(180) DEFAULT NULL,
  `source_banca` varchar(180) DEFAULT NULL,
  `source_ano` smallint(6) DEFAULT NULL,
  `source_cargo` varchar(180) DEFAULT NULL,
  `source_prova` varchar(180) DEFAULT NULL,
  `source_numero` varchar(64) DEFAULT NULL,
  `author` varchar(120) DEFAULT NULL,
  `author_id` varchar(255) DEFAULT NULL,
  `tags_json` longtext CHARACTER SET utf8mb4 COLLATE utf8mb4_bin DEFAULT NULL CHECK (json_valid(`tags_json`)),
  `metadata_json` longtext CHARACTER SET utf8mb4 COLLATE utf8mb4_bin NOT NULL CHECK (json_valid(`metadata_json`)),
  `content_json` longtext CHARACTER SET utf8mb4 COLLATE utf8mb4_bin NOT NULL CHECK (json_valid(`content_json`)),
  `root_type` varchar(50) DEFAULT NULL,
  PRIMARY KEY (`id`),
  KEY `idx_updated_at` (`updated_at`),
  KEY `idx_disciplina` (`disciplina`),
  KEY `idx_assunto` (`assunto`),
  KEY `idx_tipo` (`tipo`),
  KEY `idx_dificuldade` (`dificuldade`),
  KEY `idx_source` (`source_kind`,`source_banca`,`source_ano`),
  KEY `idx_author_id` (`author_id`),
  KEY `idx_disciplina_assunto` (`disciplina`,`assunto`),
  KEY `idx_tipo_dificuldade` (`tipo`,`dificuldade`),
  KEY `idx_root_type` (`root_type`)
) ENGINE=InnoDB DEFAULT CHARSET=utf8mb4 COLLATE=utf8mb4_unicode_ci;


-- ==========================================
-- Tabela: question_variants
-- ==========================================

DROP TABLE IF EXISTS `question_variants`;
CREATE TABLE `question_variants` (
  `id` varchar(64) NOT NULL,
  `question_id` varchar(64) NOT NULL,
  `created_at` datetime NOT NULL,
  `updated_at` datetime NOT NULL,
  `author` varchar(120) DEFAULT NULL,
  `tags_json` longtext CHARACTER SET utf8mb4 COLLATE utf8mb4_bin DEFAULT NULL CHECK (json_valid(`tags_json`)),
  `metadata_json` longtext CHARACTER SET utf8mb4 COLLATE utf8mb4_bin NOT NULL CHECK (json_valid(`metadata_json`)),
  `content_json` longtext CHARACTER SET utf8mb4 COLLATE utf8mb4_bin NOT NULL CHECK (json_valid(`content_json`)),
  `change_description` text DEFAULT NULL,
  PRIMARY KEY (`id`),
  KEY `idx_question_id` (`question_id`),
  KEY `idx_created_at` (`created_at`),
  KEY `idx_qv_question_updated` (`question_id`,`updated_at` DESC),
  CONSTRAINT `fk_variants_question` FOREIGN KEY (`question_id`) REFERENCES `questions` (`id`) ON DELETE CASCADE
) ENGINE=InnoDB DEFAULT CHARSET=utf8mb4 COLLATE=utf8mb4_unicode_ci;


-- ==========================================
