('12f5dd8c-9cb9-4282-aabb-e265db9683ff', '2026-02-18 15:54:19', '2026-02-18 15:54:19', 'Matemática', 'Geometria Analítica', 'Múltipla Escolha', 'Média', 'B', NULL, NULL, 'concurso', 'FUVEST', 'FUVEST', 2020, NULL, NULL, '22', '{\"id\":\"100387007767191405258\",\"name\":\"Marcos Paulo\"}', '100387007767191405258', '[\"circunferência\",\"distância aos eixos\",\"sistema\"]', '{\"schemaVersion\":1,\"id\":\"12f5dd8c-9cb9-4282-aabb-e265db9683ff\",\"createdAt\":\"2026-02-18T15:53:02.320Z\",\"updatedAt\":\"2026-02-18T15:53:48.261Z\",\"tipo\":\"Múltipla Escolha\",\"dificuldade\":\"Média\",\"tags\":[\"circunferência\",\"distância aos eixos\",\"sistema\"],\"gabarito\":{\"kind\":\"mcq\",\"correct\":\"B\"},\"source\":{\"kind\":\"concurso\",\"concurso\":\"FUVEST\",\"banca\":\"FUVEST\",\"ano\":2020,\"numero\":\"22\"},\"author\":{\"id\":\"100387007767191405258\",\"name\":\"Marcos Paulo\"},\"disciplina\":\"Matemática\",\"assunto\":\"Geometria Analítica\"}', '{\"type\":\"doc\",\"content\":[{\"type\":\"question\",\"attrs\":{\"tipo\":null},\"content\":[{\"type\":\"statement\",\"content\":[{\"type\":\"paragraph\",\"attrs\":{\"textAlign\":null},\"content\":[{\"type\":\"text\",\"text\":\"Um ponto \"},{\"type\":\"math_inline\",\"attrs\":{\"latex\":\"(x,y)\"}},{\"type\":\"text\",\"text\":\" do plano cartesiano pertence ao conjunto F se é equidistante dos eixos \"},{\"type\":\"math_inline\",\"attrs\":{\"latex\":\"OX\"}},{\"type\":\"text\",\"text\":\" e \"},{\"type\":\"math_inline\",\"attrs\":{\"latex\":\"OY\"}},{\"type\":\"text\",\"text\":\" e pertence ao círculo de equação\\n\"},{\"type\":\"math_inline\",\"attrs\":{\"latex\":\"x^{2}+y^{2}-2x-6y+2=0\"}},{\"type\":\"text\",\"text\":\". É correto afirmar que F\"}]}]},{\"type\":\"options\",\"content\":[{\"type\":\"option\",\"attrs\":{\"letter\":\"A\"},\"content\":[{\"type\":\"paragraph\",\"attrs\":{\"textAlign\":null},\"content\":[{\"type\":\"text\",\"text\":\"é um conjunto vazio.\"}]}]},{\"type\":\"option\",\"attrs\":{\"letter\":\"B\"},\"content\":[{\"type\":\"paragraph\",\"attrs\":{\"textAlign\":null},\"content\":[{\"type\":\"text\",\"text\":\"tem exatamente 2 pontos, um no primeiro quadrante e outro no segundo quadrante.\"}]}]},{\"type\":\"option\",\"attrs\":{\"letter\":\"C\"},\"content\":[{\"type\":\"paragraph\",\"attrs\":{\"textAlign\":null},\"content\":[{\"type\":\"text\",\"text\":\"tem exatamente 2 pontos, ambos no primeiro quadrante.\"}]}]},{\"type\":\"option\",\"attrs\":{\"letter\":\"D\"},\"content\":[{\"type\":\"paragraph\",\"attrs\":{\"textAlign\":null},\"content\":[{\"type\":\"text\",\"text\":\"tem exatamente 3 pontos, sendo dois no primeiro quadrante e outro no segundo quadrante.\"}]}]},{\"type\":\"option\",\"attrs\":{\"letter\":\"E\"},\"content\":[{\"type\":\"paragraph\",\"attrs\":{\"textAlign\":null},\"content\":[{\"type\":\"text\",\"text\":\"tem exatamente 4 pontos, sendo dois no primeiro quadrante e dois no segundo quadrante.\"}]}]}]}]}]}', 'question'),
('1685bc22-548e-4590-94d8-f711a338f913', '2026-02-22 15:46:12', '2026-02-22 15:46:12', 'Matemática', 'Geometria espacial e volume', 'Múltipla Escolha', 'Difícil', 'C', NULL, NULL, 'concurso', 'FUVEST', 'FUVEST', 2017, NULL, NULL, '88', '{\"id\":\"100387007767191405258\",\"name\":\"Marcos Paulo\"}', '100387007767191405258', '[\"cone\",\"semelhança\",\"volume\"]', '{\"schemaVersion\":1,\"id\":\"1685bc22-548e-4590-94d8-f711a338f913\",\"createdAt\":\"2026-02-22T15:45:02.888Z\",\"updatedAt\":\"2026-02-22T15:45:28.069Z\",\"tipo\":\"Múltipla Escolha\",\"dificuldade\":\"Difícil\",\"tags\":[\"cone\",\"semelhança\",\"volume\"],\"gabarito\":{\"kind\":\"mcq\",\"correct\":\"C\"},\"source\":{\"kind\":\"concurso\",\"concurso\":\"FUVEST\",\"banca\":\"FUVEST\",\"ano\":2017,\"numero\":\"88\"},\"author\":{\"id\":\"100387007767191405258\",\"name\":\"Marcos Paulo\"},\"disciplina\":\"Matemática\",\"assunto\":\"Geometria espacial e volume\"}', '{\"type\":\"doc\",\"content\":[{\"type\":\"question\",\"attrs\":{\"tipo\":null},\"content\":[{\"type\":\"statement\",\"content\":[{\"type\":\"paragraph\",\"attrs\":{\"textAlign\":null},\"content\":[{\"type\":\"text\",\"text\":\"Um reservatório de água tem o formato de um cone circular reto. O diâmetro de sua base (que está apoiada sobre o chão horizontal) é igual a \"},{\"type\":\"math_inline\",\"attrs\":{\"latex\":\"8\"}},{\"type\":\"text\",\"text\":\" m. Sua altura é igual a \"},{\"type\":\"math_inline\",\"attrs\":{\"latex\":\"12\"}},{\"type\":\"text\",\"text\":\" m. A partir de um instante em que o reservatório está completamente vazio, inicia-se seu enchimento com água a uma vazão constante de \"},{\"type\":\"math_inline\",\"attrs\":{\"latex\":\"500\"}},{\"type\":\"text\",\"text\":\" litros por minuto.\"}]},{\"type\":\"paragraph\",\"attrs\":{\"textAlign\":null},\"content\":[{\"type\":\"text\",\"text\":\"O tempo gasto para que o nível de água atinja metade da altura do reservatório é de, aproximadamente,\"}]}]},{\"type\":\"options\",\"content\":[{\"type\":\"option\",\"attrs\":{\"letter\":\"A\"},\"content\":[{\"type\":\"paragraph\",\"attrs\":{\"textAlign\":null},\"content\":[{\"type\":\"text\",\"text\":\"4 horas e 50 minutos.\"}]}]},{\"type\":\"option\",\"attrs\":{\"letter\":\"B\"},\"content\":[{\"type\":\"paragraph\",\"attrs\":{\"textAlign\":null},\"content\":[{\"type\":\"text\",\"text\":\"5 horas e 20 minutos.\"}]}]},{\"type\":\"option\",\"attrs\":{\"letter\":\"C\"},\"content\":[{\"type\":\"paragraph\",\"attrs\":{\"textAlign\":null},\"content\":[{\"type\":\"text\",\"text\":\"5 horas e 50 minutos.\"}]}]},{\"type\":\"option\",\"attrs\":{\"letter\":\"D\"},\"content\":[{\"type\":\"paragraph\",\"attrs\":{\"textAlign\":null},\"content\":[{\"type\":\"text\",\"text\":\"6 horas e 20 minutos.\"}]}]},{\"type\":\"option\",\"attrs\":{\"letter\":\"E\"},\"content\":[{\"type\":\"paragraph\",\"attrs\":{\"textAlign\":null},\"content\":[{\"type\":\"text\",\"text\":\"6 horas e 50 minutos.\"}]}]}]}]}]}', 'question'),
