xt\",\"text\":\"25\"}]}]}]}]}]}', 'question'),
('16cb83c6-f327-4ef5-b0fb-0d1bdc74fc74', '2026-02-22 23:00:04', '2026-02-23 14:06:59', 'Matemática', 'Medidas de Tendência Central', 'Múltipla Escolha', 'Fácil', 'D', NULL, NULL, 'concurso', 'FUVEST', 'FUVEST', 2014, NULL, NULL, '42', '{\"id\":\"100387007767191405258\",\"name\":\"Marcos Paulo\"}', '100387007767191405258', '[\"notas\",\"média\",\"mediana\",\"estatística\"]', '{\"schemaVersion\":1,\"id\":\"16cb83c6-f327-4ef5-b0fb-0d1bdc74fc74\",\"createdAt\":\"2026-02-22T22:58:59.897Z\",\"updatedAt\":\"2026-02-23T14:06:13.255Z\",\"tipo\":\"Múltipla Escolha\",\"dificuldade\":\"Fácil\",\"tags\":[\"notas\",\"média\",\"mediana\",\"estatística\"],\"gabarito\":{\"kind\":\"mcq\",\"correct\":\"D\"},\"source\":{\"kind\":\"concurso\",\"banca\":\"FUVEST\",\"ano\":2014,\"numero\":\"42\",\"concurso\":\"FUVEST\"},\"author\":{\"id\":\"100387007767191405258\",\"name\":\"Marcos Paulo\"},\"disciplina\":\"Matemática\",\"assunto\":\"Medidas de Tendência Central\"}', '{\"type\":\"doc\",\"content\":[{\"type\":\"question\",\"attrs\":{\"tipo\":null},\"content\":[{\"type\":\"statement\",\"content\":[{\"type\":\"paragraph\",\"attrs\":{\"textAlign\":null},\"content\":[{\"type\":\"text\",\"text\":\"Cada uma das cinco listas dadas é a relação de notas obtidas por seis alunos de uma turma em uma certa prova.\"}]},{\"type\":\"paragraph\",\"attrs\":{\"textAlign\":null},\"content\":[{\"type\":\"text\",\"text\":\"Assinale a única lista na qual a média das notas é maior do que a mediana.\"}]}]},{\"type\":\"options\",\"content\":[{\"type\":\"option\",\"attrs\":{\"letter\":\"A\"},\"content\":[{\"type\":\"paragraph\",\"attrs\":{\"textAlign\":null},\"content\":[{\"type\":\"math_inline\",\"attrs\":{\"latex\":\"5,5; 5,5; 7; 8; 9; 10\"}}]}]},{\"type\":\"option\",\"attrs\":{\"letter\":\"B\"},\"content\":[{\"type\":\"paragraph\",\"attrs\":{\"textAlign\":null},\"content\":[{\"type\":\"math_inline\",\"attrs\":{\"latex\":\"4; 5; 6; 7; 8; 8\"}}]}]},{\"type\":\"option\",\"attrs\":{\"letter\":\"C\"},\"content\":[{\"t