('19a7b284-6ab2-4779-80b2-3f1638b3c578', '2026-02-16 23:43:01', '2026-02-16 23:43:01', 'Matemática', 'Geometria Analítica', 'Múltipla Escolha', 'media', 'A', NULL, NULL, 'concurso', 'Escola Naval', 'Marinha do Brasil', 2023, NULL, NULL, '8', '{\"id\":\"100387007767191405258\",\"name\":\"Marcos Paulo\"}', '100387007767191405258', '[\"Escola Naval\",\"2023\",\"Anulada\"]', '{\"schemaVersion\":1,\"id\":\"19a7b284-6ab2-4779-80b2-3f1638b3c578\",\"createdAt\":\"2026-02-16T23:42:04.547Z\",\"updatedAt\":\"2026-02-16T23:42:37.777Z\",\"tipo\":\"Múltipla Escolha\",\"dificuldade\":\"Média\",\"tags\":[\"Escola Naval\",\"2023\",\"Anulada\"],\"gabarito\":{\"kind\":\"mcq\",\"correct\":\"A\"},\"source\":{\"kind\":\"concurso\",\"concurso\":\"Escola Naval\",\"banca\":\"Marinha do Brasil\",\"ano\":2023,\"numero\":\"8\"},\"author\":{\"id\":\"100387007767191405258\",\"name\":\"Marcos Paulo\"},\"disciplina\":\"Matemática\",\"assunto\":\"Geometria Analítica\"}', '{\"type\":\"doc\",\"content\":[{\"type\":\"question\",\"attrs\":{\"tipo\":null},\"content\":[{\"type\":\"statement\",\"content\":[{\"type\":\"paragraph\",\"attrs\":{\"textAlign\":null},\"content\":[{\"type\":\"text\",\"text\":\"Uma hipérbole tem os eixos transverso e conjugado contidos nos eixos coordenados e contém os pontos médios dos lados do quadrilátero, cujos vértices são as intersecções da elipse, de equação \"},{\"type\":\"math_inline\",\"attrs\":{\"latex\":\"9x^{2}+y^{2}=36\"}},{\"type\":\"text\",\"text\":\", com os eixos coordenados. Sabendo que as coordenadas de um dos focos da hipérbole é \"},{\"type\":\"math_inline\",\"attrs\":{\"latex\":\"(1,0)\"}},{\"type\":\"text\",\"text\":\", assinale a opção que apresenta uma das equações das assíntotas dessa hipérbole.\"}]}]},{\"type\":\"options\",\"content\":[{\"type\":\"option\",\"attrs\":{\"letter\":\"A\"},\"content\":[{\"type\":\"paragraph\",\"attrs\":{\"textAlign\":null},\"content\":[{\"type\":\"math_inline\",\"attrs\":{\"latex\":\"y=\\\\sqrt{3}\\\\,x\"}},{\"type\":\"text\",\"text\":\"  \"}]}]},{\"type\":\"option\",\"attrs\":{\"letter\":\"B\"},\"content\":[{\"type\":\"paragraph\",\"attrs\":{\"textAlign\":null},\"content\":[{\"type\":\"math_inline\",\"attrs\":{\"latex\":\"y=-\\\\sqrt{13}\\\\,x\"}},{\"type\":\"text\",\"text\":\"  \"}]}]},{\"type\":\"option\",\"attrs\":{\"letter\":\"C\"},\"content\":[{\"type\":\"paragraph\",\"attrs\":{\"textAlign\":null},\"content\":[{\"type\":\"math_inline\",\"attrs\":{\"latex\":\"y=-2\\\\sqrt{3}\\\\,x\"}},{\"type\":\"text\",\"text\":\"  \"}]}]},{\"type\":\"option\",\"attrs\":{\"letter\":\"D\"},\"content\":[{\"type\":\"paragraph\",\"attrs\":{\"textAlign\":null},\"content\":[{\"type\":\"math_inline\",\"attrs\":{\"latex\":\"y=13x\"}},{\"type\":\"text\",\"text\":\"  \"}]}]},{\"type\":\"option\",\"attrs\":{\"letter\":\"E\"},\"content\":[{\"type\":\"paragraph\",\"attrs\":{\"textAlign\":null},\"content\":[{\"type\":\"math_inline\",\"attrs\":{\"latex\":\"y=3x\"}},{\"type\":\"text\",\"text\":\"  \"}]}]}]}]}]}', 'question'),
('1a03d2ef-a6d8-4829-af68-2401b0fedbf1', '2026-02-09 14:52:04', '2026-02-09 14:52:04', 'Matemática', 'Função Quadrática', 'Múltipla Escolha', 'media', 'B', NULL, NULL, 'original', NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, '[]', '{\"schemaVersion\":1,\"id\":\"1a03d2ef-a6d8-4829-af68-2401b0fedbf1\",\"createdAt\":\"2026-02-09T14:47:11.159Z\",\"updatedAt\":\"2026-02-09T14:52:00.562Z\",\"tipo\":\"Múltipla Escolha\",\"dificuldade\":\"Média\",\"tags\":[],\"gabarito\":{\"kind\":\"mcq\",\"correct\":\"B\"},\"source\":{\"kind\":\"original\"},\"disciplina\":\"Matemática\",\"assunto\":\"Função Quadrática\"}', '{\"type\":\"doc\",\"content\":[{\"type\":\"question\",\"attrs\":{\"tipo\":null},\"content\":[{\"type\":\"statement\",\"content\":[{\"type\":\"paragraph\",\"attrs\":{\"textAlign\":null},\"content\":[{\"type\":\"text\",\"text\":\"Um curral retangular será construído aproveitando-se um muro pré-existente no terreno, por medida de economia. Para cercar os outros três lados, serão utilizados 600 metros de tela de arame. Para que a área do curral seja a maior possível, a razão entre as suas menor e maior dimensões será:\"}]}]},{\"type\":\"options\",\"content\":[{\"type\":\"option\",\"attrs\":{\"letter\":\"A\"},\"content\":[{\"type\":\"paragraph\",\"attrs\":{\"textAlign\":null},\"content\":[{\"type\":\"text\",\"text\":\"0,25\"}]}]},{\"type\":\"option\",\"attrs\":{\"letter\":\"B\"},\"content\":[{\"type\":\"paragraph\",\"attrs\":{\"textAlign\":null},\"content\":[{\"type\":\"text\",\"text\":\"0,50\"}]}]},{\"type\":\"option\",\"attrs\":{\"letter\":\"C\"},\"content\":[{\"type\":\"paragraph\",\"attrs\":{\"textAlign\":null},\"content\":[{\"type\":\"text\",\"text\":\"0,75\"}]}]},{\"type\":\"option\",\"attrs\":{\"letter\":\"D\"},\"content\":[{\"type\":\"paragraph\",\"attrs\":{\"textAlign\":null},\"content\":[{\"type\":\"text\",\"text\":\"1,00\"}]}]},{\"type\":\"option\",\"attrs\":{\"letter\":\"E\"},\"content\":[{\"type\":\"paragraph\",\"attrs\":{\"textAlign\":null},\"content\":[{\"type\":\"text\",\"text\":\"1,25\"}]}]}]}]}]}', 'question'),
('1a1a5648-e195-4afe-aaf7-bb512de22266', '2026-02-19 12:05:03', '2026-02-21 16:31:40', 'Matemática', 'Geometria Espacial', 'Múltipla Escolha', 'Média', 'D', NULL, NULL, 'concurso', 'FUVEST', 'FUVEST', 2019, NULL, NULL, '52', '{\"id\":\"100387007767191405258\",\"name\":\"Marcos Paulo\"}', '100387007767191405258', '[\"área\",\"geometria espacial\",\"quadrilátero\"]', '{\"schemaVersion\":1,\"id\":\"1a1a5648-e195-4afe-aaf7-bb512de22266\",\"createdAt\":\"2026-02-19T12:03:46.400Z\",\"updatedAt\":\"2026-02-21T16:30:25.150Z\",\"tipo\":\"Múltipla Escolha\",\"dificuldade\":\"Média\",\"tags\":[\"área\",\"geometria espacial\",\"quadrilátero\"],\"gabarito\":{\"kind\":\"mcq\",\"correct\":\"D\",\"rubric\":null},\"source\":{\"kind\":\"concurso\",\"concurso\":\"FUVEST\",\"banca\":\"FUVEST\",\"ano\":2019,\"numero\":\"52\"},\"author\":{\"id\":\"100387007767191405258\",\"name\":\"Marcos Paulo\"},\"disciplina\":\"Matemática\",\"assunto\":\"Geometria Espacial\"}', '{\"type\":\"doc\",\"content\":[{\"type\":\"question\",\"attrs\":{\"tipo\":null},\"content\":[{\"type\":\"statement\",\"content\":[{\"type\":\"paragraph\",\"attrs\":{\"textAlign\":null},\"content\":[{\"type\":\"text\",\"text\":\"Uma empresa estuda cobrir um vão entre dois prédios (com formato de paralelepípedos reto-retângulos) que têm paredes laterais paralelas, instalando uma lona na forma de um quadrilátero, com pontas presas nos pontos \"},{\"type\":\"math_inline\",\"attrs\":{\"latex\":\"A\"}},{\"type\":\"text\",\"text\":\", \"},{\"type\":\"math_inline\",\"attrs\":{\"latex\":\"B\"}},{\"type\":\"text\",\"text\":\", \"},{\"type\":\"math_inline\",\"attrs\":{\"latex\":\"C\"}},{\"type\":\"text\",\"text\":\" e \"},{\"type\":\"math_inline\",\"attrs\":{\"latex\":\"D\"}},{\"type\":\"text\",\"text\":\", conforme indicação da figura.\"}]},{\"type\":\"paragraph\",\"attrs\":{\"textAlign\":null},\"content\":[{\"type\":\"image\",\"attrs\":{\"id\":\"629971c9-9f15-4637-ab59-28f051e08c38\",\"src\":\"https://mpfaraujo.com.br/guardafiguras/upl