\",\"attrs\":{\"textAlign\":null},\"content\":[{\"type\":\"math_inline\",\"attrs\":{\"latex\":\"1.200\\\\ \\\\text{m}^2\"}},{\"type\":\"text\",\"text\":\"  \"}]}]}]}]}]}', 'question'),
