('238cec1e-80cb-48c7-83e1-0c8ed9d42ca1', '2026-01-30 02:06:36', '2026-01-30 02:06:36', 'Matemática', 'Função Quadrática', 'Múltipla Escolha', 'media', NULL, NULL, NULL, 'concurso', 'ENEM', 'INEP', 2016, 'cinza', NULL, '167', NULL, NULL, '[]', '{\"schemaVersion\":1,\"id\":\"238cec1e-80cb-48c7-83e1-0c8ed9d42ca1\",\"createdAt\":\"2026-01-30T01:47:32.672Z\",\"updatedAt\":\"2026-01-30T02:05:40.125Z\",\"tipo\":\"Múltipla Escolha\",\"dificuldade\":\"Média\",\"tags\":[],\"gabarito\":{\"kind\":\"mcq\",\"correct\":\"C\"},\"source\":{\"kind\":\"concurso\",\"banca\":\"INEP\",\"ano\":2016,\"cargo\":\"cinza\",\"numero\":\"167\",\"concurso\":\"ENEM\"},\"disciplina\":\"Matemática\",\"assunto\":\"Função Quadrática\"}', '{\"type\":\"doc\",\"content\":[{\"type\":\"question\",\"content\":[{\"type\":\"base_text\",\"content\":[{\"type\":\"paragraph\",\"content\":[{\"type\":\"text\",\"text\":\"Um túnel deve ser lacrado com uma tampa de concreto. A seção transversal do túnel e a tampa de concreto têm contornos de um arco de parábola e mesmas dimensões. Para determinar o custo da obra, um engenheiro deve calcular a área sob o arco parabólico em questão. Usando o eixo horizontal no nível do chão e o eixo de simetria da parábola como eixo vertical, obteve a seguinte equação para a parábola \"},{\"type\":\"math_inline\",\"attrs\":{\"latex\":\"y = 9 – x^2\"}},{\"type\":\"text\",\"text\":\", sendo x e y medidos em metros.\"}]},{\"type\":\"paragraph\",\"content\":[{\"type\":\"text\",\"text\":\"Sabe-se que a área sob uma parábola como esta é igual a 2/3 da área do retângulo cujas dimensões são, respectivamente, iguais à base e à altura da entrada do túnel.\"}]}]},{\"type\":\"statement\",\"content\":[{\"type\":\"paragraph\",\"content\":[{\"type\":\"text\",\"text\":\"Qual é a área da parte frontal da tampa de concreto, em metro quadrado? \"}]}]},{\"type\":\"options\",\"content\":[{\"type\":\"option\",\"attrs\":{\"letter\":\"A\"},\"content\":[{\"type\":\"paragraph\",\"content\":[{\"type\":\"text\",\"text\":\"18\"},{\"type\":\"text\",\"marks\":[{\"type\":\"strong\"}],\"text\":\" \"}]}]},{\"type\":\"option\",\"attrs\":{\"letter\":\"B\"},\"content\":[{\"type\":\"paragraph\",\"content\":[{\"type\":\"text\",\"text\":\"20\"}]}]},{\"type\":\"option\",\"attrs\":{\"letter\":\"C\"},\"content\":[{\"type\":\"paragraph\",\"content\":[{\"type\":\"text\",\"text\":\"36\"}]}]},{\"type\":\"option\",\"attrs\":{\"letter\":\"D\"},\"content\":[{\"type\":\"paragraph\",\"content\":[{\"type\":\"text\",\"text\":\"45\"}]}]},{\"type\":\"option\",\"attrs\":{\"letter\":\"E\"},\"content\":[{\"type\":\"paragraph\",\"content\":[{\"type\":\"text\",\"text\":\"54\"}]}]}]}]}]}', 'question'),
