e\":\"text\",\"text\":\"1,5\"}]}]},{\"type\":\"option\",\"attrs\":{\"letter\":\"B\"},\"content\":[{\"type\":\"paragraph\",\"attrs\":{\"textAlign\":null},\"content\":[{\"type\":\"text\",\"text\":\"2,0\"}]}]},{\"type\":\"option\",\"attrs\":{\"letter\":\"C\"},\"content\":[{\"type\":\"paragraph\",\"attrs\":{\"textAlign\":null},\"content\":[{\"type\":\"text\",\"text\":\"3,0\"}]}]},{\"type\":\"option\",\"attrs\":{\"letter\":\"D\"},\"content\":[{\"type\":\"paragraph\",\"attrs\":{\"textAlign\":null},\"content\":[{\"type\":\"text\",\"text\":\"4,0\"}]}]},{\"type\":\"option\",\"attrs\":{\"letter\":\"E\"},\"content\":[{\"type\":\"paragraph\",\"attrs\":{\"textAlign\":null},\"content\":[{\"type\":\"text\",\"text\":\"6,0\"}]}]}]}]}]}', 'question'),
('2a4b445a-0679-48a3-9c94-587473dc6421', '2026-02-16 18:27:05', '2026-02-16 18:27:05', 'Matemática', 'Geometria Analítica', 'Múltipla Escolha', 'media', 'E', NULL, NULL, 'concurso', 'ENEM', 'INEP', 2025, 'Amarela', NULL, '144', '{\"id\":\"100387007767191405258\",\"name\":\"Marcos Paulo\"}', '100387007767191405258', '[]', '{\"schemaVersion\":1,\"id\":\"2a4b445a-0679-48a3-9c94-587473dc6421\",\"createdAt\":\"2026-02-16T18:21:44.279Z\",\"updatedAt\":\"2026-02-16T18:26:42.380Z\",\"tipo\":\"Múltipla Escolha\",\"dificuldade\":\"Média\",\"tags\":[],\"gabarito\":{\"kind\":\"mcq\",\"correct\":\"E\"},\"source\":{\"kind\":\"concurso\",\"concurso\":\"ENEM\",\"banca\":\"INEP\",\"ano\":2025,\"cargo\":\"Amarela\",\"numero\":\"144\"},\"author\":{\"id\":\"100387007767191405258\",\"name\":\"Marcos Paulo\"},\"disciplina\":\"Matemática\",\"assunto\":\"Geometria Analítica\"}', '{\"type\":\"doc\",\"content\":[{\"type\":\"question\",\"attrs\":{\"tipo\":null},\"content\":[{\"type\":\"statement\",\"content\":[{\"type\":\"paragraph\",\"attrs\":{\"textAlign\":null},\"content\":[{\"type\":\"text\",\"text\":\"Em um jogo de computador, um cubo se encontra inicialmente posicionado conforme indicado na figura.\"}]},{\"type\":\"paragraph\",\"attrs\":{\"textAlign\":null},\"content\":[{\"type\":\"image\",\"attrs\":{\"id\":\"09e2ac5f-94c5-4689-b14c-95408fe6271b\",\"src\":\"https://mpfaraujo.com.br/guardafiguras/uploads/fc7f63bbd6287ef807c1998e55c4d6bdc00f7d61008ff8e05e88d7c18062cdba.png\",\"width\":302,\"align\":\"center\"}}]},{\"type\":\"paragraph\",\"attrs\":{\"textAlign\":null},\"content\":[{\"type\":\"text\",\"text\":\"Cada deslocamento efetuado por esse cubo se dá sempre em uma das direções definidas pelos três eixos coordenados.\"}]},{\"type\":\"paragraph\",\"attrs\":{\"textAlign\":null},\"content\":[{\"type\":\"text\",\"text\":\"Ao se movimentar a partir da posição inicial, esse cubo se aproximou 3 unidades do plano yz, se afastou 5 unidades do plano xz e se aproximou 4 unidades do plano xy.\"}]},{\"type\":\"paragraph\",\"attrs\":{\"textAlign\":null},\"content\":[{\"type\":\"text\",\"text\":\"A figura que apresenta as projeções ortogonais desse cubo sobre os três planos coordenados, após efetuar as movimentações descritas, é\"}]}]},{\"type\":\"options\",\"content\":[{\"type\":\"option\",\"attrs\":{\"letter\":\"A\"},\"content\":[{\"type\":\"paragraph\",\"attrs\":{\"textAlign\":null},\"content\":[{\"type\":\"image\",\"attrs\":{\"id\":\"eac6639d-7843-4d12-b6c3-092d094fda47\",\"src\":\"https://mpfaraujo.com.br/guardafiguras/uploads/d4f895c064be81d0008a06786c104b4c65993d7faad216b79d80b3302e918046.png\",\"width\":302,\"align\":null}}]}]},{\"type\":\"option\",\"attrs\":{\"letter\":\"B\"},\"content\":[{\"type\":\"paragraph\",\"attrs\":{\"textAlign\":null},\"content\":[{\"type\":\"image\",\"attrs\":{\"id\":\"9597a0b0-5e9e-4d9d-aba7-3f34f1fd7ae6\",\"src\":\"https://mpfaraujo.com.br/guardafiguras/uploads/571bf952ba7a4eb588fcbfb750952e004a495c5050e1cfd13d72bdb194f78631.png\",\"width\":302,\"align\":null}}]}]},{\"type\":\"option\",\"attrs\":{\"letter\":\"C\"},\"content\":[{\"type\":\"paragraph\",\"attrs\":{\"textAlign\":null},\"content\":[{\"type\":\"image\",\"attrs\":{\"id\":\"1da83b96-8b4d-4e9a-99d7-c632ec18069c\",\"src\":\"https://mpfaraujo.com.br/guardafiguras/uploads/ed9fb211d2d11d267f71d74c2434ff4b32af103e74eadf2d7950fa2fe7293333.png\",\"width\":302,\"align\":null}}]}]},{\"type\":\"option\",\"attrs\":{\"letter\":\"D\"},\"content\":[{\"type\":\"paragraph\",\"attrs\":{\"textAlign\":null},\"content\":[{\"type\":\"image\",\"attrs\":{\"id\":\"e27ac6a1-c780-46e0-935f-ebe92922fe05\",\"src\":\"https://mpfaraujo.com.br/guardafiguras/uploads/cc81a68d27c0a0eeed67167af8ef8432c2abad5f6e73ad149766fb72840d6533.png\",\"width\":302,\"align\":null}}]}]},{\"type\":\"option\",\"attrs\":{\"letter\":\"E\"},\"content\":[{\"type\":\"paragraph\",\"attrs\":{\"textAlign\":null},\"content\":[{\"type\":\"image\",\"attrs\":{\"id\":\"80b4126d-e500-42c4-a58a-e55eb8ae8663\",\"src\":\"https://mpf