('3c40ce59-01ce-47e4-a07f-647244e34420', '2026-01-30 10:57:20', '2026-01-30 10:57:20', 'Matemática', 'Números', 'Múltipla Escolha', 'facil', NULL, NULL, NULL, 'original', NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, '[]', '{\"schemaVersion\":1,\"id\":\"3c40ce59-01ce-47e4-a07f-647244e34420\",\"createdAt\":\"2026-01-30T10:34:01.974Z\",\"updatedAt\":\"2026-01-30T10:57:09.848Z\",\"tipo\":\"Múltipla Escolha\",\"dificuldade\":\"Fácil\",\"tags\":[],\"gabarito\":{\"kind\":\"mcq\",\"correct\":\"A\"},\"source\":{\"kind\":\"original\"},\"disciplina\":\"Matemática\",\"assunto\":\"Números\"}', '{\"type\":\"doc\",\"content\":[{\"type\":\"question\",\"content\":[{\"type\":\"base_text\",\"content\":[{\"type\":\"paragraph\",\"content\":[{\"type\":\"text\",\"text\":\"Um edifício tem a numeração dos andares iniciando no térreo (T), e continuando com primeiro, segundo, terceiro, ..., até o último andar. Uma criança entrou no elevador e, tocando no painel, seguiu uma sequência de andares, parando, abrindo e fechando a porta em diversos andares. A partir de onde entrou a criança, o elevador subiu sete andares, em seguida desceu dez, desceu mais treze, subiu nove, desceu quatro e parou no quinto andar, finalizando a sequência. Considere que, no trajeto seguido pela criança, o elevador parou uma vez no último andar do edifício\"}]}]},{\"type\":\"statement\",\"content\":[{\"type\":\"paragraph\",\"content\":[{\"type\":\"text\",\"text\":\"De acordo com as informações dadas, o último andar do edifício é o\"}]}]},{\"type\":\"options\",\"content\":[{\"type\":\"option\",\"attrs\":{\"letter\":\"A\"},\"content\":[{\"type\":\"paragraph\",\"content\":[{\"type\":\"text\",\"text\":\"16º\"}]}]},{\"type\":\"option\",\"attrs\":{\"letter\":\"B\"},\"content\":[{\"type\":\"paragraph\",\"content\":[{\"type\":\"text\",\"text\":\"22º\"}]}]},{\"type\":\"option\",\"attrs\":{\"letter\":\"C\"},\"content\":[{\"type\":\"paragraph\",\"content\":[{\"type\":\"text\",\"text\":\"23º\"}]}]},{\"type\":\"option\",\"attrs\":{\"letter\":\"D\"},\"content\":[{\"type\":\"paragraph\",\"content\":[{\"type\":\"text\",\"text\":\"25º\"}]}]},{\"type\":\"option\",\"attrs\":{\"letter\":\"E\"},\"content\":[{\"type\":\"paragraph\",\"content\":[{\"type\":\"text\",\"text\":\"32º\"}]}]}]}]}]}', 'question'),
