",\"content\":[{\"type\":\"text\",\"text\":\" If comfort is a construct, I don\'t believe in good luck\"}]},{\"type\":\"verse\",\"content\":[{\"type\":\"text\",\"text\":\" Now that I know what\'s what\"}]},{\"type\":\"verse\",\"content\":[{\"type\":\"text\",\"text\":\" I hate it here so I will go to secret gardens in my mind \"}]},{\"type\":\"verse\",\"content\":[{\"type\":\"text\",\"text\":\"People need a key to get to, the only one is mine\"}]},{\"type\":\"verse\",\"content\":[{\"type\":\"text\",\"text\":\" I read about it in a book when I was a precocious child \"}]},{\"type\":\"verse\",\"content\":[{\"type\":\"text\",\"text\":\"No mid-sized city hopes and small-town fears\"}]},{\"type\":\"verse\",\"content\":[{\"type\":\"text\",\"text\":\" I\'m there most of the year \'cause I hate it here\"}]},{\"type\":\"verse\",\"content\":[{\"type\":\"text\",\"text\":\" I hate it here\"}]},{\"type\":\"verse\",\"content\":[{\"type\":\"text\",\"text\":\" My friends used to play a game where\"}]},{\"type\":\"verse\",\"content\":[{\"type\":\"text\",\"text\":\" We would pick a decade\"}]},{\"type\":\"verse\",\"content\":[{\"type\":\"text\",\"text\":\" We wished we could live in instead of this\"}]},{\"type\":\"verse\",\"content\":[{\"type\":\"text\",\"text\":\" I\'d say the 1830s but without all the racists\"}]},{\"type\":\"verse\",\"content\":[{\"type\":\"text\",\"text\":\" And getting married off for the highest bid\"}]},{\"type\":\"verse\",\"content\":[{\"type\":\"text\",\"text\":\" Everyone would look down \'cause it wasn\'t fun now\"}]},{\"type\":\"verse\",\"content\":[{\"type\":\"text\",\"text\":\" Seems like it was never even fun back then \"}]},{\"type\":\"verse\",\"content\":[{\"type\":\"text\",\"text\":\"Nostalgia is a mind\'s trick\"}]},{\"type\":\"verse\",\"content\":[{\"type\":\"text\",\"text\":\" If I\'d been there, I\'d hate it \"}]},{\"type\":\"verse\",\"content\":[{\"type\":\"text\",\"text\":\"It was freezing in the palace”\"}]}]},{\"type\":\"credits\",\"content\