('4b4eb34f-b402-4da0-9314-2cb94536c0d0', '2026-02-16 12:36:10', '2026-02-16 12:36:10', 'Matemática', 'Função Exponencial', 'Múltipla Escolha', 'facil', 'A', NULL, NULL, 'original', NULL, NULL, NULL, NULL, NULL, NULL, '{\"id\":\"100387007767191405258\",\"name\":\"Marcos Paulo\"}', '100387007767191405258', '[]', '{\"schemaVersion\":1,\"id\":\"4b4eb34f-b402-4da0-9314-2cb94536c0d0\",\"createdAt\":\"2026-02-16T12:35:12.779Z\",\"updatedAt\":\"2026-02-16T12:35:47.953Z\",\"tipo\":\"Múltipla Escolha\",\"dificuldade\":\"Fácil\",\"tags\":[],\"gabarito\":{\"kind\":\"mcq\",\"correct\":\"A\"},\"source\":{\"kind\":\"original\"},\"author\":{\"id\":\"100387007767191405258\",\"name\":\"Marcos Paulo\"},\"disciplina\":\"Matemática\",\"assunto\":\"Função Exponencial\"}', '{\"type\":\"doc\",\"content\":[{\"type\":\"question\",\"attrs\":{\"tipo\":null},\"content\":[{\"type\":\"statement\",\"content\":[{\"type\":\"paragraph\",\"attrs\":{\"textAlign\":null},\"content\":[{\"type\":\"text\",\"text\":\"A função \"},{\"type\":\"math_inline\",\"attrs\":{\"latex\":\"f(x)=7\\\\cdot3^x\"}},{\"type\":\"text\",\"text\":\" corta o eixo \"},{\"type\":\"math_inline\",\"attrs\":{\"latex\":\"y\"}},{\"type\":\"text\",\"text\":\" em\"}]}]},{\"type\":\"options\",\"content\":[{\"type\":\"option\",\"attrs\":{\"letter\":\"A\"},\"content\":[{\"type\":\"paragraph\",\"attrs\":{\"textAlign\":null},\"content\":[{\"type\":\"text\",\"text\":\"7\"}]}]},{\"type\":\"option\",\"attrs\":{\"letter\":\"B\"},\"content\":[{\"type\":\"paragraph\",\"attrs\":{\"textAlign\":null},\"content\":[{\"type\":\"text\",\"text\":\"3\"}]}]},{\"type\":\"option\",\"attrs\":{\"letter\":\"C\"},\"content\":[{\"type\":\"paragraph\",\"attrs\":{\"textAlign\":null},\"content\":[{\"type\":\"text\",\"text\":\"21\"}]}]},{\"type\":\"option\",\"attrs\":{\"letter\":\"D\"},\"content\":[{\"type\":\"paragraph\",\"attrs\":{\"textAlign\":null},\"content\":[{\"type\":\"text\",\"text\":\"0\"}]}]},{\"type\":\"option\",\"attrs\":{\"letter\":\"E\"},\"content\":[{\"