('4c0f039a-47dd-4716-92cf-3357a7690b2a', '2026-02-25 19:37:25', '2026-02-25 19:37:25', 'Língua Portuguesa', 'Recursos Expressivos e Uso de Aspas', 'Múltipla Escolha', 'Média', 'C', NULL, NULL, 'concurso', 'ENEM', 'INEP', NULL, NULL, NULL, NULL, '{\"id\":\"100387007767191405258\",\"name\":\"Marcos Paulo\"}', '100387007767191405258', '[\"metáfora\",\"interpretação de texto\",\"linguagem jornalística\"]', '{\"schemaVersion\":1,\"id\":\"4c0f039a-47dd-4716-92cf-3357a7690b2a\",\"createdAt\":\"2026-02-25T19:22:00.024Z\",\"updatedAt\":\"2026-02-25T19:36:35.241Z\",\"tipo\":\"Múltipla Escolha\",\"dificuldade\":\"Média\",\"tags\":[\"metáfora\",\"interpretação de texto\",\"linguagem jornalística\"],\"gabarito\":{\"kind\":\"mcq\",\"correct\":\"C\"},\"source\":{\"kind\":\"concurso\",\"concurso\":\"ENEM\",\"banca\":\"INEP\"},\"author\":{\"id\":\"100387007767191405258\",\"name\":\"Marcos Paulo\"},\"disciplina\":\"Língua Portuguesa\",\"assunto\":\"Recursos Expressivos e Uso de Aspas\"}', '{\"type\":\"doc\",\"content\":[{\"type\":\"question\",\"attrs\":{\"tipo\":null},\"content\":[{\"type\":\"statement\",\"content\":[{\"type\":\"paragraph\",\"attrs\":{\"textAlign\":\"center\"},\"content\":[{\"type\":\"text\",\"marks\":[{\"type\":\"strong\"}],\"text\":\"Ouro do século 21\"}]},{\"type\":\"paragraph\",\"attrs\":{\"textAlign\":null},\"content\":[{\"type\":\"text\",\"text\":\"Cério, gadolínio, lutécio, promécio e érbio; samário, térbio e disprósio; hólmio, túlio e itérbio. Essa lista de nomes esquisitos e pouco conhecidos pode parecer a escalação de um time de futebol, que ainda teria no banco de reservas lantânio, neodímio, praseodímio, európio, escândio e ítrio. Mas esses 17 metais, chamados de terras-raras, fazem parte da vida de quase todos os humanos do planeta. Chamados por muitos de \\\"ouro do século 21\\\", \\\"elementos do futuro\\\" ou \\\"vitaminas da indústria\\\", eles estão nos materiais usados na fabricação de lâmpadas, telas de computadores, tablets e celulares, motores de carros elétricos, baterias e até turbinas eólicas. Apesar de tantas aplicações, o Brasil, dono da segunda maior reserva do mundo desses metais, parou de extraí-los e usá-los em 2002. Agora, volta a pensar em retomar sua exploração.\"}]},{\"type\":\"credits\",\"content\":[{\"type\":\"text\",\"text\":\"SILVEIRA, E. Disponível em: www.revistaplaneta.com.br\\n. Acesso em: 6 dez. 2017 (adaptado).\"}]},{\"type\":\"paragraph\",\"attrs\":{\"textAlign\":null},\"content\":[{\"type\":\"text\",\"text\":\"As aspas sinalizam expressões metafóricas empregadas intencionalmente pelo autor do texto para\"}]}]},{\"type\":\"options\",\"content\":[{\"type\":\"option\",\"attrs\":{\"letter\":\"A\"},\"content\":[{\"type\":\"paragraph\",\"attrs\":{\"textAlign\":null},\"content\":[{\"type\":\"text\",\"text\":\"imprimir um tom irônico à reportagem.\"}]}]},{\"type\":\"option\",\"attrs\":{\"letter\":\"B\"},\"content\":[{\"type\":\"paragraph\",\"attrs\":{\"textAlign\":null},\"content\":[{\"type\":\"text\",\"text\":\"incorporar citações de especialistas à reportagem.\"}]}]},{\"type\":\"option\",\"attrs\":{\"letter\":\"C\"},\"content\":[{\"type\":\"paragraph\",\"attrs\":{\"textAlign\":null},\"content\":[{\"type\":\"text\",\"text\":\"atribuir maior valor aos metais, objeto da reportagem.\"}]}]},{\"type\":\"option\",\"attrs\":{\"letter\":\"D\"},\"content\":[{\"type\":\"paragraph\",\"attrs\":{\"textAlign\":null},\"content\":[{\"type\":\"text\",\"text\":\"esclarecer termos científicos empregados na reportagem.\"}]}]},{\"type\":\"option\",\"attrs\":{\"letter\":\"E\"},\"content\":[{\"type\":\"paragraph\",\"attrs\":{\"textAlign\":null},\"content\":[{\"type\":\"text\",\"text\":\"marcar a apropriação de termos de outra ciência pela reportagem.\"}]}]}]}]}]}', 'question'),
('4d190400-4760-4717-a901-a8fc2d8a6520', '2026-02-19 11:52:29', '2026-02-19 11:52:29', 'Matemática', 'Sistemas Lineares', 'Múltipla Escolha', 'Média', 'C', NULL, NULL, 'concurso', 'FUVEST', 'FUVEST', 2019, NULL, NULL, '46', '{\"id\":\"100387007767191405258\",\"name\":\"Marcos Paulo\"}', '100387007767191405258', '[\"equações\",\"sistema\",\"contagem\",\"irmãos\"]', '{\"schemaVersion\":1,\"id\":\"4d190400-4760-4717-a901-a8fc2d8a6520\",\"createdAt\":\"2026-02-19T11:51:16.567Z\",\"updatedAt\":\"2026-02-19T11:51:56.500Z\",\"tipo\":\"Múltipla Escolha\",\"dificuldade\":\"Média\",\"tags\":[\"equações\",\"sistema\",\"contagem\",\"irmãos\"],\"gabarito\":{\"kind\":\"mcq\",\"correct\":\"C\"},\"source\":{\"kind\":\"concurso\",\"concurso\":\"FUVEST\",\"banca\":\"FUVEST\",\"ano\":2019,\"numero\":\"46\"},\"author\":{\"id\":\"100387007767191405258\",\"name\":\"Marcos Paulo\"},\"disciplina\":\"Matemática\",\"assunto\":\"Sistemas Lineares\"}', '{\"type\":\"doc\",\"content\":[{\"type\":\"question\",\"attrs\":{\"tipo\":null},\"content\":[{\"type\":\"statement\",\"content\":[{\"type\":\"paragraph\",\"attrs\":{\"textAlign\":null},\"content\":[{\"type\":\"text\",\"text\":\"Em uma família, o número de irmãs de cada filha é igual à metade do número de irmãos. Cada filho tem o mesmo número de irmãos e irmãs.\"}]},{\"type\":\"paragraph\",\"attrs\":{\"textAlign\":null},\"content\":[{\"type\":\"text\",\"text\":\"O número total de filhos e filhas da família é\"}]}]},{\"type\":\"options\",\"content\":[{\"type\":\"option\",\"attrs\":{\"letter\":\"A\"},\"content\":[{\"type\":\"paragraph\",\"attrs\":{\"textAlign\":null},\"content\":[{\"type\":\"text\",\"text\":\"4\"}]}]},{\"type\":\"option\",\"attrs\":{\"letter\":\"B\"},\"content\":[{\"type\":\"paragraph\",\"attrs\":{\"textAlign\":null},\"content\":[{\"type\":\"text\",\"text\":\"5\"}]}]},{\"type\":\"option\",\"attrs\":{\"letter\":\"C\"},\"content\":[{\"type\":\"paragraph\",\"attrs\":{\"textAlign\":null},\"content\":[{\"type\":\"text\",\"text\":\"7\"}]}]},{\"type\":\"option\",\"attrs\":{\"letter\":\"D\"},\"content\":[{\"type\":\"paragraph\",\"attrs\":{\"textAlign\":null},\"content\":[{\"type\":\"text\",\"text\":\"10\"}]}]},{\"type\":\"option\",\"attrs\":{\"letter\":\"E\"},\"content\":[{\"type\":\"paragraph\",\"attrs\":{\"textAlign\":null},\"content\":[{\"type\":\"text\",\"text\":\"15\"}]}]}]}]}]}', 'question');
