('4f55286c-3dee-4733-83ed-29b260b04b22', '2026-02-23 12:41:23', '2026-02-23 13:38:11', 'Matemática', 'Probabilidade Simples', 'Múltipla Escolha', 'Média', 'A', NULL, NULL, 'concurso', '1o Ex. Qual. UERJ', 'UERJ', 2025, NULL, NULL, '34', '{\"id\":\"100387007767191405258\",\"name\":\"Marcos Paulo\"}', '100387007767191405258', '[\"urna\",\"bolas numeradas\",\"sorteio\",\"picolé\"]', '{\"schemaVersion\":1,\"id\":\"4f55286c-3dee-4733-83ed-29b260b04b22\",\"createdAt\":\"2026-02-23T12:40:04.969Z\",\"updatedAt\":\"2026-02-23T13:32:06.469Z\",\"tipo\":\"Múltipla Escolha\",\"dificuldade\":\"Média\",\"tags\":[\"urna\",\"bolas numeradas\",\"sorteio\",\"picolé\"],\"gabarito\":{\"kind\":\"mcq\",\"correct\":\"A\",\"rubric\":null},\"source\":{\"kind\":\"concurso\",\"banca\":\"UERJ\",\"ano\":2025,\"numero\":\"34\",\"concurso\":\"1o Ex. Qual. UERJ\"},\"author\":{\"id\":\"100387007767191405258\",\"name\":\"Marcos Paulo\"},\"disciplina\":\"Matemática\",\"assunto\":\"Probabilidade Simples\"}', '{\"type\":\"doc\",\"content\":[{\"type\":\"question\",\"attrs\":{\"tipo\":null},\"content\":[{\"type\":\"statement\",\"content\":[{\"type\":\"paragraph\",\"attrs\":{\"textAlign\":null},\"content\":[{\"type\":\"text\",\"text\":\"Uma urna contém cinco bolas numeradas de 1 a 5, que serão sorteadas por duas crianças. Para formar um número de dois algarismos, cada criança retira ao acaso uma bola dessa urna. O algarismo das dezenas será a primeira bola retirada e o algarismo das unidades, a segunda. Se o número formado for par, ganhará um picolé a primeira criança que retirar a bola da urna; se for ímpar, ganhará a segunda criança.\\nA probabilidade de a primeira criança ganhar o picolé é igual a:\"}]}]},{\"type\":\"options\",\"content\":[{\"type\":\"option\",\"attrs\":{\"letter\":\"A\"},\"content\":[{\"type\":\"paragraph\",\"attrs\":{\"textAlign\":null},\"content\":[{\"type\":\"text\",\"text\":\"40%\"}]}]},{\"type\":\"option\",\"attrs\":{\"letter\":\"B\"},\"content\":[{\"type\":\"paragraph\",\"attrs\":{\"textAlign\":null},\"content\":[{\"type\":\"text\",\"text\":\"45%\"}]}]},{\"type\":\"option\",\"attrs\":{\"letter\":\"C\"},\"content\":[{\"type\":\"paragraph\",\"attrs\":{\"textAlign\":null},\"content\":[{\"type\":\"text\",\"text\":\"60%\"}]}]},{\"type\":\"option\",\"attrs\":{\"letter\":\"D\"},\"content\":[{\"type\":\"paragraph\",\"attrs\":{\"textAlign\":null},\"content\":[{\"type\":\"text\",\"text\":\"65%\"}]}]}]}]}]}', 'question'),
('4fbc3fe0-cd00-438e-86cc-4b895259a372', '2026-01-31 20:23:57', '2026-01-31 20:23:57', 'Matemática', 'Porcentagem', 'Múltipla Escolha', 'media', NULL, NULL, NULL, 'original', NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, '[]', '{\"schemaVersion\":1,\"id\":\"4fbc3fe0-cd00-438e-86cc-4b895259a372\",\"createdAt\":\"2026-01-31T20:22:37.096Z\",\"updatedAt\":\"2026-01-31T20:23:52.203Z\",\"tipo\":\"Múltipla Escolha\",\"dificuldade\":\"Média\",\"tags\":[],\"gabarito\":{\"kind\":\"mcq\",\"correct\":\"A\"},\"source\":{\"kind\":\"original\"},\"disciplina\":\"Matemática\",\"assunto\":\"Porcentagem\"}', '{\"type\":\"doc\",\"content\":[{\"type\":\"question\",\"content\":[{\"type\":\"base_text\",\"content\":[{\"type\":\"paragraph\",\"attrs\":{\"textAlign\":null},\"content\":[{\"type\":\"text\",\"text\":\"Antes de iniciar uma campanha publicitaria, um banco fez uma pesquisa entre 800 de seus clientes sobre sua intenção de adesão aos seus dois novos produtos. Dos clientes entrevistados, 240 mostraram-se interessados no primeiro produto, 400 mostraram-se interessados no segundo produto e alguns estavam interessados em ambos os produtos. A campanha publicitária só será iniciada caso pelo menos 70% dos entrevistados mostrarem-se interessados em pelo menos um dos produtos.\"}]}]},{\"type\":\"statement\",\"content\":[{\"type\":\"paragraph\",\"attrs\":{\"textAlign\":null},\"content\":[{\"type\":\"text\",\"text\":\"Qual a porcentagem máxima do total de clientes pode mostrar-se interessados em ambos os produtos para que a campanha publicitária seja iniciada?\"}]}]},{\"type\":\"options\",\"content\":[{\"type\":\"option\",\"attrs\":{\"letter\":\"A\"},\"content\":[{\"type\":\"paragraph\",\"attrs\":{\"textAlign\":null},\"content\":[{\"type\":\"text\",\"text\":\"10%\"}]}]},{\"type\":\"option\",\"attrs\":{\"letter\":\"B\"},\"content\":[{\"type\":\"paragraph\",\"attrs\":{\"textAlign\":null},\"content\":[{\"type\":\"text\",\"text\":\"15%\"}]}]},{\"type\":\"option\",\"attrs\":{\"letter\":\"C\"},\"content\":[{\"type\":\"paragraph\",\"attrs\":{\"textAlign\":null},\"content\":[{\"type\":\"text\",\"text\":\"20%\"}]}]},{\"type\":\"option\",\"attrs\":{\"letter\":\"D\"},\"content\":[{\"type\":\"paragraph\",\"attrs\":{\"textAlign\":null},\"content\":[{\"type\":\"text\",\"text\":\"25%\"}]}]},{\"type\":\"option\",\"attrs\":{\"letter\":\"E\"},\"content\":[{\"type\":\"paragraph\",\"attrs\":{\"textAlign\":null},\"content\":[{\"type\":\"text\",\"text\":\"30%\"}]}]}]}]}]}', 'question'),
