('5b51230c-c6de-4aad-8dbb-a399be097be0', '2026-02-22 19:04:49', '2026-02-22 19:04:49', 'Matemática', 'Problemas sobre as 4 Operações', 'Múltipla Escolha', 'Média', 'C', NULL, NULL, 'concurso', NULL, 'FUVEST', 2016, NULL, NULL, '01', '{\"id\":\"100387007767191405258\",\"name\":\"Marcos Paulo\"}', '100387007767191405258', '[\"moeda\",\"conversão\",\"Brás Cubas\",\"histórico\"]', '{\"schemaVersion\":1,\"id\":\"5b51230c-c6de-4aad-8dbb-a399be097be0\",\"createdAt\":\"2026-02-22T19:03:39.424Z\",\"updatedAt\":\"2026-02-22T19:04:04.421Z\",\"tipo\":\"Múltipla Escolha\",\"dificuldade\":\"Média\",\"tags\":[\"moeda\",\"conversão\",\"Brás Cubas\",\"histórico\"],\"gabarito\":{\"kind\":\"mcq\",\"correct\":\"C\"},\"source\":{\"kind\":\"concurso\",\"banca\":\"FUVEST\",\"ano\":2016,\"numero\":\"01\"},\"author\":{\"id\":\"100387007767191405258\",\"name\":\"Marcos Paulo\"},\"disciplina\":\"Matemática\",\"assunto\":\"Problemas sobre as 4 Operações\"}', '{\"type\":\"doc\",\"content\":[{\"type\":\"question\",\"attrs\":{\"tipo\":null},\"content\":[{\"type\":\"statement\",\"content\":[{\"type\":\"paragraph\",\"attrs\":{\"textAlign\":null},\"content\":[{\"type\":\"text\",\"text\":\"De 1869 até hoje, ocorreram as seguintes mudanças de moeda no Brasil: (1) em 1942, foi criado o cruzeiro, cada cruzeiro valendo mil réis; (2) em 1967, foi criado o cruzeiro novo, cada cruzeiro novo valendo mil cruzeiros; em 1970, o cruzeiro novo voltou a se chamar apenas cruzeiro; (3) em 1986, foi criado o cruzado, cada cruzado valendo mil cruzeiros; (4) em 1989, foi criado o cruzado novo, cada um valendo mil cruzados; em 1990, o cruzado novo passou a se chamar novamente cruzeiro; (5) em 1993, foi criado o cruzeiro real, cada um valendo mil cruzeiros; (6) em 1994, foi criado o real, cada um valendo 2.750 cruzeiros reais.\"}]},{\"type\":\"paragraph\",\"attrs\":{\"textAlign\":null},\"content\":[{\"type\":\"text\",\"text\":\"Quando morreu, em 1869, Brás Cubas possuía 300 contos. Se esse valor tivesse ficado até hoje em uma conta bancária, sem receber juros e sem pagar taxas, e se, a cada mudança de moeda, o depósito tivesse sido normalmente convertido para a nova moeda, o saldo hipotético dessa conta seria, aproximadamente, de um décimo de\"}]}]},{\"type\":\"options\",\"content\":[{\"type\":\"option\",\"attrs\":{\"letter\":\"A\"},\"content\":[{\"type\":\"paragraph\",\"attrs\":{\"textAlign\":null},\"content\":[{\"type\":\"text\",\"text\":\"real.\"}]}]},{\"type\":\"option\",\"attrs\":{\"letter\":\"B\"},\"content\":[{\"type\":\"paragraph\",\"attrs\":{\"textAlign\":null},\"content\":[{\"type\":\"text\",\"text\":\"milésimo de real.\"}]}]},{\"type\":\"option\",\"attrs\":{\"letter\":\"C\"},\"content\":[{\"type\":\"paragraph\",\"attrs\":{\"textAlign\":null},\"content\":[{\"type\":\"text\",\"text\":\"milionésimo de real.\"}]}]},{\"type\":\"option\",\"attrs\":{\"letter\":\"D\"},\"content\":[{\"type\":\"paragraph\",\"attrs\":{\"textAlign\":null},\"content\":[{\"type\":\"text\",\"text\":\"bilionésimo de real.\"}]}]},{\"type\":\"option\",\"attrs\":{\"letter\":\"E\"},\"content\":[{\"type\":\"paragraph\",\"attrs\":{\"textAlign\":null},\"content\":[{\"type\":\"text\",\"text\":\"trilionésimo de real.\"}]}]}]}]}]}', 'question'),
