('623b2982-518b-4cb2-bf96-1800533bad46', '2026-02-06 15:52:18', '2026-02-06 15:52:18', 'Matemática', 'Conjuntos', 'Múltipla Escolha', 'media', 'B', NULL, NULL, 'concurso', 'FUVEST', 'FUVEST', 1997, NULL, NULL, '65', NULL, NULL, '[]', '{\"schemaVersion\":1,\"id\":\"623b2982-518b-4cb2-bf96-1800533bad46\",\"createdAt\":\"2026-02-06T15:51:04.542Z\",\"updatedAt\":\"2026-02-06T15:52:03.314Z\",\"tipo\":\"Múltipla Escolha\",\"dificuldade\":\"Média\",\"tags\":[],\"gabarito\":{\"kind\":\"mcq\",\"correct\":\"B\"},\"source\":{\"kind\":\"concurso\",\"concurso\":\"FUVEST\",\"banca\":\"FUVEST\",\"ano\":1997,\"numero\":\"65\"},\"disciplina\":\"Matemática\",\"assunto\":\"Conjuntos\"}', '{\"type\":\"doc\",\"content\":[{\"type\":\"question\",\"content\":[{\"type\":\"statement\",\"content\":[{\"type\":\"paragraph\",\"attrs\":{\"textAlign\":null},\"content\":[{\"type\":\"text\",\"text\":\"Durante uma viagem choveu 5 vezes. A chuva caia pela manhã ou à tarde, nunca o dia todo. Houve 6 manhãs e 3 tardes sem chuva. Quantos dias durou a viagem?\"}]}]},{\"type\":\"options\",\"content\":[{\"type\":\"option\",\"attrs\":{\"letter\":\"A\"},\"content\":[{\"type\":\"paragraph\",\"attrs\":{\"textAlign\":null},\"content\":[{\"type\":\"text\",\"text\":\"6\"}]}]},{\"type\":\"option\",\"attrs\":{\"letter\":\"B\"},\"content\":[{\"type\":\"paragraph\",\"attrs\":{\"textAlign\":null},\"content\":[{\"type\":\"text\",\"text\":\"7\"}]}]},{\"type\":\"option\",\"attrs\":{\"letter\":\"C\"},\"content\":[{\"type\":\"paragraph\",\"attrs\":{\"textAlign\":null},\"content\":[{\"type\":\"text\",\"text\":\"8\"}]}]},{\"type\":\"option\",\"attrs\":{\"letter\":\"D\"},\"content\":[{\"type\":\"paragraph\",\"attrs\":{\"textAlign\":null},\"content\":[{\"type\":\"text\",\"text\":\"9\"}]}]},{\"type\":\"option\",\"attrs\":{\"letter\":\"E\"},\"content\":[{\"type\":\"paragraph\",\"attrs\":{\"textAlign\":null},\"content\":[{\"type\":\"text\",\"text\":\"10\"}]}]}]}]}]}', 'question'),
('63bd2e05-32e3-4d9c-9344-ee51a051547b', '2026-02-25 21:08:48', '2026-02-25 21:11:37', 'Língua Portuguesa', NULL, 'Múltipla Escolha', 'Média', 'A', NULL, NULL, 'concurso', 'FUVEST', 'FUVEST', 2025, NULL, NULL, '37-38', '{\"id\":\"100387007767191405258\",\"name\":\"Marcos Paulo\"}', '100387007767191405258', '[]', '{\"schemaVersion\":1,\"id\":\"63bd2e05-32e3-4d9c-9344-ee51a051547b\",\"createdAt\":\"2026-02-25T20:57:45.594Z\",\"updatedAt\":\"2026-02-25T21:10:46.895Z\",\"tipo\":\"Múltipla Escolha\",\"dificuldade\":\"Média\",\"tags\":[],\"gabarito\":{\"kind\":\"mcq\",\"correct\":\"A\"},\"source\":{\"kind\":\"concurso\",\"concurso\":\"FUVEST\",\"banca\":\"FUVEST\",\"ano\":2025,\"numero\":\"37-38\"},\"author\":{\"id\":\"100387007767191405258\",\"name\":\"Marcos Paulo\"},\"disciplina\":\"Língua Portuguesa\",\"items\":[{\"assunto\":\"Interpretação de Texto\",\"tags\":[\"renascimento\",\"violência simbólica\",\"leitura inferencial\"],\"gabarito\":{\"kind\":\"mcq\",\"correct\":\"C\"}},{\"assunto\":\"Figuras de Linguagem\",\"tags\":[\"conotação\",\"metáfora\",\"recursos expressivos\"],\"gabarito\":{\"kind\":\"mcq\",\"correct\":\"A\"}}]}', '{\"type\":\"doc\",\"content\":[{\"type\":\"set_questions\",\"attrs\":{\"mode\":null},\"content\":[{\"type\":\"base_text\",\"content\":[{\"type\":\"paragraph\",\"attrs\":{\"textAlign\":\"center\"},\"content\":[{\"type\":\"text\",\"marks\":[{\"type\":\"strong\"}],\"text\":\"Bem-vinda!\"}]},{\"type\":\"paragraph\",\"attrs\":{\"textAlign\":null},\"content\":[{\"type\":\"text\",\"text\":\"“Eram faíscas suas palavras que me queimavam\"}]},{\"type\":\"paragraph\",\"attrs\":{\"textAlign\":null},\"content\":[{\"type\":\"text\",\"text\":\"em doses homeopáticas\"}]},{\"type\":\"paragraph\",\"attrs\":{\"textAlign\":null},\"content\":[{\"type\":\"text\",\"text\":\"durante todas as noites…\"}]},{\"type\":\"paragraph\",\"attrs\":{\"textAlign\":null}},{\"type\":\"paragraph\",\"attrs\":{\"textAlign\":null},\"content\":[{\"type\":\"text\",\"text\":\"Foram longos anos, dia após dia perdendo um pouco\"}]},{\"type\":\"paragraph\",\"attrs\":{\"textAlign\":null},\"content\":[{\"type\":\"text\",\"text\":\"mais minha autoestima,\"}]},{\"type\":\"paragraph\",\"attrs\":{\"textAlign\":null},\"content\":[{\"type\":\"text\",\"text\":\"abrindo mão das roupas que gostava, dos estudos, do\"}]},{\"type\":\"paragraph\",\"attrs\":{\"textAlign\":null},\"content\":[{\"type\":\"text\",\"text\":\"trabalho e das amigas\"}]},{\"type\":\"paragraph\",\"attrs\":{\"textAlign\":null},\"content\":[{\"type\":\"text\",\"text\":\"fazendo de tudo pra evitar brigas,\"}]},{\"type\":\"paragraph\",\"attrs\":{\"textAlign\":null},\"content\":[{\"type\":\"text\",\"text\":\"mas ele sempre dizia que a culpa era minha.\"}]},{\"type\":\"paragraph\",\"attrs\":{\"textAlign\":null}},{\"type\":\"paragraph\",\"attrs\":{\"textAlign\":null},\"content\":[{\"type\":\"text\",\"text\":\"Até que um dia, me empurrou, me acuou\"}]},{\"type\":\"paragraph\",\"attrs\":{\"textAlign\":null},\"content\":[{\"type\":\"text\",\"text\":\"como se eu pudesse caber em qualquer fresta,\"}]},{\"type\":\"paragraph\",\"attrs\":{\"textAlign\":null},\"content\":[{\"type\":\"text\",\"text\":\"encurralada,\"}]},{\"type\":\"paragraph\",\"attrs\":{\"textAlign\":null},\"content\":[{\"type\":\"text\",\"text\":\"me mandou ficar calada e, com medo, obedeci.\"}]},{\"type\":\"paragraph\",\"attrs\":{\"textAlign\":null}},{\"type\":\"paragraph\",\"attrs\":{\"textAlign\":null},\"content\":[{\"type\":\"text\",\"text\":\"Eu pedia desculpa toda vez depois de falar\"}]},{\"type\":\"paragraph\",\"attrs\":{\"textAlign\":null},\"content\":[{\"type\":\"text\",\"text\":\"como se fosse um defeito de nascença querer me\"}]},{\"type\":\"paragraph\",\"attrs\":{\"textAlign\":null},\"content\":[{\"type\":\"text\",\"text\":\"colocar.\"}]},{\"type\":\"paragraph\",\"attrs\":{\"textAlign\":null}},{\"type\":\"paragraph\",\"attrs\":{\"textAlign\":null},\"content\":[{\"type\":\"text\",\"text\":\"A minha casa se tornou um ambiente tão hostil e eu,\"}]},{\"type\":\"paragraph\",\"attrs\":{\"textAlign\":null},\"content\":[{\"type\":\"text\",\"text\":\"prisioneira das minhas próprias ideias,\"}]},{\"type\":\"paragraph\",\"attrs\":{\"textAlign\":null},\"content\":[{\"type\":\"text\",\"text\":\"acreditando que o amor era isso, esse abismo, onde s\"}]},{\"type\":\"paragraph\",\"attrs\":{\"textAlign\":null},\"content\":[{\"type\":\"text\",\"text\":\" um fala e o outro, fica omisso.\"}]},{\"type\":\"paragraph\",\"attrs\":{\"textAlign\":null}},{\"type\":\"paragraph\",\"attrs\":{\"textAlign\":null},\"content\":[{\"type\":\"text\",\"text\":\"Precisei tirar forças de lugares sagrados\"}]},{\"type\":\"paragraph\",\"attrs\":{\"textAlign\":null},\"content\":[{\"type\":\"text\",\"text\":\"pra me afastar e reagir, recolher meus pedaços\"}]},{\"type\":\"paragraph\",\"attrs\":{\"textAlign\":null}},{\"type\":\"paragraph\",\"attrs\":{\"textAlign\":null},\"content\":[{\"type\":\"text\",\"text\":\"Meus olhos encheram de mar, eu desaguei,\"}]},{\"type\":\"paragraph\",\"attrs\":{\"textAlign\":null},\"content\":[{\"type\":\"text\",\"text\":\"decidi não mais me calar, denunciei!\"}]},{\"type\":\"paragraph\",\"attrs\":{\"textAlign\":null}},{\"type\":\"paragraph\",\"attrs\":{\"textAlign\":null},\"content\":[{\"type\":\"text\",\"text\":\"E depois do silêncio quebrado, meus pensamentos em\"}]},{\"type\":\"paragraph\",\"attrs\":{\"textAlign\":null},\"content\":[{\"type\":\"text\",\"text\":\"guerra cessaram,\"}]},{\"type\":\"paragraph\",\"attrs\":{\"textAlign\":null},\"content\":[{\"type\":\"text\",\"text\":\"recuperei o fôlego e ouvi meu coração sendo grato.\"}]},{\"type\":\"paragraph\",\"attrs\":{\"textAlign\":null}},{\"type\":\"paragraph\",\"attrs\":{\"textAlign\":null},\"content\":[{\"type\":\"text\",\"text\":\"Encontrei em mim um porto seguro, entendi que meu\"}]},{\"type\":\"paragraph\",\"attrs\":{\"textAlign\":null},\"content\":[{\"type\":\"text\",\"text\":\"corpo é meu lar\"}]},{\"type\":\"paragraph\",\"attrs\":{\"textAlign\":null},\"content\":[{\"type\":\"text\",\"text\":\"e, no caminho até ele, escolho quem anda comigo\"}]},{\"type\":\"paragraph\",\"attrs\":{\"textAlign\":null},\"content\":[{\"type\":\"text\",\"text\":\"e quem convido pra entrar.\"}]},{\"type\":\"paragraph\",\"attrs\":{\"textAlign\":null}},{\"type\":\"paragraph\",\"attrs\":{\"textAlign\":null},\"content\":[{\"type\":\"text\",\"text\":\"Hoje, quando olho pra dentro, vejo uma nova mulher\"}]},{\"type\":\"paragraph\",\"attrs\":{\"textAlign\":null},\"content\":[{\"type\":\"text\",\"text\":\"renascendo,\"}]},{\"type\":\"paragraph\",\"attrs\":{\"textAlign\":null},\"content\":[{\"type\":\"text\",\"text\":\"eu celebro sua chegada e contemplo essa nova vida.\"}]},{\"type\":\"paragraph\",\"attrs\":{\"textAlign\":null}},{\"type\":\"paragraph\",\"attrs\":{\"textAlign\":null},\"content\":[{\"type\":\"text\",\"text\":\"Sem medo, abro a janela de casa\"}]},{\"type\":\"paragraph\",\"attrs\":{\"textAlign\":null},\"content\":[{\"type\":\"text\",\"text\":\"e, com olhar de quem há tanto tempo esperava,\"}]},{\"type\":\"paragraph\",\"attrs\":{\"textAlign\":null},\"content\":[{\"type\":\"text\",\"text\":\"te pego pela mão e digo:\"}]},{\"type\":\"paragraph\",\"attrs\":{\"textAlign\":null},\"content\":[{\"type\":\"text\",\"text\":\"Seja bem-vinda!”\"}]},{\"type\":\"credits\",\"content\":[{\"type\":\"text\",\"text\":\"Mel Duarte. Colmeia - Poemas Reunidos.\"}]}]},{\"type\":\"question_item\",\"attrs\":{\"answerKey\":{\"kind\":\"mcq\",\"correct\":\"C\"},\"assunto\":\"Interpretação de Texto\",\"tags\":[\"renascimento\",\"violência simbólica\",\"leitura inferencial\"]},\"content\":[{\"type\":\"statement\",\"content\":[{\"type\":\"paragraph\",\"attrs\":{\"textAlign\":null},\"content\":[{\"type\":\"text\",\"text\":\"A expressão \"},{\"type\":\"text\",\"marks\":[{\"type\":\"strong\"},{\"type\":\"underline\"}],\"text\":\"bem-vinda\"},{\"type\":\"text\",\"text\":\" usada no título e repetida no último verso faz alusão\"}]}]},{\"type\":\"options\",\"content\":[{\"type\":\"option\",\"attrs\":{\"letter\":\"A\"},\"content\":[{\"type\":\"paragraph\",\"attrs\":{\"textAlign\":null},\"content\":[{\"type\":\"text\",\"text\":\"ao aprisionamento da mulher que não consegue se libertar do poderio masculino.\"}]}]},{\"type\":\"option\",\"attrs\":{\"letter\":\"B\"},\"content\":[{\"type\":\"paragraph\",\"attrs\":{\"textAlign\":null},\"content\":[{\"type\":\"text\",\"text\":\"à guerra interior e à falta de forças da mulher oprimida, que aceita sua condição.\"}]}]},{\"type\":\"option\",\"attrs\":{\"letter\":\"C\"},\"content\":[{\"type\":\"paragraph\",\"attrs\":{\"textAlign\":null},\"content\":[{\"type\":\"text\",\"text\":\"ao renascimento da mulher que alcança, após a opressão, coragem para encontrar-se a si mesma.\"}]}]},{\"type\":\"option\",\"attrs\":{\"letter\":\"D\"},\"content\":[{\"type\":\"paragraph\",\"attrs\":{\"textAlign\":null},\"content\":[{\"type\":\"text\",\"text\":\"ao rebaixamento da mulher que se cala e se desculpa, perdendo aos poucos sua autoestima.\"}]}]},{\"type\":\"option\",\"attrs\":{\"letter\":\"E\"},\"content\":[{\"type\":\"paragraph\",\"attrs\":{\"textAlign\":null},\"content\":[{\"type\":\"text\",\"text\":\"à força da mulher que, mesmo hostilizada, tem poder para fazer entrar em sua casa quem a encurralava.\"}]}]}]}]},{\"type\":\"question_item\",\"attrs\":{\"answerKey\":{\"kind\":\"mcq\",\"correct\":\"A\"},\"assunto\":\"Figuras de Linguagem\",\"tags\":[\"conotação\",\"metáfora\",\"recursos expressivos\"]},\"content\":[{\"type\":\"statement\",\"content\":[{\"type\":\"paragraph\",\"attrs\":{\"textAlign\":null},\"content\":[{\"type\":\"text\",\"text\":\"Assinale a alternativa que apresenta uma correspondência correta entre os versos destacados e os recursos utilizados para evidenciar a dor expressa no poema.\"}]}]},{\"type\":\"options\",\"content\":[{\"type\":\"option\",\"attrs\":{\"letter\":\"A\"},\"content\":[{\"type\":\"paragraph\",\"attrs\":{\"textAlign\":null},\"content\":[{\"type\":\"text\",\"text\":\"“Eram faíscas suas palavras que me queimavam em/ doses homeopáticas/ durante todas as noites…” ꟷ conotação: o predicativo “faíscas” e a forma verbal “queimavam” estão sendo usados em sentido figurado, enfatizando seu sofrimento.\"}]}]},{\"type\":\"option\",\"attrs\":{\"letter\":\"B\"},\"content\":[{\"type\":\"paragraph\",\"attrs\":{\"textAlign\":null},\"content\":[{\"type\":\"text\",\"text\":\"“Até que um dia, me empurrou, me acuou/como se eu pudesse caber em qualquer fresta, /encurralada” ꟷ antítese: os elementos “empurrou”, “acuou” e “encurralada” potencializam de forma contraditória seu sofrimento.\"}]}]},{\"type\":\"option\",\"attrs\":{\"letter\":\"C\"},\"content\":[{\"type\":\"paragraph\",\"attrs\":{\"textAlign\":null},\"content\":[{\"type\":\"text\",\"text\":\"“acreditando que o amor era isso, esse abismo, onde só/ um fala e o outro, fica omisso” ꟷ metonímia: o uso do aposto “esse abismo”, referindo-se a “amor”, expressa literalmente seu sofrimento.\"}]}]},{\"type\":\"option\",\"attrs\":{\"letter\":\"D\"},\"content\":[{\"type\":\"paragraph\",\"attrs\":{\"textAlign\":null},\"content\":[{\"type\":\"text\",\"text\":\"“Precisei tirar forças de lugares sagrados/ pra me afastar e reagir, recolher meus pedaços” ꟷ pleonasmo: o complemento “meus pedaços” reforça o significado do verbo “recolher”, acentuando seu sofrimento.\"}]}]},{\"type\":\"option\",\"attrs\":{\"letter\":\"E\"},\"content\":[{\"type\":\"paragraph\",\"attrs\":{\"textAlign\":null},\"content\":[{\"type\":\"text\",\"text\":\"“Meus olhos encheram de mar, eu desaguei, /decidi não mais me calar, denunciei!” ꟷ paronímia: os verbos “encher” e “desaguar” são elementos de significação próxima que dão ênfase a seu sofrimento.\"}]}]}]}]}]}]}', 'set_questions'),
