('6933d2f8-844b-41d2-b9aa-2e3d2f568ca3', '2026-02-16 23:36:42', '2026-02-21 16:28:49', 'Matemática', 'Análise Combinatória', 'Múltipla Escolha', 'Média', 'C', NULL, NULL, 'concurso', 'Escola Naval', 'Marinha do Brasil', 2023, NULL, NULL, '1', '{\"id\":\"100387007767191405258\",\"name\":\"Marcos Paulo\"}', '100387007767191405258', '[\"Escola Naval\",\"2023\"]', '{\"schemaVersion\":1,\"id\":\"6933d2f8-844b-41d2-b9aa-2e3d2f568ca3\",\"createdAt\":\"2026-02-16T23:34:56.014Z\",\"updatedAt\":\"2026-02-19T11:16:15.882Z\",\"tipo\":\"Múltipla Escolha\",\"dificuldade\":\"Média\",\"tags\":[\"Escola Naval\",\"2023\"],\"gabarito\":{\"kind\":\"mcq\",\"correct\":\"C\",\"rubric\":null},\"source\":{\"kind\":\"concurso\",\"concurso\":\"Escola Naval\",\"banca\":\"Marinha do Brasil\",\"ano\":2023,\"numero\":\"1\"},\"author\":{\"id\":\"100387007767191405258\",\"name\":\"Marcos Paulo\"},\"disciplina\":\"Matemática\",\"assunto\":\"Análise Combinatória\"}', '{\"type\":\"doc\",\"content\":[{\"type\":\"question\",\"attrs\":{\"tipo\":null},\"content\":[{\"type\":\"statement\",\"content\":[{\"type\":\"paragraph\",\"attrs\":{\"textAlign\":null},\"content\":[{\"type\":\"text\",\"text\":\"A camisa de um grande clube de futebol carioca e mundial é formada por sete listras verticais (frente da camisa) das cores preta e branca, conforme a figura 1.\"}]},{\"type\":\"paragraph\",\"attrs\":{\"textAlign\":null},\"content\":[{\"type\":\"image\",\"attrs\":{\"id\":\"87cca904-d3ef-4c04-92cc-d47f11547606\",\"src\":\"data:image/png;base64,\",\"width\":null,\"align\":\"center\"}}]},{\"type\":\"paragraph\",\"attrs\":{\"textAlign\":null},\"content\":[{\"type\":\"text\",\"text\":\"A empresa que confecciona a camisa oferece modelos com diferentes maneiras de disposição das cores das listras, e o clube exige que sempre exista a cor preta entre brancas e/ou a cor branca entre pretas, conforme apresentado na figura 1 (camisa original) e nas figuras 2, 3 e 4.\"}]},{\"type\":\"paragraph\",\"attrs\":{\"textAlign\":null},\"content\":[{\"type\":\"image\",\"attrs\":{\"id\":\"919545cf-bad1-4e3d-9c05-7f51d40c5e7a\",\"src\":\"data:image/png;base64,\",\"width\":null,\"align\":\"center\"}}]},{\"type\":\"paragraph\",\"attrs\":{\"textAlign\":null},\"content\":[{\"type\":\"text\",\"text\":\"Considerando apenas a frente da camisa e cumprindo a exigência do clube, quantos modelos de camisa podem ser confeccionados pela empresa?\"}]}]},{\"type\":\"options\",\"content\":[{\"type\":\"option\",\"attrs\":{\"letter\":\"A\"},\"content\":[{\"type\":\"paragraph\",\"attrs\":{\"textAlign\":null},\"content\":[{\"type\":\"text\",\"text\":\"126\"}]}]},{\"type\":\"option\",\"attrs\":{\"letter\":\"B\"},\"content\":[{\"type\":\"paragraph\",\"attrs\":{\"textAlign\":null},\"content\":[{\"type\":\"text\",\"text\":\"122\"}]}]},{\"type\":\"option\",\"attrs\":{\"letter\":\"C\"},\"content\":[{\"type\":\"paragraph\",\"attrs\":{\"textAlign\":null},\"content\":[{\"type\":\"text\",\"text\":\"114\"}]}]},{\"type\":\"option\",\"attrs\":{\"letter\":\"D\"},\"content\":[{\"type\":\"paragraph\",\"attrs\":{\"textAlign\":null},\"content\":[{\"type\":\"text\",\"text\":\"112\"}]}]},{\"type\":\"option\",\"attrs\":{\"letter\":\"E\"},\"content\":[{\"type\":\"paragraph\",\"attrs\":{\"textAlign\":null},\"content\":[{\"type\":\"text\",\"text\":\"64\"}]}]}]}]}]}', 'question'),
('69e179a2-958b-45d8-a005-1622a7e71394', '2026-02-22 19:05:40', '2026-02-22 19:05:40', 'Matemática', 'Probabilidade Simples', 'Múltipla Escolha', 'Média', 'C', NULL, NULL, 'concurso', NULL, 'FUVEST', 2016, NULL, NULL, '05', '{\"id\":\"100387007767191405258\",\"name\":\"Marcos Paulo\"}', '100387007767191405258', '[\"bolas\",\"caixa\",\"retirada sem reposição\"]', '{\"schemaVersion\":1,\"id\":\"69e179a2-958b-45d8-a005-1622a7e71394\",\"createdAt\":\"2026-02-22T19:04:45.527Z\",\"updatedAt\":\"2026-02-22T19:04:55.341Z\",\"tipo\":\"Múltipla Escolha\",\"dificuldade\":\"Média\",\"tags\":[\"bolas\",\"caixa\",\"retirada sem reposição\"],\"gabarito\":{\"kind\":\"mcq\",\"correct\":\"C\"},\"source\":{\"kind\":\"concurso\",\"banca\":\"FUVEST\",\"ano\":2016,\"numero\":\"05\"},\"author\":{\"id\":\"100387007767191405258\",\"name\":\"Marcos Paulo\"},\"disciplina\":\"Matemática\",\"assunto\":\"Probabilidade Simples\"}', '{\"type\":\"doc\",\"content\":[{\"type\":\"question\",\"attrs\":{\"tipo\":null},\"content\":[{\"type\":\"statement\",\"content\":[{\"type\":\"paragraph\",\"attrs\":{\"textAlign\":null},\"content\":[{\"type\":\"text\",\"text\":\"Em um experimento probabilístico, Joana retirará aleatoriamente 2 bolas de uma caixa contendo bolas azuis e bolas vermelhas. Ao montar-se o experimento, colocam-se 6 bolas azuis na caixa. Quantas bolas vermelhas devem ser acrescentadas para que a probabilidade de Joana obter 2 azuis seja \"},{\"type\":\"math_inline\",\"attrs\":{\"latex\":\"1/3\"}},{\"type\":\"text\",\"text\":\"?\"}]}]},{\"type\":\"options\",\"content\":[{\"type\":\"option\",\"attrs\":{\"letter\":\"A\"},\"content\":[{\"type\":\"paragraph\",\"attrs\":{\"textAlign\":null},\"content\":[{\"type\":\"text\",\"text\":\"2\"}]}]},{\"type\":\"option\",\"attrs\":{\"letter\":\"B\"},\"content\":[{\"type\":\"paragraph\",\"attrs\":{\"textAlign\":null},\"content\":[{\"type\":\"text\",\"text\":\"4\"}]}]},{\"type\":\"option\",\"attrs\":{\"letter\":\"C\"},\"content\":[{\"type\":\"paragraph\",\"att