('6f394d6f-3f53-4e7a-95cf-9575c6bf88b3', '2026-02-08 14:21:11', '2026-02-08 14:21:11', 'Matemática', 'Análise Combinatória', 'Múltipla Escolha', 'media', 'B', NULL, NULL, 'concurso', 'ENEM', 'INEP', 2014, NULL, NULL, NULL, NULL, NULL, '[]', '{\"schemaVersion\":1,\"id\":\"6f394d6f-3f53-4e7a-95cf-9575c6bf88b3\",\"createdAt\":\"2026-02-08T14:14:55.825Z\",\"updatedAt\":\"2026-02-08T14:21:08.985Z\",\"tipo\":\"Múltipla Escolha\",\"dificuldade\":\"Média\",\"tags\":[],\"gabarito\":{\"kind\":\"mcq\",\"correct\":\"B\"},\"source\":{\"kind\":\"concurso\",\"concurso\":\"ENEM\",\"banca\":\"INEP\",\"ano\":2014},\"disciplina\":\"Matemática\",\"assunto\":\"Análise Combinatória\"}', '{\"type\":\"doc\",\"content\":[{\"type\":\"question\",\"attrs\":{\"tipo\":null},\"content\":[{\"type\":\"statement\",\"content\":[{\"type\":\"paragraph\",\"attrs\":{\"textAlign\":null},\"content\":[{\"type\":\"text\",\"text\":\"Um cliente de uma videolocadora tem o hábito de alugar dois filmes por vez. Quando os devolve, sempre pega outros dois filmes e assim sucessivamente. Ele soube que a videolocadora recebeu alguns lançamentos, sendo 8 filmes de ação, 5 de comédia e 3 de drama e, por isso, estabeleceu uma estratégia para ver todos esses 16 lançamentos. Inicialmente alugará, em cada vez, um filme de ação e um de comédia. Quando se esgotarem as possibilidades de comédia, o cliente alugará um filme de ação e um de drama, até que todos os lançamentos sejam vistos e sem que nenhum filme seja repetido.\"}]},{\"type\":\"paragraph\",\"attrs\":{\"textAlign\":null},\"content\":[{\"type\":\"text\",\"text\":\"De quantas formas distintas a estratégia desse cliente poderá ser posta em prática?\"}]}]},{\"type\":\"options\",\"content\":[{\"type\":\"option\",\"attrs\":{\"letter\":\"A\"},\"content\":[{\"type\":\"paragraph\",\"attrs\":{\"textAlign\":null},\"content\":[{\"type\":\"math_inline\",\"attrs\":{\"latex\":\"20\\\\times8!+(3!)^2\"}}]}]},{\"type\":\"option\",\"attrs\":{\"letter\":\"B\"},\"content\":[{\"type\":\"paragraph\",\"attrs\":{\"textAlign\":null},\"content\":[{\"type\":\"math_inline\",\"attrs\":{\"latex\":\"8!\\\\times 5!\\\\times 3!\"}}]}]},{\"type\":\"option\",\"attrs\":{\"letter\":\"C\"},\"content\":[{\"type\":\"paragraph\",\"attrs\":{\"textAlign\":null},\"content\":[{\"type\":\"math_inline\",\"attrs\":{\"latex\":\"\\\\dfrac{8!\\\\times 5!\\\\times 3!}{2^8}\"}}]}]},{\"type\":\"option\",\"attrs\":{\"letter\":\"D\"},\"content\":[{\"type\":\"paragraph\",\"attrs\":{\"textAlign\":null},\"content\":[{\"type\":\"math_inline\",\"attrs\":{\"latex\":\"\\\\dfrac{8!\\\\times 5!\\\\times 3!}{2^2}\"}}]}]},{\"type\":\"option\",\"attrs\":{\"letter\":\"E\"},\"content\":[{\"type\":\"paragraph\",\"attrs\":{\"textAlign\":null},\"content\":[{\"type\":\"math_inline\",\"attrs\":{\"latex\":\"\\\\dfrac{16!}{2^8}\"}}]}]}]}]}]}', 'question'),
