\":\"math_inline\",\"attrs\":{\"latex\":\"x \\\\geq \\\\frac{10}{3}\"}},{\"type\":\"text\",\"text\":\". \"}]}]},{\"type\":\"list_item\",\"content\":[{\"type\":\"paragraph\",\"attrs\":{\"textAlign\":null},\"content\":[{\"type\":\"math_inline\",\"attrs\":{\"latex\":\"x \\\\cdot 10^{2.000.000}\"}},{\"type\":\"text\",\"text\":\" é um inteiro par.\"}]}]}]},{\"type\":\"paragraph\",\"attrs\":{\"textAlign\":null},\"content\":[{\"type\":\"text\",\"text\":\"Então,\"}]}]},{\"type\":\"options\",\"content\":[{\"type\":\"option\",\"attrs\":{\"letter\":\"A\"},\"content\":[{\"type\":\"paragraph\",\"attrs\":{\"textAlign\":null},\"content\":[{\"type\":\"text\",\"text\":\"nenhuma das três afirmações é verdadeira.\"}]}]},{\"type\":\"option\",\"attrs\":{\"letter\":\"B\"},\"content\":[{\"type\":\"paragraph\",\"attrs\":{\"textAlign\":null},\"content\":[{\"type\":\"text\",\"text\":\"apenas as afirmações I e II são verdadeiras.\"}]}]},{\"type\":\"option\",\"attrs\":{\"letter\":\"C\"},\"content\":[{\"type\":\"paragraph\",\"attrs\":{\"textAlign\":null},\"content\":[{\"type\":\"text\",\"text\":\"apenas a afirmação I é verdadeira.\"}]}]},{\"type\":\"option\",\"attrs\":{\"letter\":\"D\"},\"content\":[{\"type\":\"paragraph\",\"attrs\":{\"textAlign\":null},\"content\":[{\"type\":\"text\",\"text\":\"apenas a afirmação II é verdadeira.\"}]}]},{\"type\":\"option\",\"attrs\":{\"letter\":\"E\"},\"content\":[{\"type\":\"paragraph\",\"attrs\":{\"textAlign\":null},\"content\":[{\"type\":\"text\",\"text\":\"apenas a afirmação III é verdadeira.\"}]}]}]}]}]}', 'question'),
