('87e6092f-78ca-4a93-b303-1ea3243b8520', '2026-02-08 14:48:42', '2026-02-08 14:48:42', 'Matemática', 'Análise Combinatória', 'Múltipla Escolha', 'media', 'C', NULL, NULL, 'concurso', 'ENEM', 'INEP', NULL, NULL, NULL, NULL, NULL, NULL, '[]', '{\"schemaVersion\":1,\"id\":\"87e6092f-78ca-4a93-b303-1ea3243b8520\",\"createdAt\":\"2026-02-08T14:46:04.101Z\",\"updatedAt\":\"2026-02-08T14:48:40.508Z\",\"tipo\":\"Múltipla Escolha\",\"dificuldade\":\"Média\",\"tags\":[],\"gabarito\":{\"kind\":\"mcq\",\"correct\":\"C\"},\"source\":{\"kind\":\"concurso\",\"concurso\":\"ENEM\",\"banca\":\"INEP\"},\"disciplina\":\"Matemática\",\"assunto\":\"Análise Combinatória\"}', '{\"type\":\"doc\",\"content\":[{\"type\":\"question\",\"attrs\":{\"tipo\":null},\"content\":[{\"type\":\"statement\",\"content\":[{\"type\":\"paragraph\",\"attrs\":{\"textAlign\":null},\"content\":[{\"type\":\"text\",\"text\":\"Desde 1999 houve uma significativa mudança nas placas dos carros particulares em todo o Brasil. As placas, que antes eram formadas apenas por seis caracteres alfanuméricos, foram acrescidas de uma letra, passando a ser formadas por sete caracteres, sendo que os três primeiros caracteres devem ser letras (dentre as 26 letras do alfabeto) e os quatro últimos devem ser algarismos (de 0 a 9). Essa mudança possibilitou a criação de um cadastro nacional unificado de todos os veículos licenciados e ainda aumentou significativamente a quantidade de combinações possíveis de placas. Não são utilizadas placas em que todos os algarismos sejam iguais a zero.\"}]},{\"type\":\"paragraph\",\"attrs\":{\"textAlign\":null},\"content\":[{\"type\":\"text\",\"text\":\"Nessas condições, a quantidade de placas que podem ser utilizadas é igual a\"}]}]},{\"type\":\"options\",\"content\":[{\"type\":\"option\",\"attrs\":{\"letter\":\"A\"},\"content\":[{\"type\":\"paragraph\",\"attrs\":{\"textAlign\":null},\"content\":[{\"type\":\"math_inline\",\"attrs\":{\"latex\":\"26^3+9^4\"}}]}]},{\"type\":\"option\",\"attrs\":{\"letter\":\"B\"},\"content\":[{\"type\":\"paragraph\",\"attrs\":{\"textAlign\":null},\"content\":[{\"type\":\"math_inline\",\"attrs\":{\"latex\":\"26^3\\\\times9^4\"}}]}]},{\"type\":\"option\",\"attrs\":{\"letter\":\"C\"},\"content\":[{\"type\":\"paragraph\",\"attrs\":{\"textAlign\":null},\"content\":[{\"type\":\"math_inline\",\"attrs\":{\"latex\":\"26^3(10^4-1)\"}}]}]},{\"type\":\"option\",\"attrs\":{\"letter\":\"D\"},\"content\":[{\"type\":\"paragraph\",\"attrs\":{\"textAlign\":null},\"content\":[{\"type\":\"math_inline\",\"attrs\":{\"latex\":\"(26^3+10^4)-1\"}}]}]},{\"type\":\"option\",\"attrs\":{\"letter\":\"E\"},\"content\":[{\"type\":\"paragraph\",\"attrs\":{\"textAlign\":null},\"content\":[{\"type\":\"math_inline\",\"attrs\":{\"latex\":\"(26^3\\\\times10^4)-1\"}}]}]}]}]}]}', 'question'),
