('89d4eeae-b536-4f33-9830-8df23546d718', '2026-02-05 16:16:13', '2026-02-05 16:16:13', 'Matemática', 'Funções', 'Múltipla Escolha', 'facil', 'B', NULL, NULL, 'concurso', 'UERJ', 'UERJ', 2025, NULL, NULL, NULL, NULL, NULL, '[]', '{\"schemaVersion\":1,\"id\":\"89d4eeae-b536-4f33-9830-8df23546d718\",\"createdAt\":\"2026-02-05T16:08:40.412Z\",\"updatedAt\":\"2026-02-05T16:16:05.561Z\",\"tipo\":\"Múltipla Escolha\",\"dificuldade\":\"Fácil\",\"tags\":[],\"gabarito\":{\"kind\":\"mcq\",\"correct\":\"B\"},\"source\":{\"kind\":\"concurso\",\"concurso\":\"UERJ\",\"banca\":\"UERJ\",\"ano\":2025},\"disciplina\":\"Matemática\",\"assunto\":\"Funções\"}', '{\"type\":\"doc\",\"content\":[{\"type\":\"question\",\"content\":[{\"type\":\"statement\",\"content\":[{\"type\":\"paragraph\",\"attrs\":{\"textAlign\":\"justify\"},\"content\":[{\"type\":\"text\",\"text\":\"Os veículos para transporte de passageiros em  determinado município têm vida útil que varia entre 4 e 6 anos, dependendo do tipo de veículo. Nos gráficos está representada a desvalorização\"}]},{\"type\":\"paragraph\",\"attrs\":{\"textAlign\":null},\"content\":[{\"type\":\"text\",\"text\":\"de quatro desses veículos ao longo dos anos, a partir de sua compra na fábrica.\"}]},{\"type\":\"paragraph\",\"attrs\":{\"textAlign\":null},\"content\":[{\"type\":\"image\",\"attrs\":{\"src\":\"https://mpfaraujo.com.br/guardafiguras/uploads/fa46a339cd76383541f8c4c113657b73a5eb8bfb2752e56162e3c6d57bf53868.png\",\"width\":\"113\",\"align\":null}},{\"type\":\"image\",\"attrs\":{\"src\":\"https://mpfaraujo.com.br/guardafiguras/uploads/5e0a69bfdc532f10cbd0f01caf22b6e4ff1fa5fabc6417583a4f3ccd185099bb.png\",\"width\":\"113\",\"align\":null}},{\"type\":\"image\",\"attrs\":{\"src\":\"https://mpfaraujo.com.br/guardafiguras/uploads/ee00721fd3aef421c941ca04fb8cb832634fbb60e69103c68a6c7ae801d5cf01.png\",\"width\":\"113\",\"align\":null}},{\"type\":\"image\",\"attrs\":{\"src\":\"https://mpfaraujo.com.br/guardafiguras/uploads/eace29af0e51f0adf35e8ff50c