('9baec22b-36c9-47b1-92b4-486a13fec8df', '2026-01-31 15:26:43', '2026-01-31 15:26:43', 'Matemática', 'Análise Combinatória', 'Múltipla Escolha', 'media', NULL, NULL, NULL, 'original', NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, '[]', '{\"schemaVersion\":1,\"id\":\"9baec22b-36c9-47b1-92b4-486a13fec8df\",\"createdAt\":\"2026-01-31T15:21:47.253Z\",\"updatedAt\":\"2026-01-31T15:26:38.646Z\",\"tipo\":\"Múltipla Escolha\",\"dificuldade\":\"Média\",\"tags\":[],\"gabarito\":{\"kind\":\"mcq\",\"correct\":\"D\"},\"source\":{\"kind\":\"original\"},\"disciplina\":\"Matemática\",\"assunto\":\"Análise Combinatória\"}', '{\"type\":\"doc\",\"content\":[{\"type\":\"question\",\"content\":[{\"type\":\"statement\",\"content\":[{\"type\":\"paragraph\",\"attrs\":{\"textAlign\":null},\"content\":[{\"type\":\"text\",\"text\":\"Aldo e Baldo dividem um apartamento onde há um varal para secarem apenas 4 peças de roupa lado a lado. No fim de uma semana, Aldo tinha usado seis camisas idênticas de seu uniforme de motorista e Baldo havia usado três camisas idênticas de seu uniforme de enfermeiro. Após a lavagem dessas peças de roupa, 4 foram colocadas no varal e o restante ficou na máquina. Quantas são as disposições possíveis das roupas no varal do apartamento de Aldo e Baldo?\"}]}]},{\"type\":\"options\",\"content\":[{\"type\":\"option\",\"attrs\":{\"letter\":\"A\"},\"content\":[{\"type\":\"paragraph\",\"attrs\":{\"textAlign\":null},\"content\":[{\"type\":\"text\",\"text\":\"10\"}]}]},{\"type\":\"option\",\"attrs\":{\"letter\":\"B\"},\"content\":[{\"type\":\"paragraph\",\"attrs\":{\"textAlign\":null},\"content\":[{\"type\":\"text\",\"text\":\"12\"}]}]},{\"type\":\"option\",\"attrs\":{\"letter\":\"C\"},\"content\":[{\"type\":\"paragraph\",\"attrs\":{\"textAlign\":null},\"content\":[{\"type\":\"text\",\"text\":\"14\"}]}]},{\"type\":\"option\",\"attrs\":{\"letter\":\"D\"},\"content\":[{\"type\":\"paragraph\",\"attrs\":{\"textAlign\":null},\"content\":[{\"type\":\"text\",\"text\":\"15\"}]}]},{\"type\":\"option\",\"attrs\":{\"letter\":\"E\"},\"content\":[{\"type\":\"paragraph\",\"attrs\":{\"textAlign\":null},\"content\":[{\"type\":\"text\",\"text\":\"16\"}]}]}]}]}]}', 'question'),
