('dfa81312-7288-4dd4-ab7a-85bb119e0aec', '2026-02-23 12:34:40', '2026-02-23 13:39:52', 'Matemática', 'Juros Simples', 'Múltipla Escolha', 'Média', 'D', NULL, NULL, 'concurso', '1o Ex. Qual. UERJ', 'UERJ', 2025, NULL, NULL, '29', '{\"id\":\"100387007767191405258\",\"name\":\"Marcos Paulo\"}', '100387007767191405258', '[\"banco\",\"imposto de renda\",\"aplicação financeira\",\"rendimento anual\"]', '{\"schemaVersion\":1,\"id\":\"dfa81312-7288-4dd4-ab7a-85bb119e0aec\",\"createdAt\":\"2026-02-23T12:30:10.580Z\",\"updatedAt\":\"2026-02-23T13:31:03.366Z\",\"tipo\":\"Múltipla Escolha\",\"dificuldade\":\"Média\",\"tags\":[\"banco\",\"imposto de renda\",\"aplicação financeira\",\"rendimento anual\"],\"gabarito\":{\"kind\":\"mcq\",\"correct\":\"D\",\"rubric\":null},\"source\":{\"kind\":\"concurso\",\"banca\":\"UERJ\",\"ano\":2025,\"numero\":\"29\",\"concurso\":\"1o Ex. Qual. UERJ\"},\"author\":{\"id\":\"100387007767191405258\",\"name\":\"Marcos Paulo\"},\"disciplina\":\"Matemática\",\"assunto\":\"Juros Simples\"}', '{\"type\":\"doc\",\"content\":[{\"type\":\"question\",\"attrs\":{\"tipo\":null},\"content\":[{\"type\":\"statement\",\"content\":[{\"type\":\"paragraph\",\"attrs\":{\"textAlign\":null},\"content\":[{\"type\":\"text\",\"text\":\"Para determinado tipo de aplicação financeira, um banco oferece a taxa de juros de 12% ao ano. Do rendimento obtido nessa aplicação, é descontado apenas o percentual de imposto de renda , de acordo com a tabela a seguir.\"}]},{\"type\":\"paragraph\",\"attrs\":{\"textAlign\":null},\"content\":[{\"type\":\"image\",\"attrs\":{\"id\":\"0a205d21-2661-48ba-9c9a-f0624e54aa7b\",\"src\":\"https://mpfaraujo.com.br/guardafiguras/uploads/948d102ce51a0e2d5ba63a5f55abff0c07e2cbee6376302e08c3d95a42515255.png\",\"width\":302,\"align\":\"center\"}}]},{\"type\":\"paragraph\",\"attrs\":{\"textAlign\":null},\"content\":[{\"type\":\"text\",\"text\":\"Assim, se um cliente deixar o dinheiro aplicado nesse banco por 800 dias, seu rendimento em um ano, já descontad