('e5c28a6f-b80e-4abf-a352-7a652ea49ae8', '2026-01-31 20:28:26', '2026-01-31 20:28:26', 'Matemática', 'Sistemas Lineares', 'Múltipla Escolha', 'dificil', NULL, NULL, NULL, 'original', NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, '[]', '{\"schemaVersion\":1,\"id\":\"e5c28a6f-b80e-4abf-a352-7a652ea49ae8\",\"createdAt\":\"2026-01-31T20:23:55.166Z\",\"updatedAt\":\"2026-01-31T20:28:21.314Z\",\"tipo\":\"Múltipla Escolha\",\"dificuldade\":\"Difícil\",\"tags\":[],\"gabarito\":{\"kind\":\"mcq\",\"correct\":\"C\"},\"source\":{\"kind\":\"original\"},\"disciplina\":\"Matemática\",\"assunto\":\"Sistemas Lineares\"}', '{\"type\":\"doc\",\"content\":[{\"type\":\"question\",\"content\":[{\"type\":\"statement\",\"content\":[{\"type\":\"paragraph\",\"attrs\":{\"textAlign\":null},\"content\":[{\"type\":\"text\",\"text\":\"Para estimular a produtividade, uma empresa instituiu prêmios a serem pagos nos meses de janeiro, referente à captação de clientes no período de julho à dezembro do ano anterior, e julho, referente à captação de clientes no período de janeiro a junho do ano corrente. Os prêmios são proporcionais aos valores dos produtos P\"},{\"type\":\"text\",\"marks\":[{\"type\":\"subscript\"}],\"text\":\"1\"},{\"type\":\"text\",\"text\":\", P\"},{\"type\":\"text\",\"marks\":[{\"type\":\"subscript\"}],\"text\":\"2\"},{\"type\":\"text\",\"text\":\" e P\"},{\"type\":\"text\",\"marks\":[{\"type\":\"subscript\"}],\"text\":\"3\"},{\"type\":\"text\",\"text\":\" ofertados pela empresa. Em julho de 2019, Aldo recebeu um prêmio de R$7.000,00 por ter captado 7 clientes para o produto P\"},{\"type\":\"text\",\"marks\":[{\"type\":\"subscript\"}],\"text\":\"1\"},{\"type\":\"text\",\"text\":\", 5 clientes para o produto P\"},{\"type\":\"text\",\"marks\":[{\"type\":\"subscript\"}],\"text\":\"2\"},{\"type\":\"text\",\"text\":\" e 9 clientes para o produto P\"},{\"type\":\"text\",\"marks\":[{\"type\":\"subscript\"}],\"text\":\"3\"},{\"type\":\"text\",\"text\":\". Em janeiro de 2020, Aldo recebeu R$9.000,00 por ter captado 10 clientes para o produto P\"},{\"type\":\"text\",\"marks\":[{\"type\":\"subscript\"}],\"text\":\"1\"},{\"type\":\"text\",\"text\":\", 7 clientes para o produto P\"},{\"type\":\"text\",\"marks\":[{\"type\":\"subscript\"}],\"text\":\"2\"},{\"type\":\"text\",\"text\":\" e 13 clientes para o produto P\"},{\"type\":\"text\",\"marks\":[{\"type\":\"subscript\"}],\"text\":\"3\"},{\"type\":\"text\",\"text\":\". Mesmo sem nenhum reajuste nos valores dos produtos, no período de janeiro a junho de 2020, Aldo captou apenas 1 cliente para cada produto.\"}]},{\"type\":\"paragraph\",\"attrs\":{\"textAlign\":null},\"content\":[{\"type\":\"text\",\"text\":\"Quanto, em reais, Aldo recebeu de prêmio em julho de 2020?\"}]}]},{\"type\":\"options\",\"content\":[{\"type\":\"option\",\"attrs\":{\"letter\":\"A\"},\"content\":[{\"type\":\"paragraph\",\"attrs\":{\"textAlign\":null},\"content\":[{\"type\":\"text\",\"text\":\"1.000,00\"}]}]},{\"type\":\"option\",\"attrs\":{\"letter\":\"B\"},\"content\":[{\"type\":\"paragraph\",\"attrs\":{\"textAlign\":null},\"content\":[{\"type\":\"text\",\"text\":\"2.000,00\"}]}]},{\"type\":\"option\",\"attrs\":{\"letter\":\"C\"},\"content\":[{\"type\":\"paragraph\",\"attrs\":{\"textAlign\":null},\"content\":[{\"type\":\"text\",\"text\":\"3.000,00\"}]}]},{\"type\":\"option\",\"attrs\":{\"letter\":\"D\"},\"content\":[{\"type\":\"paragraph\",\"attrs\":{\"textAlign\":null},\"content\":[{\"type\":\"text\",\"text\":\"4.000,00\"}]}]},{\"type\":\"option\",\"attrs\":{\"letter\":\"E\"},\"content\":[{\"type\":\"paragraph\",\"attrs\":{\"textAlign\":null},\"content\":[{\"type\":\"text\",\"text\":\"5.000,00\"}]}]}]}]}]}', 'question'),
