('f528cae8-b9cf-4d55-9f6b-9f5440c5a205', '2026-02-05 16:51:07', '2026-02-05 16:51:07', 'Matemática', 'Porcentagem', 'Múltipla Escolha', 'media', 'A', NULL, NULL, 'concurso', 'UERJ', 'UERJ', 2025, NULL, NULL, NULL, NULL, NULL, '[]', '{\"schemaVersion\":1,\"id\":\"f528cae8-b9cf-4d55-9f6b-9f5440c5a205\",\"createdAt\":\"2026-02-05T16:50:00.994Z\",\"updatedAt\":\"2026-02-05T16:50:59.950Z\",\"tipo\":\"Múltipla Escolha\",\"dificuldade\":\"Média\",\"tags\":[],\"gabarito\":{\"kind\":\"mcq\",\"correct\":\"A\"},\"source\":{\"kind\":\"concurso\",\"concurso\":\"UERJ\",\"banca\":\"UERJ\",\"ano\":2025},\"disciplina\":\"Matemática\",\"assunto\":\"Porcentagem\"}', '{\"type\":\"doc\",\"content\":[{\"type\":\"question\",\"content\":[{\"type\":\"statement\",\"content\":[{\"type\":\"paragraph\",\"attrs\":{\"textAlign\":null},\"content\":[{\"type\":\"text\",\"text\":\"As farmácias W e Y adquirem determinado produto com igual preço de custo. A farmácia W vende esse produto com 50% de lucro sobre o preço de custo. Na farmácia Y, o preço de venda do produto é 80% mais caro do que na farmácia W.\"}]},{\"type\":\"paragraph\",\"attrs\":{\"textAlign\":null},\"content\":[{\"type\":\"text\",\"text\":\"O lucro da farmácia Y em relação ao preço de custo é de:\"}]}]},{\"type\":\"options\",\"content\":[{\"type\":\"option\",\"attrs\":{\"letter\":\"A\"},\"content\":[{\"type\":\"paragraph\",\"attrs\":{\"textAlign\":null},\"content\":[{\"type\":\"text\",\"text\":\"170%\"}]}]},{\"type\":\"option\",\"attrs\":{\"letter\":\"B\"},\"content\":[{\"type\":\"paragraph\",\"attrs\":{\"textAlign\":null},\"content\":[{\"type\":\"text\",\"text\":\"150%\"}]}]},{\"type\":\"option\",\"attrs\":{\"letter\":\"C\"},\"content\":[{\"type\":\"paragraph\",\"attrs\":{\"textAlign\":null},\"content\":[{\"type\":\"text\",\"text\":\"130%\"}]}]},{\"type\":\"option\",\"attrs\":{\"letter\":\"D\"},\"content\":[{\"type\":\"paragraph\",\"attrs\":{\"textAlign\":null},\"content\":[{\"type\":\"text\",\"text\":\"110%\"}]}]}]}]}]}', 'question')