('f71ae700-82d4-4fc5-8da7-546749b55aa9', '2026-02-19 12:02:59', '2026-02-19 12:02:59', 'Matemática', 'Interpretação de Gráficos', 'Múltipla Escolha', 'Média', 'C', NULL, NULL, 'concurso', 'FUVEST', 'FUVEST', 2019, NULL, NULL, '49', '{\"id\":\"100387007767191405258\",\"name\":\"Marcos Paulo\"}', '100387007767191405258', '[\"função\",\"crescimento\",\"variação\",\"análise gráfica\"]', '{\"schemaVersion\":1,\"id\":\"f71ae700-82d4-4fc5-8da7-546749b55aa9\",\"createdAt\":\"2026-02-19T12:00:09.706Z\",\"updatedAt\":\"2026-02-19T12:02:27.224Z\",\"tipo\":\"Múltipla Escolha\",\"dificuldade\":\"Média\",\"tags\":[\"função\",\"crescimento\",\"variação\",\"análise gráfica\"],\"gabarito\":{\"kind\":\"mcq\",\"correct\":\"C\"},\"source\":{\"kind\":\"concurso\",\"concurso\":\"FUVEST\",\"banca\":\"FUVEST\",\"ano\":2019,\"numero\":\"49\"},\"author\":{\"id\":\"100387007767191405258\",\"name\":\"Marcos Paulo\"},\"disciplina\":\"Matemática\",\"assunto\":\"Interpretação de Gráficos\"}', '{\"type\":\"doc\",\"content\":[{\"type\":\"question\",\"attrs\":{\"tipo\":null},\"content\":[{\"type\":\"statement\",\"content\":[{\"type\":\"paragraph\",\"attrs\":{\"textAlign\":null},\"content\":[{\"type\":\"text\",\"text\":\"Um dono de restaurante assim descreveu a evolução do faturamento quinzenal de seu negócio, ao longo dos dez primeiros meses após a inauguração: \\\"Até o final dos três primeiros meses, tivemos uma velocidade de crescimento mais ou menos constante, quando então sofremos uma queda abrupta, com o faturamento caindo à metade do que tinha sido atingido. Em seguida, voltamos a crescer, igualando, um mês e meio depois dessa queda, o faturamento obtido ao final do terceiro mês. Agora, ao final do décimo mês, estamos estabilizando o faturamento em um patamar 50% acima do faturamento obtido ao final do terceiro mês\\\".\"}]},{\"type\":\"paragraph\",\"attrs\":{\"textAlign\":null},\"content\":[{\"type\":\"text\",\"text\":\"Considerando que, na ordenada, o faturamento quinzenal está representado em unidades desconhecidas, porém uniformemente espaçadas, qual dos gráficos é compatível com a descrição do comerciante?\"}]}]},{\"type\":\"options\",\"content\":[{\"type\":\"option\",\"attrs\":{\"letter\":\"A\"},\"content\":[{\"type\":\"paragraph\",\"attrs\":{\"textAlign\":null},\"content\":[{\"type\":\"image\",\"attrs\":{\"id\":\"e454f635-a206-47c7-b5ad-5575b89c4b13\",\"src\":\"data:image/png;base64,\",\"width\":\"151\",\"align\":null}}]}]},{\"type\":\"option\",\"attrs\":{\"letter\":\"B\"},\"content\":[{\"type\":\"paragraph\",\"attrs\":{\"textAlign\":null},\"content\":[{\"type\":\"image\",\"attrs\":{\"id\":\"e2448011-fe7a-4e12-9b05-a42818a231c4\",\"src\":\"data:image/png;base64,\",\"width\":null,\"align\":null}}]}]},{\"type\":\"option\",\"attrs\":{\"letter\":\"C\"},\"content\":[{\"type\":\"paragraph\",\"attrs\":{\"textAlign\":null},\"content\":[{\"type\":\"image\",\"attrs\":{\"id\":\"d7cc21d6-da2d-42fe-a6dc-850a9e131b15\",\"src\":\"data:image/png;base64,\",\"width\":null,\"align\":null}}]}]},{\"type\":\"option\",\"attrs\":{\"letter\":\"D\"},\"content\":[{\"type\":\"paragraph\",\"attrs\":{\"textAlign\":null},\"content\":[{\"type\":\"image\",\"attrs\":{\"id\":\"96d684cc-21c4-401d-a9c7-35c4014a7096\",\"src\":\"data:image/png;base64,\",\"width\":null,\"align\":null}}]}]},{\"type\":\"option\",\"attrs\":{\"letter\":\"E\"},\"content\":[{\"type\":\"paragraph\",\"attrs\":{\"textAlign\":null},\"content\":[{\"type\":\"image\",\"attrs\":{\"id\":\"7877a340-8959-43d5-a0e6-769c9d87d9f9\",\"src\":\"data:image/png;base64,\",\"width\":null,\"align\":null}}]}]}]}]}]}', 'question'),
