('fdbb38ce-4b9b-4e69-8e4b-3914753f588f', '2026-02-19 12:06:10', '2026-02-21 14:13:46', 'Matemática', 'Geometria Plana', 'Múltipla Escolha', 'Difícil', 'A', NULL, NULL, 'concurso', 'FUVEST', 'FUVEST', 2019, NULL, NULL, '54', '{\"id\":\"100387007767191405258\",\"name\":\"Marcos Paulo\"}', '100387007767191405258', '[\"rotação\",\"arco de circunferência\",\"trajetória\"]', '{\"schemaVersion\":1,\"id\":\"fdbb38ce-4b9b-4e69-8e4b-3914753f588f\",\"createdAt\":\"2026-02-19T12:05:06.778Z\",\"updatedAt\":\"2026-02-20T15:45:08.282Z\",\"tipo\":\"Múltipla Escolha\",\"dificuldade\":\"Difícil\",\"tags\":[\"rotação\",\"arco de circunferência\",\"trajetória\"],\"gabarito\":{\"kind\":\"mcq\",\"correct\":\"A\",\"rubric\":null},\"source\":{\"kind\":\"concurso\",\"concurso\":\"FUVEST\",\"banca\":\"FUVEST\",\"ano\":2019,\"numero\":\"54\"},\"author\":{\"id\":\"100387007767191405258\",\"name\":\"Marcos Paulo\"},\"disciplina\":\"Matemática\",\"assunto\":\"Geometria Plana\"}', '{\"type\":\"doc\",\"content\":[{\"type\":\"question\",\"attrs\":{\"tipo\":null},\"content\":[{\"type\":\"statement\",\"content\":[{\"type\":\"paragraph\",\"attrs\":{\"textAlign\":null},\"content\":[{\"type\":\"text\",\"text\":\"Um triângulo retângulo com vértices denominados \"},{\"type\":\"math_inline\",\"attrs\":{\"latex\":\"A\"}},{\"type\":\"text\",\"text\":\", \"},{\"type\":\"math_inline\",\"attrs\":{\"latex\":\"B\"}},{\"type\":\"text\",\"text\":\" e \"},{\"type\":\"math_inline\",\"attrs\":{\"latex\":\"C\"}},{\"type\":\"text\",\"text\":\" apoia-se sobre uma linha horizontal, que corresponde ao solo, e gira sem escorregar no sentido horário. Isto é, se a posição inicial é aquela mostrada na figura, o movimento começa com uma rotação em torno do vértice \"},{\"type\":\"math_inline\",\"attrs\":{\"latex\":\"C\"}},{\"type\":\"text\",\"text\":\" até o vértice \"},{\"type\":\"math_inline\",\"attrs\":{\"latex\":\"A\"}},{\"type\":\"text\",\"text\":\" tocar o solo, após o que passa a ser uma rotação em torno de \"},{\"type\"