('01d75e1c4b390bb6645a142c6aec5cd5', 'cb3d7ef8-4560-48e0-884a-092b2e242b08', '2026-01-30 23:52:31', '2026-01-30 23:52:31', NULL, '[]', '{\"schemaVersion\":1,\"id\":\"cb3d7ef8-4560-48e0-884a-092b2e242b08\",\"createdAt\":\"2026-01-30T23:47:50.669Z\",\"updatedAt\":\"2026-01-30T23:52:27.216Z\",\"tipo\":\"Múltipla Escolha\",\"dificuldade\":\"Média\",\"tags\":[],\"gabarito\":{\"kind\":\"mcq\",\"correct\":\"D\"},\"source\":{\"kind\":\"original\"},\"disciplina\":\"Matemática\",\"assunto\":\"Geometria Analítica\"}', '{\"type\":\"doc\",\"content\":[{\"type\":\"question\",\"content\":[{\"type\":\"statement\",\"content\":[{\"type\":\"paragraph\",\"content\":[{\"type\":\"text\",\"text\":\"Uma câmara dos sussurros é um espaço em que, se duas pessoas estão nas posições especificadas como foco, elas podem falar entre si, mesmo sussurrando, a uma distância considerável. Isso porque os painéis colocados atrás delas são partes de uma mesma elipse cujos focos são as posições das cabeças das pessoas.\"}]},{\"type\":\"paragraph\",\"content\":[{\"type\":\"text\",\"text\":\"Na câmara de sussurros representada na figura a seguir, a distância entre as duas pessoas é de 20m e a distância de cada pessoa até um vértice da elipse é 2m.\"}]},{\"type\":\"paragraph\",\"content\":[{\"type\":\"image\",\"attrs\":{\"src\":\"https://mpfaraujo.com.br/guardafiguras/uploads/8a72e6f96ba2fac443d61674c085c8d8c2693320d5f6ce8c6e4c689697d61144.jpg\",\"width\":\"302\"}},{\"type\":\"text\",\"text\":\"  \"}]},{\"type\":\"paragraph\",\"content\":[{\"type\":\"text\",\"text\":\"A equação da elipse que contém os painéis da câmara representada no sistema de eixos proposto na figura é\"}]}]},{\"type\":\"options\",\"content\":[{\"type\":\"option\",\"attrs\":{\"letter\":\"A\"},\"content\":[{\"type\":\"paragraph\",\"content\":[{\"type\":\"math_inline\",\"attrs\":{\"latex\":\"\\\\frac{x^2}{100}+\\\\frac{y^2}{44}=1\"}}]}]},{\"type\":\"option\",\"attrs\":{\"letter\":\"B\"},\"content\":[{\"type\":\"paragraph\",\"content\":[{\"type\":\"math_inline\",\"attrs\":{\"latex\":\"\\\\frac{x^2}{44}+\\\\frac{y^2}{100}=1\"}}]}]},{\"type\":\"option\",\"attrs\":{\"letter\":\"C\"},\"content\":[{\"type\":\"paragraph\",\"content\":[{\"type\":\"math_inline\",\"attrs\":{\"latex\":\"\\\\frac{x^2}{44}+\\\\frac{y^2}{144}=1\"}}]}]},{\"type\":\"option\",\"attrs\":{\"letter\":\"D\"},\"content\":[{\"type\":\"paragraph\",\"content\":[{\"type\":\"math_inline\",\"attrs\":{\"latex\":\"\\\\frac{x^2}{144}+\\\\frac{y^2}{44}=1\"}}]}]},{\"type\":\"option\",\"attrs\":{\"letter\":\"E\"},\"content\":[{\"type\":\"paragraph\",\"content\":[{\"type\":\"math_inline\",\"attrs\":{\"latex\":\"\\\\frac{x^2}{4}+\\\\frac{y^2}{44}=1\"}},{\"type\":\"text\",\"text\":\"  \"}]}]}]}]}]}', NULL),
('02fc1c756c7ec2fa7d6cd02a91e36cfa', '7c39c235-0b2f-41a4-b24c-45a02f85f393', '2026-02-06 13:49:49', '2026-02-06 13:49:49', NULL, '[]', '{\"schemaVersion\":1,\"id\":\"7c39c235-0b2f-41a4-b24c-45a02f85f393\",\"createdAt\":\"2026-02-05T16:51:21.035Z\",\"updatedAt\":\"2026-02-06T13:49:34.210Z\",\"tipo\":\"Múltipla Escolha\",\"dificuldade\":\"Média\",\"tags\":[],\"gabarito\":{\"kind\":\"mcq\",\"correct\":\"B\",\"rubric\":null},\"source\":{\"kind\":\"concurso\",\"concurso\":\"UERJ\",\"banca\":\"UERJ\",\"ano\":2025},\"disciplina\":\"Matemática\",\"assunto\":\"Sequências\"}', '{\"type\":\"doc\",\"content\":[{\"type\":\"question\",\"content\":[{\"type\":\"statement\",\"content\":[{\"type\":\"paragraph\",\"attrs\":{\"textAlign\":null},\"content\":[{\"type\":\"text\",\"text\":\"Admitindo um retângulo cujos lados medem a e b, sendo a < b, é possível formar uma sequência ilimitada de retângulos da seguinte forma: a partir do primeiro, cada novo retângulo é construído acrescentando-se um quadrado cujo lado é igual ao maior lado do retângulo anterior, conforme ilustrado a seguir.\"}]},{\"type\":\"paragraph\",\"attrs\":{\"textAlign\":null},\"content\":[{\"type\":\"image\",\"attrs\":{\"id\":\"3a38b028-912c-4596-9e62-5badebe8f35c\",\"src\":\"https://mpfaraujo.com.br/guardafiguras/uploads/f1cc52ea2ccedc4f891d61842424b5cf54ed6348a785f807b59be2c2355d64f8.png\",\"width\":302,\"align\":null}}]},{\"type\":\"paragraph\",\"attrs\":{\"textAlign\":null},\"content\":[{\"type\":\"text\",\"text\":\"A figura IV destaca a linha poligonal P\"},{\"type\":\"text\",\"marks\":[{\"type\":\"subscript\"}],\"text\":\"1\"},{\"type\":\"text\",\"text\":\" P\"},{\"type\":\"text\",\"marks\":[{\"type\":\"subscript\"}],\"text\":\"2\"},{\"type\":\"text\",\"text\":\" P\"},{\"type\":\"text\",\"marks\":[{\"type\":\"subscript\"}],\"text\":\"3\"},{\"type\":\"text\",\"text\":\" P\"},{\"type\":\"text\",\"marks\":[{\"type\":\"subscript\"}],\"text\":\"4\"},{\"type\":\"text\",\"text\":\" P\"},{\"type\":\"text\",\"marks\":[{\"