('27324ade5ce2d330f318e2ee8847dc2c', '6dec8d9c-2236-4d83-b37e-af73eb6df6e2', '2026-02-06 13:51:18', '2026-02-06 13:51:18', NULL, '[]', '{\"schemaVersion\":1,\"id\":\"6dec8d9c-2236-4d83-b37e-af73eb6df6e2\",\"createdAt\":\"2026-02-04T19:45:09.969Z\",\"updatedAt\":\"2026-02-06T13:51:03.026Z\",\"tipo\":\"Múltipla Escolha\",\"dificuldade\":\"Média\",\"tags\":[],\"gabarito\":{\"kind\":\"mcq\",\"correct\":\"C\",\"rubric\":null},\"source\":{\"kind\":\"concurso\",\"ano\":2025,\"banca\":\"INEP\",\"cargo\":\"Amarela\"},\"disciplina\":\"Matemática\",\"assunto\":\"Geometria Plana\"}', '{\"type\":\"doc\",\"content\":[{\"type\":\"question\",\"content\":[{\"type\":\"statement\",\"content\":[{\"type\":\"paragraph\",\"attrs\":{\"textAlign\":\"justify\"},\"content\":[{\"type\":\"text\",\"text\":\"No entorno de uma lagoa circular, cujo raio mede 1 km, há um uma ciclovia. Devido aos frequentes roubos de bicicleta, a prefeitura planeja alocar policiais em posições estratégicas para patrulhar essa ciclovia, de forma a torná-la totalmente protegida. Um ponto da ciclovia é considerado protegido se houver pelo menos um policial a, no máximo, 200 m de distância daquele ponto, posicionado sobre a ciclovia. A figura ilustra um ponto P sobre a ciclovia, que estará protegido se houver pelo menos um policial posicionado sobre a região de cor cinza escuro.\"}]},{\"type\":\"paragraph\",\"attrs\":{\"textAlign\":\"justify\"},\"content\":[{\"type\":\"text\",\"text\":\"Desconsidere a largura da pista da ciclovia e utilize 3 como aproximação para p.\"}]},{\"type\":\"paragraph\",\"attrs\":{\"textAlign\":\"justify\"},\"content\":[{\"type\":\"image\",\"attrs\":{\"id\":\"15195e5c-58bd-456a-85dc-1adfa141435f\",\"src\":\"https://mpfaraujo.com.br/guardafiguras/uploads/9205e3c2817861df179630e7573fed748ccbff4d6dafcd4bce4e90252437bb7f.png\",\"width\":213,\"align\":\"center\"}},{\"type\":\"text\",\"text\":\"Nessas condições, a quantidade mínima necessária de policiais a serem alocados ao longo dessa ciclovia para torná-la protegida é\"}]}]},{\"type\":\"options\",\"content\":[{\"type\":\"option\",\"attrs\":{\"letter\":\"A\"},\"content\":[{\"type\":\"paragraph\",\"attrs\":{\"textAlign\":null},\"content\":[{\"type\":\"text\",\"text\":\"4.\"}]}]},{\"type\":\"option\",\"attrs\":{\"letter\":\"B\"},\"content\":[{\"type\":\"paragraph\",\"attrs\":{\"textAlign\":null},\"content\":[{\"type\":\"text\",\"text\":\"8.\"}]}]},{\"type\":\"option\",\"attrs\":{\"letter\":\"C\"},\"content\":[{\"type\":\"paragraph\",\"attrs\":{\"textAlign\":null},\"content\":[{\"type\":\"text\",\"text\":\"15.\"}]}]},{\"type\":\"option\",\"attrs\":{\"letter\":\"D\"},\"content\":[{\"type\":\"paragraph\",\"attrs\":{\"textAlign\":null},\"content\":[{\"type\":\"text\",\"text\":\"30.\"}]}]},{\"type\":\"option\",\"attrs\":{\"letter\":\"E\"},\"content\":[{\"type\":\"paragraph\",\"attrs\":{\"textAlign\":null},\"content\":[{\"type\":\"text\",\"text\":\"60.\"}]}]}]}]}]}', NULL),
('2d3ed550f02b9a18e6e484b847d062ca', '5acb2baa-cc9f-458f-bcaf-515fa6be33e4', '2026-02-04 12:11:00', '2026-02-04 12:11:00', NULL, '[]', '{\"schemaVersion\":1,\"id\":\"5acb2baa-cc9f-458f-bcaf-515fa6be33e4\",\"createdAt\":\"2026-02-04T10:46:45.284Z\",\"updatedAt\":\"2026-02-04T12:10:55.224Z\",\"tipo\":\"Múltipla Escolha\",\"dificuldade\":\"Média\",\"tags\":[],\"source\":{\"kind\":\"original\"},\"disciplina\":\"Matemática\",\"assunto\":\"Porcentagem\"}', '{\"type\":\"doc\",\"content\":[{\"type\":\"set_questions\",\"content\":[{\"type\":\"base_text\",\"content\":[{\"type\":\"paragraph\",\"attrs\":{\"textAlign\":null},\"content\":[{\"type\":\"text\",\"text\":\"Antes de iniciar uma campanha publicitaria, um banco fez uma pesquisa entre 800 de seus clientes sobre sua intenção de adesão aos seus dois novos produtos. Dos clientes entrevistados, 240 mostraram-se interessados no primeiro produto, 400 mostraram-se interessados no segundo produto e alguns estavam interessados em ambos os produtos. A campanha publicitária só será iniciada caso pelo menos 70% dos entrevistados mostrarem-se interessados em pelo menos um dos produtos.\"}]}]},{\"type\":\"question_item\",\"attrs\":{\"answerKey\":{\"kind\":\"mcq\",\"correct\":\"B\"}},\"content\":[{\"type\":\"statement\",\"content\":[{\"type\":\"paragraph\",\"attrs\":{\"textAlign\":null},\"content\":[{\"type\":\"text\",\"text\":\"Qual a porcentagem máxima do total de clientes pode mostrar-se interessados em ambos os produtos para que a campanha publicitária seja iniciada?\"}]}]},{\"type\":\"options\",\"content\":[{\"type\":\"option\",\"attrs\":{\"letter\":\"A\"},\"content\":[{\"type\":\"paragraph\",\"attrs\":{\"textAlign\":null},\"content\":[{\"type\":\"text\",\"text\":\"10%\"}]}]},{\"type\":\"option\",\"attrs\":{\"letter\":\"B\"},\"content\":[{\"type\":\"paragraph\",\"attrs\":{\"textAlign\":null},\"content\":[{\"type\":\"text\",\"text\":\"15%\"}]}]},{\"type\":\"option\",\"attrs\":{\"letter\":\"C\"},\"content\":[{\"type\":\"paragraph\",\"attrs\":{\"textAlign\":null},\"content\":[{\"type\":\"text\",\"text\":\"20%\"}]}]},{\"type\":\"option\",\"attrs\":{\"letter\":\"D\"},\"content\":[{\"type\":\"paragraph\",\"attrs\":{\"textAlign\":null},\"content\":[{\"type\":\"text\",\"text\":\"25%\"}]}]},{\"type\":\"option\",\"attrs\":{\"letter\":\"E\"},\"content\":[{\"type\":\"paragraph\",\"attrs\":{\"textAlign\":null},\"content\":[{\"type\":\"text\",\"text\":\"30%\"}]}]}]}]},{\"type\":\"question_item\",\"attrs\":{\"answerKey\":{\"kind\":\"mcq\",\"correct\":\"E\"}},\"content\":[{\"type\":\"statement\",\"content\":[{\"type\":\"paragraph\",\"attrs\":{\"textAlign\":null},\"content\":[{\"type\":\"text\",\"text\":\"O número de clientes interessados em ambos os produtos não pode ser igual a \"}]}]},{\"type\":\"options\",\"content\":[{\"type\":\"option\",\"attrs\":{\"letter\":\"A\"},\"content\":[{\"type\":\"paragraph\",\"attrs\":{\"textAlign\":null},\"content\":[{\"type\":\"text\",\"text\":\"75\"}]}]},{\"type\":\"option\",\"attrs\":{\"letter\":\"B\"},\"content\":[{\"type\":\"paragraph\",\"attrs\":{\"textAlign\":null},\"content\":[{\"type\":\"text\",\"text\":\"78\"}]}]},{\"type\":\"option\",\"attrs\":{\"letter\":\"C\"},\"content\":[{\"type\":\"paragraph\",\"attrs\":{\"textAlign\":null},\"content\":[{\"type\":\"text\",\"text\":\"79\"}]}]},{\"type\":\"option\",\"attrs\":{\"letter\":\"D\"},\"content\":[{\"type\":\"paragraph\",\"attrs\":{\"textAlign\":null},\"content\":[{\"type\":\"text\",\"text\":\"80\"}]}]},{\"type\":\"option\",\"attrs\":{\"letter\":\"E\"},\"content\":[{\"type\":\"paragraph\",\"attrs\":{\"textAlign\":null},\"content\":[{\"type\":\"text\",\"text\":\"82\"}]}]}]}]}]}]}', NULL),
('2d9ccc1f19fdffb503a713007e48835b', '0052c445-0cee-4fc7-b34a-c1de32dca311', '2026-02-05 18:30:23', '2026-02-05 18:30:23', NULL, '[]', '{\"schemaVersion\":1,\"id\":\"0052c445-0cee-4fc7-b34a-c1de32dca311\",\"createdAt\":\"2026-02-05T18:17:11.763Z\",\"updatedAt\":\"2026-02-05T18:30:15.278Z\",\"tipo\":\"Múltipla Escolha\",\"dificuldade\":\"Média\",\"tags\":[],\"gabarito\":{\"kind\":\"mcq\",\"correct\":\"C\",\"rubric\":null},\"source\":{\"kind\":\"concurso\",\"concurso\":\"UERJ\",\"banca\":\"UERJ\",\"ano\":2025},\"disciplina\":\"Matemática\",\"assunto\":\"Geometria Plana\"}', '{\"type\":\"doc\",\"content\":[{\"type\":\"question\",\"content\":[{\"type\":\"statement\",\"content\":[{\"type\":\"paragraph\",\"attrs\":{\"textAlign\":null},\"content\":[{\"type\":\"text\",\"text\":\"No triângulo equilátero ABC, H corresponde ao ponto médio do lado AC. Desse modo, a área do triângulo ABH é igual à metade da área de ABC.\"}]},{\"type\":\"paragraph\",\"attrs\":{\"textAlign\":null},\"content\":[{\"type\":\"image\",\"attrs\":{\"src\":\"https://mpfaraujo.com.br/guardafiguras/uploads/12fd020bcdf366c7e80da5dd4ec1313f9916eff1206e0bab0847d48f209b5644.png\",\"width\":\"151\",\"align\":\"center\"}},{\"type\":\"text\",\"text\":\"Sendo W o perímetro do triângulo ABH e Y o perímetro do triângulo ABC, uma relação correta entre W e Y é:\"}]}]},{\"type\":\"options\",\"content\":[{\"type\":\"option\",\"attrs\":{\"letter\":\"A\"},\"content\":[{\"type\":\"paragraph\",\"attrs\":{\"textAlign\":null},\"content\":[{\"type\":\"math_inline\",\"attrs\":{\"latex\":\"0 < W < \\\\frac{Y}{2}\"}}]}]},{\"type\":\"option\",\"attrs\":{\"letter\":\"B\"},\"content\":[{\"type\":\"paragraph\",\"attrs\":{\"textAlign\":null},\"content\":[{\"type\":\"math_inline\",\"attrs\":{\"latex\":\"W = \\\\frac{Y}{2}\"}}]}]},{\"type\":\"option\",\"attrs\":{\"letter\":\"C\"},\"content\":[{\"type\":\"paragraph\",\"attrs\":{\"textAlign\":null},\"content\":[{\"type\":\"math_inline\",\"attrs\":{\"latex\":\"\\\\frac{Y}{2} < W < Y\"}}]}]},{\"type\":\"option\",\"attrs\":{\"letter\":\"D\"},\"content\":[{\"type\":\"paragraph\",\"attrs\":{\"textAlign\":null},\"content\":[{\"type\":\"text\",\"text\":\"W = Y\"}]}]},{\"type\":\"option\",\"attrs\":{\"letter\":\"E\"},\"content\":[{\"type\":\"paragraph\",\"attrs\":{\"textAlign\":null}}]}]}]}]}', NULL),
