('31fafcd7bbc03ddd4f712986536e9f71', '1a03d2ef-a6d8-4829-af68-2401b0fedbf1', '2026-02-09 14:57:25', '2026-02-09 14:57:25', NULL, '[]', '{\"schemaVersion\":1,\"id\":\"1a03d2ef-a6d8-4829-af68-2401b0fedbf1\",\"createdAt\":\"2026-02-09T14:47:11.159Z\",\"updatedAt\":\"2026-02-09T14:57:21.760Z\",\"tipo\":\"Múltipla Escolha\",\"dificuldade\":\"Média\",\"tags\":[],\"gabarito\":{\"kind\":\"mcq\",\"correct\":\"B\",\"rubric\":null},\"source\":{\"kind\":\"original\"},\"disciplina\":\"Matemática\",\"assunto\":\"Função Quadrática\"}', '{\"type\":\"doc\",\"content\":[{\"type\":\"question\",\"attrs\":{\"tipo\":null},\"content\":[{\"type\":\"statement\",\"content\":[{\"type\":\"paragraph\",\"attrs\":{\"textAlign\":null},\"content\":[{\"type\":\"text\",\"text\":\"Um curral retangular será construído aproveitando-se um muro pré-existente no terreno, por medida de economia. Para cercar os outros três lados, serão utilizados 600 metros de tela de arame. Para que a área do curral seja a maior possível, a razão entre as suas menor e maior dimensões será:\"}]}]},{\"type\":\"options\",\"content\":[{\"type\":\"option\",\"attrs\":{\"letter\":\"A\"},\"content\":[{\"type\":\"paragraph\",\"attrs\":{\"textAlign\":null},\"content\":[{\"type\":\"text\",\"text\":\"0,25\"}]}]},{\"type\":\"option\",\"attrs\":{\"letter\":\"B\"},\"content\":[{\"type\":\"paragraph\",\"attrs\":{\"textAlign\":null},\"content\":[{\"type\":\"text\",\"text\":\"0,50\"}]}]},{\"type\":\"option\",\"attrs\":{\"letter\":\"C\"},\"content\":[{\"type\":\"paragraph\",\"attrs\":{\"textAlign\":null},\"content\":[{\"type\":\"text\",\"text\":\"0,75\"}]}]},{\"type\":\"option\",\"attrs\":{\"letter\":\"D\"},\"content\":[{\"type\":\"paragraph\",\"attrs\":{\"textAlign\":null},\"content\":[{\"type\":\"text\",\"text\":\"1,00\"}]}]},{\"type\":\"option\",\"attrs\":{\"letter\":\"E\"},\"content\":[{\"type\":\"paragraph\",\"attrs\":{\"textAlign\":null},\"content\":[{\"type\":\"text\",\"text\":\"1,25\"}]}]}]}]}]}', NULL),
('35165ed354ca202de28d4f12bb1dd492', '5fe4ff6c-c04d-40ea-be17-cf3de6100dbb', '2026-02-06 13:50:25', '2026-02-06 13:50:25', NULL, '[]', '{\"schemaVersion\":1,\"id\":\"5fe4ff6c-c04d-40ea-be17-cf3de6100dbb\",\"createdAt\":\"2026-02-05T15:52:50.125Z\",\"updatedAt\":\"2026-02-06T13:50:10.546Z\",\"tipo\":\"Múltipla Escolha\",\"dificuldade\":\"Média\",\"tags\":[],\"gabarito\":{\"kind\":\"mcq\",\"correct\":\"B\",\"rubric\":null},\"source\":{\"kind\":\"concurso\",\"concurso\":\"UERJ\",\"banca\":\"UERJ\",\"ano\":2025},\"disciplina\":\"Matemática\",\"assunto\":\"Geometria Plana\"}', '{\"type\":\"doc\",\"content\":[{\"type\":\"question\",\"content\":[{\"type\":\"statement\",\"content\":[{\"type\":\"paragraph\",\"attrs\":{\"textAlign\":\"justify\"},\"content\":[{\"type\":\"text\",\"text\":\"Considere na imagem abaixo:\"}]},{\"type\":\"bullet_list\",\"content\":[{\"type\":\"list_item\",\"content\":[{\"type\":\"paragraph\",\"attrs\":{\"textAlign\":\"justify\"},\"content\":[{\"type\":\"text\",\"text\":\"os quadrados ACFG e ABHI, cujas áreas medem, respectivamente, S\"},{\"type\":\"text\",\"marks\":[{\"type\":\"subscript\"}],\"text\":\"1\"},{\"type\":\"text\",\"text\":\" \"}]},{\"type\":\"paragraph\",\"attrs\":{\"textAlign\":\"justify\"},\"content\":[{\"type\":\"text\",\"text\":\"e S\"},{\"type\":\"text\",\"marks\":[{\"type\":\"subscript\"}],\"text\":\"2\"},{\"type\":\"text\",\"text\":\";\"}]}]},{\"type\":\"list_item\",\"content\":[{\"type\":\"paragraph\",\"attrs\":{\"textAlign\":\"justify\"},\"content\":[{\"type\":\"text\",\"text\":\"o triângulo retângulo ABC;\"}]}]},{\"type\":\"list_item\",\"content\":[{\"type\":\"paragraph\",\"attrs\":{\"textAlign\":\"justify\"},\"content\":[{\"type\":\"text\",\"text\":\"o trapézio retângulo BCDE, construído sobre a hipotenusa BC, que contém o ponto X.\"}]}]}]},{\"type\":\"paragraph\",\"attrs\":{\"textAlign\":\"justify\"},\"content\":[{\"type\":\"image\",\"attrs\":{\"id\":\"fbb12df7-ba36-4c50-b1eb-ad9fb0e5b5ca\",\"src\":\"https://mpfaraujo.com.br/guardafiguras/uploads/b1a4bb6a9342513e3a5f5cfc2b0aac4f70a18123619d184df14ac0e47d57b1a1.png\",\"width\":\"151\",\"align\":\"center\"}}]},{\"type\":\"paragraph\",\"attrs\":{\"textAlign\":\"justify\"},\"content\":[{\"type\":\"text\",\"text\":\"E Sabendo que CD = CX e BE = BX, a área do trapézio BCDE é igual a:\"}]}]},{\"type\":\"options\",\"content\":[{\"type\":\"option\",\"attrs\":{\"letter\":\"A\"},\"content\":[{\"type\":\"paragraph\",\"attrs\":{\"textAlign\":\"justify\"},\"content\":[{\"type\":\"math_inline\",\"attrs\":{\"latex\":\"\\\\dfrac{S_1+S_2}{2}\"}}]}]},{\"type\":\"option\",\"attrs\":{\"letter\":\"B\"},\"content\":[{\"type\":\"paragraph\",\"attrs\":{\"textAlign\":\"justify\"},\"content\":[{\"type\":\"math_inline\",\"attrs\":{\"latex\":\"\\\\dfrac{S_1+S_2}{3}\"}}]}]},{\"type\":\"option\",\"attrs\":{\"letter\":\"C\"},\"content\":[{\"type\":\"paragraph\",\"attrs\":{\"textAlign\":\"justify\"},\"content\":[{\"type\":\"math_inline\",\"attrs\":{\"latex\":\"\\\\sqrt{S_1\\\\cdot S_2}\"}}]}]},{\"type\":\"option\",\"attrs\":{\"letter\":\"D\"},\"content\":[{\"type\":\"paragraph\",\"attrs\":{\"textAlign\":\"justify\"},\"content\":[{\"type\":\"math_inline\",\"attrs\":{\"latex\":\"\\\\sqrt{(S_1)^2+(S_2)^2}\"}}]}]}]}]}]}', NULL),
('3521ed15a4d17a29a2f1d40592e6eebc', '17697546-c51e-4f22-9bbf-c0e2c4895260', '2026-02-10 22:06:18', '2026-02-10 22:06:18', NULL, '[\"problema\"]', '{\"schemaVersion\":1,\"id\":\"17697546-c51e-4f22-9bbf-c0e2c4895260\",\"createdAt\":\"2026-02-03T21:59:41.067Z\",\"updatedAt\":\"2026-02-10T22:06:07.803Z\",\"tipo\":\"Múltipla Escolha\",\"dificuldade\":\"Média\",\"tags\":[\"problema\"],\"source\":{\"kind\":\"original\"},\"disciplina\":\"Português\",\"assunto\":\"Interporetação de texto\"}', '{\"type\":\"doc\",\"content\":[{\"type\":\"set_questions\",\"attrs\":{\"mode\":null},\"content\":[{\"type\":\"base_text\",\"content\":[{\"type\":\"paragraph\",\"attrs\":{\"textAlign\":\"center\"},\"content\":[{\"type\":\"text\",\"text\":\"Maria José \"}]},{\"type\":\"paragraph\",\"attrs\":{\"textAlign\":\"right\"},\"content\":[{\"type\":\"text\",\"text\":\"Paulo Mendes Campos \"}]},{\"type\":\"paragraph\",\"attrs\":{\"textAlign\":null},\"content\":[{\"type\":\"text\",\"text\":\"Faz um ano que Maria José morreu. Era meiga quase sempre, violenta quando necessário. Eu era menino e apanhava de um companheiro maior, quando ela me gritou da sacada se eu não via a pedra que marcava o gol. Dei uma pedrada no outro e acabei com a briga por milagre.\"}]},{\"type\":\"paragraph\",\"attrs\":{\"textAlign\":null},\"content\":[{\"type\":\"text\",\"text\":\"Visitava os miseráveis, internava indigentes enfermos, devotava-se ao alívio de misérias físicas e morais do próximo, estudava o mistério teológico, exigia sempre o mais difícil de si mesma, comungava todos os dias, ingressou na Ordem Terceira de São Francisco. Mas nunca deixou de ter na gaveta o revólver que havia recebido, menina-e-moça, das mãos do pai, e que empunhou no quintal noturno, perse guindo um ladrão, para espanto de meus cinco anos.\"}]},{\"type\":\"paragraph\",\"attrs\":{\"textAlign\":null},\"content\":[{\"type\":\"text\",\"text\":\"Já perto dos setenta anos, ela explicava para um amigo meu que tinha chegado à humildade da velhice; já não se importava com quem tentasse ofendê-la, mas conservava o revólver para a defesa dos filhos e dos netos.\"}]},{\"type\":\"paragraph\",\"attrs\":{\"textAlign\":null},\"content\":[{\"type\":\"text\",\"text\":\"Tratou-me com a dureza e o carinho que mere ciam a rebeldia e o verdor da minha meninice. Ensi nou-me a ler as primeiras sentenças; me falava do Cura d’Ars e nos dois Franciscos, o de Sales e o de Assis; apresentou-me aos contos de Edgar Poe e aos poemas de Baudelaire; dizia-me sorrindo versos de Antônio Nobre que havia decorado quando menina; discutia comigo as ideias finais de Tolstoi; escutava maternalmente meus contos toscos. Quando me desgarrei nos primeiros envolvimentos adolescentes, Maria José, com irônico afeto, me repetia a advertência de Drummond: “Paulo, sossegue, o amor é isso que você está vendo: hoje beija, amanhã não beija, depois de amanhã é domingo e segunda-feira ninguém sabe o que será”.\"}]},{\"type\":\"paragraph\",\"attrs\":{\"textAlign\":null},\"content\":[{\"type\":\"text\",\"text\":\"Logo que me fiz homenzinho, deixou a dureza e se fez minha amiga: nada me perguntava, adivinhava tudo.\"}]},{\"type\":\"paragraph\",\"attrs\":{\"textAlign\":null},\"content\":[{\"type\":\"text\",\"text\":\"Terna e firme, nunca lhe vi a fraqueza da pieguice. Com o gosto espontâneo da qualidade das coisas, renunciou às vaidades mais singelas. Sensível, alegre, aprendeu a encarar o sofrimento de olhos lúcidos. Fiel à disciplina religiosa, compreendia celestialmente as almas que perdiam o rumo. Fé, Esperança e Caridade eram para ela a flecha e o alvo das criaturas.\"}]},{\"type\":\"paragraph\",\"attrs\":{\"textAlign\":null},\"content\":[{\"type\":\"text\",\"text\":\"Tornara-se tão íntima da substância terrestre – a dor – que se fazia difícil para o médico saber o que sentia; acabava dizendo que doía um pouco, por delicadeza.\"}]},{\"type\":\"paragraph\",\"attrs\":{\"textAlign\":null},\"content\":[{\"type\":\"text\",\"text\":\"Capaz de longos jejuns e abstinências, já no final da vida, podia acompanhar um casal amigo a Copacabana, passar do bar da moda ao restaurante diferente, beber dois cafés ou três uísques em santa serenidade e aceitar com alegria o prato exótico.\"}]},{\"type\":\"paragraph\",\"attrs\":{\"textAlign\":null},\"content\":[{\"type\":\"text\",\"text\":\"Gostava das pessoas erradas, consumidas de paixão, admirava São Paulo e Santo Agostinho, acre ditava que era preciso se fazer violência para entrar no reino celeste.\"}]},{\"type\":\"paragraph\",\"attrs\":{\"textAlign\":null},\"content\":[{\"type\":\"text\",\"text\":\"Poucas horas antes de morrer, pediu um conhaque e sorriu, destemida e doce, como quem vai partir para o céu. Santificara-se. Deus era o dia e a noite de seu coração, o Pai, a piedade, o fogo do espírito. Per di quem me amava e perdoava, quem me encomendava à compaixão do Criador e me defendia contra o mundo de revólver na mão.\"}]},{\"type\":\"paragraph\",\"attrs\":{\"textAlign\":\"right\"},\"content\":[{\"type\":\"text\",\"text\":\"Disponível em: https://cronicabrasileira.org.br/cronicas/7173/ma ria-jose. Acesso em: 05 fev. 2022.\"}]}]},{\"type\":\"question_item\",\"attrs\":{\"answerKey\":{\"kind\":\"mcq\",\"correct\":\"A\"}},\"content\":[{\"type\":\"statement\",\"content\":[{\"type\":\"paragraph\",\"attrs\":{\"textAlign\":null},\"content\":[{\"type\":\"text\",\"text\":\"No texto, o narrador apresenta Maria José ao leitor, des crevendo-a a partir de aspectos subjetivos, como em:\"}]}]},{\"type\":\"options\",\"content\":[{\"type\":\"option\",\"attrs\":{\"letter\":\"A\"},\"content\":[{\"type\":\"paragraph\",\"attrs\":{\"textAlign\":null},\"content\":[{\"type\":\"text\",\"text\":\"“Faz um ano que Maria José morreu.” (parágrafo 1)\"}]}]},{\"type\":\"option\",\"attrs\":{\"letter\":\"B\"},\"content\":[{\"type\":\"paragraph\",\"attrs\":{\"textAlign\":null},\"content\":[{\"type\":\"text\",\"text\":\"\\\"Visitava os miseráveis, internava indigentes enfermos” (parágrafo 2)\"}]}]},{\"type\":\"option\",\"attrs\":{\"letter\":\"C\"},\"content\":[{\"type\":\"paragraph\",\"attrs\":{\"textAlign\":null},\"content\":[{\"type\":\"text\",\"text\":\"“comungava todos os dias” (parágrafo 2)\"}]}]},{\"type\":\"option\",\"attrs\":{\"letter\":\"D\"},\"content\":[{\"type\":\"paragraph\",\"attrs\":{\"textAlign\":null},\"content\":[{\"type\":\"text\",\"text\":\"\\\"apresentou-me aos contos de Edgar Poe e aos poemas de Baudelaire” (parágrafo 4)\"}]}]},{\"type\":\"option\",\"attrs\":{\"letter\":\"E\"},\"content\":[{\"type\":\"paragraph\",\"attrs\":{\"textAlign\":null},\"content\":[{\"type\":\"text\",\"text\":\"“Terna e firme, nunca lhe vi a fraqueza da pieguice.” (parágrafo 6)\"}]}]}]}]},{\"type\":\"question_item\",\"attrs\":{\"answerKey\":{\"kind\":\"mcq\",\"correct\":\"D\"}},\"content\":[{\"type\":\"statement\",\"content\":[{\"type\":\"paragraph\",\"attrs\":{\"textAlign\":null},\"content\":[{\"type\":\"text\",\"text\":\"De acordo com o narrador, Maria José “Era meiga quase sempre, violenta quando necessário” (parágrafo 1)\"}]},{\"type\":\"paragraph\",\"attrs\":{\"textAlign\":null},\"content\":[{\"type\":\"text\",\"text\":\"Essa violência a que o narrador se refere pode ser com provada no trecho:\"}]}]},{\"type\":\"options\",\"content\":[{\"type\":\"option\",\"attrs\":{\"letter\":\"A\"},\"content\":[{\"type\":\"paragraph\",\"attrs\":{\"textAlign\":null},\"content\":[{\"type\":\"text\",\"text\":\"“ela me gritou da sacada se eu não via a pedra que mar cava o gol. Dei uma pedrada no outro” (parágrafo 1)\"}]}]},{\"type\":\"option\",\"attrs\":{\"letter\":\"B\"},\"content\":[{\"type\":\"paragraph\",\"attrs\":{\"textAlign\":null},\"content\":[{\"type\":\"text\",\"text\":\"\\\"Tratou-me com a dureza e o carinho que mereciam a rebeldia e o verdor da minha meninice.” (parágrafo 4)\"}]}]},{\"type\":\"option\",\"attrs\":{\"letter\":\"C\"},\"content\":[{\"type\":\"paragraph\",\"attrs\":{\"textAlign\":null},\"content\":[{\"type\":\"text\",\"text\":\"“Fé, Esperança e Caridade eram para ela a flecha e o alvo das criaturas.” (parágrafo 6)\"}]}]},{\"type\":\"option\",\"attrs\":{\"letter\":\"D\"},\"content\":[{\"type\":\"paragraph\",\"attrs\":{\"textAlign\":null},\"content\":[{\"type\":\"text\",\"text\":\"Tornara-se tão íntima da substância terrestre – a dor” (parágrafo 7)\"}]}]},{\"type\":\"option\",\"attrs\":{\"letter\":\"E\"},\"content\":[{\"type\":\"paragraph\",\"attrs\":{\"textAlign\":null},\"content\":[{\"type\":\"text\",\"text\":\"“Gostava das pessoas erradas, consumidas de paixão” (parágrafo 9)\"}]}]}]}]}]}]}', NULL),
('35e953f532750d57589f15f45608f62e', 'e3e87095-bc12-4a2c-87ca-ffaab3327a75', '2026-02-06 18:05:05', '2026-02-06 18:05:05', NULL, '[]', '{\"schemaVersion\":1,\"id\":\"e3e87095-bc12-4a2c-87ca-ffaab3327a75\",\"createdAt\":\"2026-02-06T17:29:42.523Z\",\"updatedAt\":\"2026-02-06T18:05:27.275Z\",\"tipo\":\"Discursiva\",\"dificuldade\":\"Média\",\"tags\":[],\"gabarito\":{\"kind\":\"mcq\",\"correct\":\"E\",\"rubric\":null},\"source\":{\"kind\":\"concurso\",\"concurso\":\"FUVEST\",\"banca\":\"FUVEST\",\"numero\":\"80\",\"ano\":1997},\"disciplina\":\"Matemática\",\"assunto\":\"Geometria Analítica\"}', '{\"type\":\"doc\",\"content\":[{\"type\":\"question\",\"content\":[{\"type\":\"statement\",\"content\":[{\"type\":\"paragraph\",\"attrs\":{\"textAlign\":null},\"content\":[{\"type\":\"text\",\"text\":\"Na figura abaixo, \"},{\"type\":\"math_inline\",\"attrs\":{\"latex\":\"A\"}},{\"type\":\"text\",\"text\":\" é um ponto do plano cartesiano, com coordenadas \"},{\"type\":\"math_inline\",\"attrs\":{\"latex\":\"(x,y)\"}},{\"type\":\"text\",\"text\":\". \"}]},{\"type\":\"paragraph\",\"attrs\":{\"textAlign\":null},\"content\":[{\"type\":\"image\",\"attrs\":{\"id\":\"1e239f4e-c75f-4637-87a6-e77f002e8504\",\"src\":\"https://mpfaraujo.com.br/guardafiguras/uploads/1c248e62c7e32114196e08d0af8d6d53c15ced486f56d49ece9f9eb188aaa374.png\",\"width\":\"227\",\"align\":\"center\"}}]},{\"type\":\"paragraph\",\"attrs\":{\"textAlign\":null},\"content\":[{\"type\":\"text\",\"text\":\"Sabendo que \"},{\"type\":\"math_inline\",\"attrs\":{\"latex\":\"A\"}},{\"type\":\"text\",\"text\":\" está localizado abaixo da reta \"},{\"type\":\"math_inline\",\"attrs\":{\"latex\":\"r\"}},{\"type\":\"text\",\"text\":\" e acima da reta \"},{\"type\":\"math_inline\",\"attrs\":{\"latex\":\"s\"}},{\"type\":\"text\",\"text\":\", tem-se\"}]}]}]}]}', NULL),
('368e916bd3a71914a7c96dd4b1750c80', 'b9eb5ff1-221f-415b-9612-685dd0272352', '2026-02-01 00:52:47', '2026-02-01 00:52:47', NULL, '[]', '{\"schemaVersion\":1,\"id\":\"b9eb5ff1-221f-415b-9612-685dd0272352\",\"createdAt\":\"2026-02-01T00:50:23.369Z\",\"updatedAt\":\"2026-02-01T00:52:39.783Z\",\"tipo\":\"Múltipla Escolha\",\"dificuldade\":\"Média\",\"tags\":[],\"gabarito\":{\"kind\":\"mcq\",\"correct\":\"C\"},\"source\":{\"kind\":\"original\"},\"disciplina\":\"Matemática\",\"assunto\":\"Geometria Plana\"}', '{\"type\":\"doc\",\"content\":[{\"type\":\"question\",\"content\":[{\"type\":\"statement\",\"content\":[{\"type\":\"paragraph\",\"attrs\":{\"textAlign\":null},\"content\":[{\"type\":\"text\",\"text\":\"Um ponto P é tomado sobre um dos lados de um quadrado de lado 2cm. Por P, traça-se perpendicularmente às diagonais do quadrado os segmentos PA e PB que medem, respectivamente a e b. O valor de a + b, em cm, é igual a\"},{\"type\":\"image\",\"attrs\":{\"src\":\"https://mpfaraujo.com.br/guardafiguras/uploads/c96b0917f33b2e86ad7ce75a7e199e4f87a0fa6c85aaf6a84d8db4b8299b1cc7.jpg\",\"width\":\"151\",\"align\":\"center\"}}]}]},{\"type\":\"options\",\"content\":[{\"type\":\"option\",\"attrs\":{\"letter\":\"A\"},\"content\":[{\"type\":\"paragraph\",\"attrs\":{\"textAlign\":null},\"content\":[{\"type\":\"math_inline\",\"attrs\":{\"latex\":\"\\\\frac{\\\\sqrt2}{2}\"}}]}]},{\"type\":\"option\",\"attrs\":{\"letter\":\"B\"},\"content\":[{\"type\":\"paragraph\",\"attrs\":{\"textAlign\":null},\"content\":[{\"type\":\"text\",\"text\":\"1\"}]}]},{\"type\":\"option\",\"attrs\":{\"letter\":\"C\"},\"content\":[{\"type\":\"paragraph\",\"attrs\":{\"textAlign\":null},\"content\":[{\"type\":\"math_inline\",\"attrs\":{\"latex\":\"\\\\sqrt2\"}}]}]},{\"type\":\"option\",\"attrs\":{\"letter\":\"D\"},\"content\":[{\"type\":\"paragraph\",\"attrs\":{\"textAlign\":null},\"content\":[{\"type\":\"text\",\"text\":\"2\"}]}]},{\"type\":\"option\",\"attrs\":{\"letter\":\"E\"},\"content\":[{\"type\":\"paragraph\",\"attrs\":{\"textAlign\":null},\"content\":[{\"type\":\"math_inline\",\"attrs\":{\"latex\":\"2\\\\sqrt{2}\"}}]}]}]}]}]}', NULL),
