('3e28550c55745863152a70572c3b298b', '35f56afd-fe72-4a33-887e-899a680a13de', '2026-02-06 13:50:58', '2026-02-06 13:50:58', NULL, '[]', '{\"schemaVersion\":1,\"id\":\"35f56afd-fe72-4a33-887e-899a680a13de\",\"createdAt\":\"2026-02-04T20:02:27.712Z\",\"updatedAt\":\"2026-02-06T13:50:43.826Z\",\"tipo\":\"Múltipla Escolha\",\"dificuldade\":\"Fácil\",\"tags\":[],\"gabarito\":{\"kind\":\"mcq\",\"correct\":\"C\",\"rubric\":null},\"source\":{\"kind\":\"concurso\",\"concurso\":\"ENEM\",\"banca\":\"INEP\",\"ano\":2025,\"cargo\":\"Amarela\",\"numero\":\"139\"},\"disciplina\":\"Matemática\",\"assunto\":\"Estatística\"}', '{\"type\":\"doc\",\"content\":[{\"type\":\"question\",\"content\":[{\"type\":\"statement\",\"content\":[{\"type\":\"paragraph\",\"attrs\":{\"textAlign\":\"justify\"},\"content\":[{\"type\":\"text\",\"text\":\"Uma empresa de tecnologia vai padronizar a velocidade de conexão de internet que oferece a seus clientes em dez cidades.\"}]},{\"type\":\"paragraph\",\"attrs\":{\"textAlign\":\"justify\"},\"content\":[{\"type\":\"text\",\"text\":\"A direção da empresa decide que seu novo padrão de velocidade de referência será a mediana dos valores das velocidades de referência de conexões nessas dez cidades. Esses valores, em megabyte por segundo (MB/s), são apresentados no quadro.\"}]},{\"type\":\"paragraph\",\"attrs\":{\"textAlign\":\"justify\"},\"content\":[{\"type\":\"image\",\"attrs\":{\"id\":\"cc907840-b7da-4b9d-a64c-85a1faeb3b25\",\"src\":\"https://mpfaraujo.com.br/guardafiguras/uploads/08a24c6a73fc75b8a2401665a161218092c2431e09a41cc07e72abce53710738.png\",\"width\":302,\"align\":\"center\"}},{\"type\":\"text\",\"text\":\"A velocidade de referência, em megabyte por segundo, a ser adotada por essa empresa é\"}]}]},{\"type\":\"options\",\"content\":[{\"type\":\"option\",\"attrs\":{\"letter\":\"A\"},\"content\":[{\"type\":\"paragraph\",\"attrs\":{\"textAlign\":null},\"content\":[{\"type\":\"text\",\"text\":\"360.\"}]}]},{\"type\":\"option\",\"attrs\":{\"letter\":\"B\"