('412f20b297d11ab77359b06662f2e227', 'e3e87095-bc12-4a2c-87ca-ffaab3327a75', '2026-02-06 18:35:23', '2026-02-06 18:35:23', NULL, '[]', '{\"schemaVersion\":1,\"id\":\"e3e87095-bc12-4a2c-87ca-ffaab3327a75\",\"createdAt\":\"2026-02-06T17:29:42.523Z\",\"updatedAt\":\"2026-02-06T18:35:07.188Z\",\"tipo\":\"Múltipla Escolha\",\"dificuldade\":\"Média\",\"tags\":[],\"gabarito\":{\"kind\":\"mcq\",\"correct\":\"E\",\"rubric\":null},\"source\":{\"kind\":\"concurso\",\"concurso\":\"FUVEST\",\"banca\":\"FUVEST\",\"numero\":\"80\",\"ano\":1997},\"disciplina\":\"Matemática\",\"assunto\":\"Geometria Analítica\"}', '{\"type\":\"doc\",\"content\":[{\"type\":\"question\",\"content\":[{\"type\":\"statement\",\"content\":[{\"type\":\"paragraph\",\"attrs\":{\"textAlign\":null},\"content\":[{\"type\":\"text\",\"text\":\"Na figura abaixo, \"},{\"type\":\"math_inline\",\"attrs\":{\"latex\":\"A\"}},{\"type\":\"text\",\"text\":\" é um ponto do plano cartesiano, com coordenadas \"},{\"type\":\"math_inline\",\"attrs\":{\"latex\":\"(x,y)\"}},{\"type\":\"text\",\"text\":\". \"}]},{\"type\":\"paragraph\",\"attrs\":{\"textAlign\":null},\"content\":[{\"type\":\"image\",\"attrs\":{\"id\":\"84024ddb-de64-4932-b566-39640f6ce6f4\",\"src\":\"https://mpfaraujo.com.br/guardafiguras/uploads/1c248e62c7e32114196e08d0af8d6d53c15ced486f56d49ece9f9eb188aaa374.png\",\"width\":\"227\",\"align\":\"center\"}}]},{\"type\":\"paragraph\",\"attrs\":{\"textAlign\":null},\"content\":[{\"type\":\"text\",\"text\":\"Sabendo que \"},{\"type\":\"math_inline\",\"attrs\":{\"latex\":\"A\"}},{\"type\":\"text\",\"text\":\" está localizado abaixo da reta \"},{\"type\":\"math_inline\",\"attrs\":{\"latex\":\"r\"}},{\"type\":\"text\",\"text\":\" e acima da reta \"},{\"type\":\"math_inline\",\"attrs\":{\"latex\":\"s\"}},{\"type\":\"text\",\"text\":\", tem-se\"}]}]},{\"type\":\"options\",\"content\":[{\"type\":\"option\",\"attrs\":{\"letter\":\"A\"},\"content\":[{\"type\":\"paragraph\",\"attrs\":{\"textAlign\":null},\"content\":[{\"type\"