('44819045c5c0e2a22485343e508471c7', '7c39c235-0b2f-41a4-b24c-45a02f85f393', '2026-02-05 17:03:30', '2026-02-05 17:03:30', NULL, '[]', '{\"schemaVersion\":1,\"id\":\"7c39c235-0b2f-41a4-b24c-45a02f85f393\",\"createdAt\":\"2026-02-05T16:51:21.035Z\",\"updatedAt\":\"2026-02-05T17:03:22.835Z\",\"tipo\":\"Múltipla Escolha\",\"dificuldade\":\"Média\",\"tags\":[],\"gabarito\":{\"kind\":\"mcq\",\"correct\":\"B\",\"rubric\":null},\"source\":{\"kind\":\"concurso\",\"concurso\":\"UERJ\",\"banca\":\"UERJ\",\"ano\":2025},\"disciplina\":\"Matemática\",\"assunto\":\"Sequências\"}', '{\"type\":\"doc\",\"content\":[{\"type\":\"question\",\"content\":[{\"type\":\"statement\",\"content\":[{\"type\":\"paragraph\",\"attrs\":{\"textAlign\":null},\"content\":[{\"type\":\"text\",\"text\":\"Admitindo um retângulo cujos lados medem a e b, sendo a < b, é possível formar uma sequência ilimitada de retângulos da seguinte forma: a partir do primeiro, cada novo retângulo é construído acrescentando-se um quadrado cujo lado é igual ao maior lado do retângulo anterior, conforme ilustrado a seguir.\"}]},{\"type\":\"paragraph\",\"attrs\":{\"textAlign\":null},\"content\":[{\"type\":\"image\",\"attrs\":{\"src\":\"https://mpfaraujo.com.br/guardafiguras/uploads/f1cc52ea2ccedc4f891d61842424b5cf54ed6348a785f807b59be2c2355d64f8.png\",\"width\":302,\"align\":null}}]},{\"type\":\"paragraph\",\"attrs\":{\"textAlign\":null},\"content\":[{\"type\":\"text\",\"text\":\"A figura IV destaca a linha poligonal P\"},{\"type\":\"text\",\"marks\":[{\"type\":\"subscript\"}],\"text\":\"1\"},{\"type\":\"text\",\"text\":\" P\"},{\"type\":\"text\",\"marks\":[{\"type\":\"subscript\"}],\"text\":\"2\"},{\"type\":\"text\",\"text\":\" P\"},{\"type\":\"text\",\"marks\":[{\"type\":\"subscript\"}],\"text\":\"3\"},{\"type\":\"text\",\"text\":\" P\"},{\"type\":\"text\",\"marks\":[{\"type\":\"subscript\"}],\"text\":\"4\"},{\"type\":\"text\",\"text\":\" P\"},{\"type\":\"text\",\"marks\":[{\"type\":\"subscript\"}],\"text\":\"5\"},{\"type\":\"text\",\"text\":\" P\"},{\"type\":\"text\",\"marks\":[{\"type\":\"subscript\"}],\"text\":\"6\"},{\"type\":\"text\",\"text\":\" , formada pelos lados dos retângulos, que são os elementos da sequência (a, b, a + b, a + 2b, 2a + 3b).\"}]},{\"type\":\"paragraph\",\"attrs\":{\"textAlign\":null},\"content\":[{\"type\":\"text\",\"text\":\"Mantendo o mesmo padrão de construção, o comprimento da linha poligonal P\"},{\"type\":\"text\",\"marks\":[{\"type\":\"subscript\"}],\"text\":\"1\"},{\"type\":\"text\",\"text\":\" P\"},{\"type\":\"text\",\"marks\":[{\"type\":\"subscript\"}],\"text\":\"2\"},{\"type\":\"text\",\"text\":\" P\"},{\"type\":\"text\",\"marks\":[{\"type\":\"subscript\"}],\"text\":\"3\"},{\"type\":\"text\",\"text\":\" P\"},{\"type\":\"text\",\"marks\":[{\"type\":\"subscript\"}],\"text\":\"4\"},{\"type\":\"text\",\"text\":\" P\"},{\"type\":\"text\",\"marks\":[{\"type\":\"subscript\"}],\"text\":\"5\"},{\"type\":\"text\",\"text\":\" P\"},{\"type\":\"text\",\"marks\":[{\"type\":\"subscript\"}],\"text\":\"6\"},{\"type\":\"text\",\"text\":\" P\"},{\"type\":\"text\",\"marks\":[{\"type\":\"subscript\"}],\"text\":\"7\"},{\"type\":\"text\",\"text\":\" ,\"}]},{\"type\":\"paragraph\",\"attrs\":{\"textAlign\":null},\"content\":[{\"type\":\"text\",\"text\":\"de P\"},{\"type\":\"text\",\"marks\":[{\"type\":\"subscript\"}],\"text\":\"1\"},{\"type\":\"text\",\"text\":\" até o vértice P\"},{\"type\":\"text\",\"marks\":[{\"type\":\"subscript\"}],\"text\":\"7\"},{\"type\":\"text\",\"text\":\" , é igual a:\"}]}]},{\"type\":\"options\",\"content\":[{\"type\":\"option\",\"attrs\":{\"letter\":\"A\"},\"content\":[{\"type\":\"paragraph\",\"attrs\":{\"textAlign\":null},\"content\":[{\"type\":\"text\",\"text\":\"5a + 7b\"}]}]},{\"type\":\"option\",\"attrs\":{\"letter\":\"B\"},\"content\":[{\"type\":\"paragraph\",\"attrs\":{\"textAlign\":null},\"content\":[{\"type\":\"text\",\"text\":\"8a + 12b\"}]}]},{\"type\":\"option\",\"attrs\":{\"letter\":\"C\"},\"content\":[{\"type\":\"paragraph\",\"attrs\":{\"textAlign\":null},\"content\":[{\"type\":\"text\",\"text\":\"13a + 20b\"}]}]},{\"type\":\"option\",\"attrs\":{\"letter\":\"D\"},\"content\":[{\"type\":\"paragraph\",\"attrs\":{\"textAlign\":null},\"content\":[{\"type\":\"text\",\"text\":\"21a + 33b\"}]}]}]}]}]}', NULL),
('4676b79fff7d95b5aead0e7304624f37', '5acb2baa-cc9f-458f-bcaf-515fa6be33e4', '2026-02-04 12:11:23', '2026-02-04 12:11:23', NULL, '[]', '{\"schemaVersion\":1,\"id\":\"5acb2baa-cc9f-458f-bcaf-515fa6be33e4\",\"createdAt\":\"2026-02-04T10:46:45.284Z\",\"updatedAt\":\"2026-02-04T12:11:17.647Z\",\"tipo\":\"Múltipla Escolha\",\"dificuldade\":\"Média\",\"tags\":[],\"source\":{\"kind\":\"original\"},\"disciplina\":\"Matemática\",\"assunto\":\"Porcentagem\"}', '{\"type\":\"doc\",\"content\":[{\"type\":\"set_questions\",\"content\":[{\"type\":\"base_text\",\"content\":[{\"type\":\"paragraph\",\"attrs\":{\"textAlign\":null},\"content\":[{\"type\":\"text\",\"text\":\"Antes de iniciar uma campanha publicitaria, um banco fez uma pesquisa entre 800 de seus clientes sobre sua intenção de adesão aos seus dois novos produtos. Dos clientes entrevistados, 240 mostraram-se interessados no primeiro produto, 400 mostraram-se interessados no segundo produto e alguns estavam interessados em ambos os produtos. A campanha publicitária só será iniciada caso pelo menos 70% dos entrevistados mostrarem-se interessados em pelo menos um dos produtos.\"}]}]},{\"type\":\"question_item\",\"attrs\":{\"answerKey\":{\"kind\":\"mcq\",\"correct\":\"A\"}},\"content\":[{\"type\":\"statement\",\"content\":[{\"type\":\"paragraph\",\"attrs\":{\"textAlign\":null},\"content\":[{\"type\":\"text\",\"text\":\"Qual a porcentagem máxima do total de clientes pode mostrar-se interessados em ambos os produtos para que a campanha publicitária seja iniciada?\"}]}]},{\"type\":\"options\",\"content\":[{\"type\":\"option\",\"attrs\":{\"letter\":\"A\"},\"content\":[{\"type\":\"paragraph\",\"attrs\":{\"textAlign\":null},\"content\":[{\"type\":\"text\",\"text\":\"10%\"}]}]},{\"type\":\"option\",\"attrs\":{\"letter\":\"B\"},\"content\":[{\"type\":\"paragraph\",\"attrs\":{\"textAlign\":null},\"content\":[{\"type\":\"text\",\"text\":\"15%\"}]}]},{\"type\":\"option\",\"attrs\":{\"letter\":\"C\"},\"content\":[{\"type\":\"paragraph\",\"attrs\":{\"textAlign\":null},\"content\":[{\"type\":\"text\",\"text\":\"20%\"}]}]},{\"type\":\"option\",\"attrs\":{\"letter\":\"D\"},\"content\":[{\"type\":\"paragraph\",\"attrs\":{\"textAlign\":null},\"content\":[{\"type\":\"text\",\"text\":\"25%\"}]}]},{\"type\":\"option\",\"attrs\":{\"letter\":\"E\"},\"content\":[{\"type\":\"paragraph\",\"attrs\":{\"textAlign\":null},\"content\":[{\"type\":\"text\",\"text\":\"30%\"}]}]}]}]},{\"type\":\"question_item\",\"attrs\":{\"answerKey\":{\"kind\":\"mcq\",\"correct\":\"E\"}},\"content\":[{\"type\":\"statement\",\"content\":[{\"type\":\"paragraph\",\"attrs\":{\"textAlign\":null},\"content\":[{\"type\":\"text\",\"text\":\"O número de clientes interessados em ambos os produtos não pode ser igual a \"}]}]},{\"type\":\"options\",\"content\":[{\"type\":\"option\",\"attrs\":{\"letter\":\"A\"},\"content\":[{\"type\":\"paragraph\",\"attrs\":{\"textAlign\":null},\"content\":[{\"type\":\"text\",\"text\":\"75\"}]}]},{\"type\":\"option\",\"attrs\":{\"letter\":\"B\"},\"content\":[{\"type\":\"paragraph\",\"attrs\":{\"textAlign\":null},\"content\":[{\"type\":\"text\",\"text\":\"78\"}]}]},{\"type\":\"option\",\"attrs\":{\"letter\":\"C\"},\"content\":[{\"type\":\"paragraph\",\"attrs\":{\"textAlign\":null},\"content\":[{\"type\":\"text\",\"text\":\"79\"}]}]},{\"type\":\"option\",\"attrs\":{\"letter\":\"D\"},\"content\":[{\"type\":\"paragraph\",\"attrs\":{\"textAlign\":null},\"content\":[{\"type\":\"text\",\"text\":\"80\"}]}]},{\"type\":\"option\",\"attrs\":{\"letter\":\"E\"},\"content\":[{\"type\":\"paragraph\",\"attrs\":{\"textAlign\":null},\"content\":[{\"type\":\"text\",\"text\":\"82\"}]}]}]}]}]}]}', NULL),
('51c0531554a18174b1819456f7a2004c', 'cb3d7ef8-4560-48e0-884a-092b2e242b08', '2026-01-30 23:54:10', '2026-01-30 23:54:10', NULL, '[]', '{\"schemaVersion\":1,\"id\":\"cb3d7ef8-4560-48e0-884a-092b2e242b08\",\"createdAt\":\"2026-01-30T23:47:50.669Z\",\"updatedAt\":\"2026-01-30T23:54:06.096Z\",\"tipo\":\"Múltipla Escolha\",\"dificuldade\":\"Média\",\"tags\":[],\"gabarito\":{\"kind\":\"mcq\",\"correct\":\"D\"},\"source\":{\"kind\":\"original\"},\"disciplina\":\"Matemática\",\"assunto\":\"Geometria Analítica\"}', '{\"type\":\"doc\",\"content\":[{\"type\":\"question\",\"content\":[{\"type\":\"statement\",\"content\":[{\"type\":\"paragraph\",\"content\":[{\"type\":\"text\",\"text\":\"Uma câmara dos sussurros é um espaço em que, se duas pessoas estão nas posições especificadas como foco, elas podem falar entre si, mesmo sussurrando, a uma distância considerável. Isso porque os painéis colocados atrás delas são partes de uma mesma elipse cujos focos são as posições das cabeças das pessoas.\"}]},{\"type\":\"paragraph\",\"content\":[{\"type\":\"text\",\"text\":\"Na câmara de sussurros representada na figura a seguir, a distância entre as duas pessoas é de 20m e a distância de cada pessoa até um vértice da elipse é 2m.\"}]},{\"type\":\"paragraph\",\"content\":[{\"type\":\"image\",\"attrs\":{\"src\":\"https://mpfaraujo.com.br/guardafiguras/uploads/8a72e6f96ba2fac443d61674c085c8d8c2693320d5f6ce8c6e4c689697d61144.jpg\",\"width\":\"302\"}},{\"type\":\"text\",\"text\":\"  \"}]},{\"type\":\"paragraph\",\"content\":[{\"type\":\"text\",\"text\":\"A equação da elipse que contém os painéis da câmara representada no sistema de eixos proposto na figura é\"}]}]},{\"type\":\"options\",\"content\":[{\"type\":\"option\",\"attrs\":{\"letter\":\"A\"},\"content\":[{\"type\":\"paragraph\",\"content\":[{\"type\":\"math_inline\",\"attrs\":{\"latex\":\"\\\\frac{x^2}{100}+\\\\frac{y^2}{44}=1\"}}]}]},{\"type\":\"option\",\"attrs\":{\"letter\":\"B\"},\"content\":[{\"type\":\"paragraph\",\"content\":[{\"t