('51df223e7ff6fad0c7018e9483d868f1', '0b8f2a45-b888-49c9-bd71-f8f80987284d', '2026-01-31 13:43:50', '2026-01-31 13:43:50', NULL, '[]', '{\"schemaVersion\":1,\"id\":\"0b8f2a45-b888-49c9-bd71-f8f80987284d\",\"createdAt\":\"2026-01-26T16:36:10.260Z\",\"updatedAt\":\"2026-01-31T13:43:45.369Z\",\"tipo\":\"Múltipla Escolha\",\"dificuldade\":\"Fácil\",\"tags\":[],\"gabarito\":{\"kind\":\"mcq\",\"correct\":\"C\"},\"source\":{\"kind\":\"original\"},\"disciplina\":\"Matemática\",\"assunto\":\"PA\"}', '{\"type\":\"doc\",\"content\":[{\"type\":\"question\",\"content\":[{\"type\":\"statement\",\"content\":[{\"type\":\"paragraph\",\"attrs\":{\"textAlign\":\"left\"},\"content\":[{\"type\":\"text\",\"text\":\"O valor de \"},{\"type\":\"math_inline\",\"attrs\":{\"latex\":\"x\"}},{\"type\":\"text\",\"text\":\" para que  \"},{\"type\":\"math_inline\",\"attrs\":{\"latex\":\"\\\\displaystyle{\\\\log_2x, \\\\log_2(3x+2), \\\\log_2(10x+12)}\"}},{\"type\":\"text\",\"text\":\"formem, nessa ordem, uma PA é:\"}]}]},{\"type\":\"options\",\"content\":[{\"type\":\"option\",\"attrs\":{\"letter\":\"A\"},\"content\":[{\"type\":\"paragraph\",\"attrs\":{\"textAlign\":null},\"content\":[{\"type\":\"text\",\"text\":\"um quadrado perfeito.\"}]}]},{\"type\":\"option\",\"attrs\":{\"letter\":\"B\"},\"content\":[{\"type\":\"paragraph\",\"attrs\":{\"textAlign\":null},\"content\":[{\"type\":\"text\",\"text\":\"um número negativo.\"}]}]},{\"type\":\"option\",\"attrs\":{\"letter\":\"C\"},\"content\":[{\"type\":\"paragraph\",\"attrs\":{\"textAlign\":null},\"content\":[{\"type\":\"text\",\"text\":\"um número primo.\"}]}]},{\"type\":\"option\",\"attrs\":{\"letter\":\"D\"},\"content\":[{\"type\":\"paragraph\",\"attrs\":{\"textAlign\":null},\"content\":[{\"type\":\"text\",\"text\":\"um número ímpar.\"}]}]},{\"type\":\"option\",\"attrs\":{\"letter\":\"E\"},\"content\":[{\"type\":\"paragraph\",\"attrs\":{\"textAlign\":null},\"content\":[{\"type\":\"text\",\"text\":\"inexistente.\"}]}]}]}]}]}', NULL),
('5507a9e50811d2933e58c17d3d24a12f', '17697546-c51e-4f22-9bbf-c0e2c4895260', '2026-02-07 12:26:06', '2026-02-07 12:26:06', NULL, '[]', '{\"schemaVersion\":1,\"id\":\"17697546-c51e-4f22-9bbf-c0e2c4895260\",\"createdAt\":\"2026-02-03T21:59:41.067Z\",\"updatedAt\":\"2026-02-07T12:26:06.049Z\",\"tipo\":\"Múltipla Escolha\",\"dificuldade\":\"Média\",\"tags\":[],\"source\":{\"kind\":\"original\"},\"disciplina\":\"Português\",\"assunto\":\"Interporetação de texto\"}', '{\"type\":\"doc\",\"content\":[{\"type\":\"set_questions\",\"content\":[{\"type\":\"base_text\",\"content\":[{\"type\":\"paragraph\",\"attrs\":{\"textAlign\":\"center\"},\"content\":[{\"type\":\"text\",\"text\":\"Maria José \"}]},{\"type\":\"paragraph\",\"attrs\":{\"textAlign\":\"right\"},\"content\":[{\"type\":\"text\",\"text\":\"Paulo Mendes Campos \"}]},{\"type\":\"paragraph\",\"attrs\":{\"textAlign\":null},\"content\":[{\"type\":\"text\",\"text\":\"Faz um ano que Maria José morreu. Era meiga quase sempre, violenta quando necessário. Eu era menino e apanhava de um companheiro maior, quando ela me gritou da sacada se eu não via a pedra que marcava o gol. Dei uma pedrada no outro e acabei com a briga por milagre.\"}]},{\"type\":\"paragraph\",\"attrs\":{\"textAlign\":null},\"content\":[{\"type\":\"text\",\"text\":\"Visitava os miseráveis, internava indigentes enfermos, devotava-se ao alívio de misérias físicas e morais do próximo, estudava o mistério teológico, exigia sempre o mais difícil de si mesma, comungava todos os dias, ingressou na Ordem Terceira de São Francisco. Mas nunca deixou de ter na gaveta o revólver que havia recebido, menina-e-moça, das mãos do pai, e que empunhou no quintal noturno, perse guindo um ladrão, para espanto de meus cinco anos.\"}]},{\"type\":\"paragraph\",\"attrs\":{\"textAlign\":null},\"content\":[{\"type\":\"text\",\"text\":\"Já perto dos setenta anos, ela explicava para um amigo meu que tinha chegado à humildade da velhice; já não se importava com quem tentasse ofendê-la, mas conservava o revólver para a defesa dos filhos e dos netos.\"}]},{\"type\":\"paragraph\",\"attrs\":{\"textAlign\":null},\"content\":[{\"type\":\"text\",\"text\":\"Tratou-me com a dureza e o carinho que mere ciam a rebeldia e o verdor da minha meninice. Ensi nou-me a ler as primeiras sentenças; me falava do Cura d’Ars e nos dois Franciscos, o de Sales e o de Assis; apresentou-me aos contos de Edgar Poe e aos poemas de Baudelaire; dizia-me sorrindo versos de Antônio Nobre que havia decorado quando menina; discutia comigo as ideias finais de Tolstoi; escutava maternalmente meus contos toscos. Quando me desgarrei nos primeiros envolvimentos adolescentes, Maria José, com irônico afeto, me repetia a advertência de Drummond: “Paulo, sossegue, o amor é isso que você está vendo: hoje beija, amanhã não beija, depois de amanhã é domingo e segunda-feira ninguém sabe o que será”.\"}]},{\"type\":\"paragraph\",\"attrs\":{\"textAlign\":null},\"content\":[{\"type\":\"text\",\"text\":\"Logo que me fiz homenzinho, deixou a dureza e se fez minha amiga: nada me perguntava, adivinhava tudo.\"}]},{\"type\":\"paragraph\",\"attrs\":{\"textAlign\":null},\"content\":[{\"type\":\"text\",\"text\":\"Terna e firme, nunca lhe vi a fraqueza da pieguice. Com o gosto espontâneo da qualidade das coisas, renunciou às vaidades mais singelas. Sensível, alegre, aprendeu a encarar o sofrimento de olhos lúcidos. Fiel à disciplina religiosa, compreendia celestialmente as almas que perdiam o rumo. Fé, Esperança e Caridade eram para ela a flecha e o alvo das criaturas.\"}]},{\"type\":\"paragraph\",\"attrs\":{\"textAlign\":null},\"content\":[{\"type\":\"text\",\"text\":\"Tornara-se tão íntima da substância terrestre – a dor – que se fazia difícil para o médico saber o que sentia; acabava dizendo que doía um pouco, por delicadeza.\"}]},{\"type\":\"paragraph\",\"attrs\":{\"textAlign\":null},\"content\":[{\"type\":\"text\",\"text\":\"Capaz de longos jejuns e abstinências, já no final da vida, podia acompanhar um casal amigo a Copacabana, passar do bar da moda ao restaurante diferente, beber dois cafés ou três uísques em santa serenidade e aceitar com alegria o prato exótico.\"}]},{\"type\":\"paragraph\",\"attrs\":{\"textAlign\":null},\"content\":[{\"type\":\"text\",\"text\":\"Gostava das pessoas erradas, consumidas de paixão, admirava São Paulo e Santo Agostinho, acre ditava que era preciso se fazer violência para entrar no reino celeste.\"}]},{\"type\":\"paragraph\",\"attrs\":{\"textAlign\":null},\"content\":[{\"type\":\"text\",\"text\":\"Poucas horas antes de morrer, pediu um conhaque e sorriu, destemida e doce, como quem vai partir para o céu. Santificara-se. Deus era o dia e a noite de seu coração, o Pai, a piedade, o fogo do espírito. Per di quem me amava e perdoava, quem me encomendava à compaixão do Criador e me defendia contra o mundo de revólver na mão.\"}]},{\"type\":\"paragraph\",\"attrs\":{\"textAlign\":\"right\"},\"content\":[{\"type\":\"text\",\"text\":\"Disponível em: https://cronicabrasileira.org.br/cronicas/7173/ma ria-jose. Acesso em: 05 fev. 2022.\"}]}]},{\"type\":\"question_item\",\"attrs\":{\"answerKey\":{\"kind\":\"mcq\",\"correct\":\"A\"}},\"content\":[{\"type\":\"statement\",\"content\":[{\"type\":\"paragraph\",\"attrs\":{\"textAlign\":null},\"content\":[{\"type\":\"text\",\"text\":\"No texto, o narrador apresenta Maria José ao leitor, des crevendo-a a partir de aspectos subjetivos, como em:\"}]}]},{\"type\":\"options\",\"content\":[{\"type\":\"option\",\"attrs\":{\"letter\":\"A\"},\"content\":[{\"type\":\"paragraph\",\"attrs\":{\"textAlign\":null},\"content\":[{\"type\":\"text\",\"text\":\"“Faz um ano que Maria José morreu.” (parágrafo 1)\"}]}]},{\"type\":\"option\",\"attrs\":{\"letter\":\"B\"},\"content\":[{\"type\":\"paragraph\",\"attrs\":{\"textAlign\":null},\"content\":[{\"type\":\"text\",\"text\":\"\\\"Visitava os miseráveis, internava indigentes enfermos” (parágrafo 2)\"}]}]},{\"type\":\"option\",\"attrs\":{\"letter\":\"C\"},\"content\":[{\"type\":\"paragraph\",\"attrs\":{\"textAlign\":null},\"content\":[{\"type\":\"text\",\"text\":\"“comungava todos os dias” (parágrafo 2)\"}]}]},{\"type\":\"option\",\"attrs\":{\"letter\":\"D\"},\"content\":[{\"type\":\"paragraph\",\"attrs\":{\"textAlign\":null},\"content\":[{\"type\":\"text\",\"text\":\"\\\"apresentou-me aos contos de Edgar Poe e aos poemas de Baudelaire” (parágrafo 4)\"}]}]},{\"type\":\"option\",\"attrs\":{\"letter\":\"E\"},\"content\":[{\"type\":\"paragraph\",\"attrs\":{\"textAlign\":null},\"content\":[{\"type\":\"text\",\"text\":\"“Terna e firme, nunca lhe vi a fraqueza da pieguice.” (parágrafo 6)\"}]}]}]}]},{\"type\":\"question_item\",\"attrs\":{\"answerKey\":{\"kind\":\"mcq\",\"correct\":\"D\"}},\"content\":[{\"type\":\"statement\",\"content\":[{\"type\":\"paragraph\",\"attrs\":{\"textAlign\":null},\"content\":[{\"type\":\"text\",\"text\":\"De acordo com o narrador, Maria José “Era meiga quase sempre, violenta quando necessário” (parágrafo 1)\"}]},{\"type\":\"paragraph\",\"attrs\":{\"textAlign\":null},\"content\":[{\"type\":\"text\",\"text\":\"Essa violência a que o narrador se refere pode ser com provada no trecho:\"}]}]},{\"type\":\"options\",\"content\":[{\"type\":\"option\",\"attrs\":{\"letter\":\"A\"},\"content\":[{\"type\":\"paragraph\",\"attrs\":{\"textAlign\":null},\"content\":[{\"type\":\"text\",\"text\":\"“ela me gritou da sacada se eu não via a pedra que mar cava o gol. Dei uma pedrada no outro” (parágrafo 1)\"}]}]},{\"type\":\"option\",\"attrs\":{\"letter\":\"B\"},\"content\":[{\"type\":\"paragraph\",\"attrs\":{\"textAlign\":null},\"content\":[{\"type\":\"text\",\"text\":\"\\\"Tratou-me com a dureza e o carinho que mereciam a rebeldia e o verdor da minha meninice.” (parágrafo 4)\"}]}]},{\"type\":\"option\",\"attrs\":{\"letter\":\"C\"},\"content\":[{\"type\":\"paragraph\",\"attrs\":{\"textAlign\":null},\"content\":[{\"type\":\"text\",\"text\":\"“Fé, Esperança e Caridade eram para ela a flecha e o alvo das criaturas.” (parágrafo 6)\"}]}]},{\"type\":\"option\",\"attrs\":{\"letter\":\"D\"},\"content\":[{\"type\":\"paragraph\",\"attrs\":{\"textAlign\":null},\"content\":[{\"type\":\"text\",\"text\":\"Tornara-se tão íntima da substância terrestre – a dor” (parágrafo 7)\"}]}]},{\"type\":\"option\",\"attrs\":{\"letter\":\"E\"},\"content\":[{\"type\":\"paragraph\",\"attrs\":{\"textAlign\":null},\"content\":[{\"type\":\"text\",\"text\":\"“Gostava das pessoas erradas, consumidas de paixão” (parágrafo 9)\"}]}]}]}]}]}]}', NULL),
('572b80377a4e5aa7ae89bc85eb4aed2f', 'cb3d7ef8-4560-48e0-884a-092b2e242b08', '2026-01-31 14:47:00', '2026-01-31 14:47:00', NULL, '[]', '{\"schemaVersion\":1,\"id\":\"cb3d7ef8-4560-48e0-884a-092b2e242b08\",\"createdAt\":\"2026-01-30T23:47:50.669Z\",\"updatedAt\":\"2026-01-31T14:46:55.280Z\",\"tipo\":\"Múltipla Escolha\",\"dificuldade\":\"Média\",\"tags\":[],\"gabarito\":{\"kind\":\"mcq\",\"correct\":\"D\"},\"source\":{\"kind\":\"original\"},\"disciplina\":\"Matemática\",\"assunto\":\"Geometria Analítica\"}', '{\"type\":\"doc\",\"content\":[{\"type\":\"question\",\"content\":[{\"type\":\"statement\",\"content\":[{\"type\":\"paragraph\",\"attrs\":{\"textAlign\":null},\"content\":[{\"type\":\"text\",\"text\":\"Uma câmara dos sussurros é um espaço em que, se duas pessoas estão nas posições especificadas como foco, elas podem falar entre si, mesmo sussurrando, a uma distância considerável. Isso porque os painéis colocados atrás delas são partes de uma mesma elipse cujos focos são as posições das cabeças das pessoas.\"}]},{\"type\":\"paragraph\",\"attrs\":{\"textAlign\":null},\"content\":[{\"type\":\"text\",\"text\":\"Na câmara de sussurros representada na figura a seguir, a distância entre as duas pessoas é de 20m e a distância de cada pessoa até um vértice da elipse é 2, 0m.\"}]},{\"type\":\"paragraph\",\"attrs\":{\"textAlign\":null},\"content\":[{\"type\":\"image\",\"attrs\":{\"src\":\"https://mpfaraujo.com.br/guardafiguras/uploads/8a72e6f96ba2fac443d61674c085c8d8c2693320d5f6ce8c6e4c689697d61144.jpg\",\"width\":\"227\",\"align\":\"center\"}},{\"type\":\"text\",\"text\":\" A equação da elipse que contém os painéis da câmara representada no sistema de eixos proposto na figura é\"}]}]},{\"type\":\"options\",\"content\":[{\"type\":\"option\",\"attrs\":{\"letter\":\"A\"},\"content\":[{\"type\":\"paragraph\",\"attrs\":{\"textAlign\":null},\"content\":[{\"type\":\"math_inline\",\"attrs\":{\"latex\":\"\\\\frac{x^2}{100}+\\\\frac{y^2}{44}=1\"}}]}]},{\"type\":\"option\",\"attrs\":{\"letter\":\"B\"},\"content\":[{\"type\":\"paragraph\",\"attrs\":{\"textAlign\":null},\"content\":[{\"type\":\"math_inline\",\"attrs\":{\"latex\":\"\\\\frac{x^2}{44}+\\\\frac{y^2}{100}=1\"}}]}]},{\"type\":\"option\",\"attrs\":{\"letter\":\"C\"},\"content\":[{\"type\":\"paragraph\",\"attrs\":{\"textAlign\":null},\"content\":[{\"type\":\"math_inline\",\"attrs\":{\"latex\":\"\\\\frac{x^2}{44}+\\\\frac{y^2}{144}=1\"}}]}]},{\"type\":\"option\",\"attrs\":{\"letter\":\"D\"},\"content\":[{\"type\":\"paragraph\",\"attrs\":{\"textAlign\":null},\"content\":[{\"type\":\"math_inline\",\"attrs\":{\"latex\":\"\\\\frac{x^2}{144}+\\\\frac{y^2}{44}=1\"}}]}]},{\"type\":\"option\",\"attrs\":{\"letter\":\"E\"},\"content\":[{\"type\":\"paragraph\",\"attrs\":{\"textAlign\":null},\"content\":[{\"type\":\"math_inline\",\"attrs\":{\"latex\":\"\\\\frac{x^2}{4}+\\\\frac{y^2}{44}=1\"}},{\"type\":\"text\",\"text\":\"  \"}]}]}]}]}]}', NULL),
