('5e2c04320c4c2b9d1c4b0ffe3107937e', '0052c445-0cee-4fc7-b34a-c1de32dca311', '2026-02-06 12:14:58', '2026-02-06 12:14:58', NULL, '[]', '{\"schemaVersion\":1,\"id\":\"0052c445-0cee-4fc7-b34a-c1de32dca311\",\"createdAt\":\"2026-02-05T18:17:11.763Z\",\"updatedAt\":\"2026-02-06T12:14:43.858Z\",\"tipo\":\"Múltipla Escolha\",\"dificuldade\":\"Média\",\"tags\":[],\"gabarito\":{\"kind\":\"mcq\",\"correct\":\"C\",\"rubric\":null},\"source\":{\"kind\":\"concurso\",\"concurso\":\"UERJ\",\"banca\":\"UERJ\",\"ano\":2025},\"disciplina\":\"Matemática\",\"assunto\":\"Geometria Plana\"}', '{\"type\":\"doc\",\"content\":[{\"type\":\"question\",\"content\":[{\"type\":\"statement\",\"content\":[{\"type\":\"paragraph\",\"attrs\":{\"textAlign\":null},\"content\":[{\"type\":\"text\",\"text\":\"No triângulo equilátero ABC, H corresponde ao ponto médio do lado AC. Desse modo, a área do triângulo ABH é igual à metade da área de ABC.\"}]},{\"type\":\"paragraph\",\"attrs\":{\"textAlign\":null},\"content\":[{\"type\":\"image\",\"attrs\":{\"src\":\"https://mpfaraujo.com.br/guardafiguras/uploads/12fd020bcdf366c7e80da5dd4ec1313f9916eff1206e0bab0847d48f209b5644.png\",\"width\":\"151\",\"align\":\"center\"}}]},{\"type\":\"paragraph\",\"attrs\":{\"textAlign\":null},\"content\":[{\"type\":\"text\",\"text\":\"Sendo W o perímetro do triângulo ABH e Y o perímetro do triângulo ABC, uma relação correta entre W e Y é:\"}]}]},{\"type\":\"options\",\"content\":[{\"type\":\"option\",\"attrs\":{\"letter\":\"A\"},\"content\":[{\"type\":\"paragraph\",\"attrs\":{\"textAlign\":null},\"content\":[{\"type\":\"math_inline\",\"attrs\":{\"latex\":\"0 < W < \\\\frac{Y}{2}\"}}]}]},{\"type\":\"option\",\"attrs\":{\"letter\":\"B\"},\"content\":[{\"type\":\"paragraph\",\"attrs\":{\"textAlign\":null},\"content\":[{\"type\":\"math_inline\",\"attrs\":{\"latex\":\"W = \\\\frac{Y}{2}\"}}]}]},{\"type\":\"option\",\"attrs\":{\"letter\":\"C\"},\"content\":[{\"type\":\"paragraph\",\"attrs\":{\"textAlign\":null},\"content\":[{\"type\":\"math_inline\",\"attrs\":{\"latex\":\"\\\\frac{Y}{2} < W < Y\"}}]}]},{\"type\":\"option\",\"attrs\":{\"letter\":\"D\"},\"content\":[{\"type\":\"paragraph\",\"attrs\":{\"textAlign\":null},\"content\":[{\"type\":\"text\",\"text\":\"W = Y\"}]}]}]}]}]}', NULL),
('6415c6e57e68af19caecea55f383dea5', 'dfb7582b-abdb-4e6d-b2b3-f4d6244fc995', '2026-02-06 20:56:18', '2026-02-06 20:56:18', NULL, '[]', '{\"schemaVersion\":1,\"id\":\"dfb7582b-abdb-4e6d-b2b3-f4d6244fc995\",\"createdAt\":\"2026-02-06T20:17:14.335Z\",\"updatedAt\":\"2026-02-06T20:56:02.675Z\",\"tipo\":\"Múltipla Escolha\",\"dificuldade\":\"Média\",\"tags\":[],\"gabarito\":{\"kind\":\"mcq\",\"correct\":\"D\",\"rubric\":null},\"source\":{\"kind\":\"concurso\",\"concurso\":\"Enem\",\"banca\":\"INEP\"},\"assunto\":\"Combinatoria\"}', '{\"type\":\"doc\",\"content\":[{\"type\":\"question\",\"content\":[{\"type\":\"statement\",\"content\":[{\"type\":\"paragraph\",\"attrs\":{\"textAlign\":null},\"content\":[{\"type\":\"text\",\"text\":\"Durante suas férias, oito amigos, dos quais dois são canhotos, decidem realizar um torneio de vôlei de praia. Eles precisam formar quatro duplas para a realização do torneio.\"}]},{\"type\":\"paragraph\",\"attrs\":{\"textAlign\":null},\"content\":[{\"type\":\"text\",\"text\":\"Nenhuma dupla pode ser formada por dois jogadores canhotos.\"}]},{\"type\":\"paragraph\",\"attrs\":{\"textAlign\":null},\"content\":[{\"type\":\"text\",\"text\":\"De quantas maneiras diferentes podem ser formadas essas quatro duplas?\"}]}]},{\"type\":\"options\",\"content\":[{\"type\":\"option\",\"attrs\":{\"letter\":\"A\"},\"content\":[{\"type\":\"paragraph\",\"attrs\":{\"textAlign\":null},\"content\":[{\"type\":\"text\",\"text\":\"69\"}]}]},{\"type\":\"option\",\"attrs\":{\"letter\":\"B\"},\"content\":[{\"type\":\"paragraph\",\"attrs\":{\"textAlign\":null},\"content\":[{\"type\":\"text\",\"text\":\"70\"}]}]},{\"type\":\"option\",\"attrs\":{\"letter\":\"C\"},\"content\":[{\"type\":\"paragraph\",\"attrs\":{\"textAlign\":null},\"content\":[{\"type\":\"text\",\"text\":\"90\"}]}]},{\"type\":\"option\",\"attrs\":{\"letter\":\"D\"},\"content\":[{\"type\":\"paragraph\",\"attrs\":{\"textAlign\":null},\"content\":[{\"type\":\"text\",\"text\":\"104\"}]}]},{\"type\":\"option\",\"attrs\":{\"letter\":\"E\"},\"content\":[{\"type\":\"paragraph\",\"attrs\":{\"textAlign\":null},\"content\":[{\"type\":\"text\",\"text\":\"105\"}]}]}]}]}]}', NULL),
('6cec3176e2ad92ccc52cdc9de92eccbc', '0052c445-0cee-4fc7-b34a-c1de32dca311', '2026-02-05 18:30:44', '2026-02-05 18:30:44', NULL, '[]', '{\"schemaVersion\":1,\"id\":\"0052c445-0cee-4fc7-b34a-c1de32dca311\",\"createdAt\":\"2026-02-05T18:17:11.763Z\",\"updatedAt\":\"2026-02-05T18:30:36.980Z\",\"tipo\":\"Múltipla Escolha\",\"dificuldade\":\"Média\",\"tags\":[],\"gabarito\":{\"kind\":\"mcq\",\"correct\":\"C\",\"rubric\":null},\"source\":{\"kind\":\"concurso\",\"concurso\":\"UERJ\",\"banca\":\"UERJ\",\"ano\":2025},\"disciplina\":\"Matemática\",\"assunto\":\"Geometria Plana\"}', '{\"type\":\"doc\",\"content\":[{\"type\":\"question\",\"content\":[{\"type\":\"statement\",\"content\":[{\"type\":\"paragraph\",\"attrs\":{\"textAlign\":null},\"content\":[{\"type\":\"text\",\"text\":\"No triângulo equilátero ABC, H corresponde ao ponto médio do lado AC. Desse modo, a área do triângulo ABH é igual à metade da área de ABC.\"}]},{\"type\":\"paragraph\",\"attrs\":{\"textAlign\":null},\"content\":[{\"type\":\"image\",\"attrs\":{\"src\":\"https://mpfaraujo.com.br/guardafiguras/uploads/12fd020bcdf366c7e80da5dd4ec1313f9916eff1206e0bab0847d48f209b5644.png\",\"width\":\"151\",\"align\":\"center\"}}]},{\"type\":\"paragraph\",\"attrs\":{\"textAlign\":null},\"content\":[{\"type\":\"text\",\"text\":\"Sendo W o perímetro do triângulo ABH e Y o perímetro do triângulo ABC, uma relação correta entre W e Y é:\"}]}]},{\"type\":\"options\",\"content\":[{\"type\":\"option\",\"attrs\":{\"letter\":\"A\"},\"content\":[{\"type\":\"paragraph\",\"attrs\":{\"textAlign\":null},\"content\":[{\"type\":\"math_inline\",\"attrs\":{\"latex\":\"0 < W < \\\\frac{Y}{2}\"}}]}]},{\"type\":\"option\",\"attrs\":{\"letter\":\"B\"},\"content\":[{\"type\":\"paragraph\",\"attrs\":{\"textAlign\":null},\"content\":[{\"type\":\"math_inline\",\"attrs\":{\"latex\":\"W = \\\\frac{Y}{2}\"}}]}]},{\"type\":\"option\",\"attrs\":{\"letter\":\"C\"},\"content\":[{\"type\":\"paragraph\",\"attrs\":{\"textAlign\":null},\"content\":[{\"type\":\"math_inline\",\"attrs\":{\"latex\":\"\\\\frac{Y}{2} < W < Y\"}}]}]},{\"type\":\"option\",\"attrs\":{\"letter\":\"D\"},\"content\":[{\"type\":\"paragraph\",\"attrs\":{\"textAlign\":null},\"content\":[{\"type\":\"text\",\"text\":\"W = Y\"}]}]},{\"type\":\"option\",\"attrs\":{\"letter\":\"E\"},\"content\":[{\"type\":\"paragraph\",\"attrs\":{\"textAlign\":null}}]}]}]}]}', NULL),
('6d0c56d62ed28ecbc1ac53879520b9c2', '17697546-c51e-4f22-9bbf-c0e2c4895260', '2026-02-04 12:18:18', '2026-02-04 12:18:18', NULL, '[]', '{\"schemaVersion\":1,\"id\":\"17697546-c51e-4f22-9bbf-c0e2c4895260\",\"createdAt\":\"2026-02-03T21:59:41.067Z\",\"updatedAt\":\"2026-02-04T12:18:13.089Z\",\"tipo\":\"Múltipla Escolha\",\"dificuldade\":\"Média\",\"tags\":[],\"source\":{\"kind\":\"original\"},\"disciplina\":\"Português\",\"assunto\":\"Interporetação de texto\"}', '{\"type\":\"doc\",\"content\":[{\"type\":\"set_questions\",\"content\":[{\"type\":\"base_text\",\"content\":[{\"type\":\"paragraph\",\"attrs\":{\"textAlign\":\"center\"},\"content\":[{\"type\":\"text\",\"text\":\"Maria José \"}]},{\"type\":\"paragraph\",\"attrs\":{\"textAlign\":\"right\"},\"content\":[{\"type\":\"text\",\"text\":\"Paulo Mendes Campos \"}]},{\"type\":\"paragraph\",\"attrs\":{\"textAlign\":null},\"content\":[{\"type\":\"text\",\"text\":\"Faz um ano que Maria José morreu. Era meiga quase sempre, violenta quando necessário. Eu era menino e apanhava de um companheiro maior, quando ela me gritou da sacada se eu não via a pedra que marcava o gol. Dei uma pedrada no outro e acabei com a briga por milagre.\"}]},{\"type\":\"paragraph\",\"attrs\":{\"textAlign\":null},\"content\":[{\"type\":\"text\",\"text\":\"Visitava os miseráveis, internava indigentes enfermos, devotava-se ao alívio de misérias físicas e morais do próximo, estudava o mistério teológico, exigia sempre o mais difícil de si mesma, comungava todos os dias, ingressou na Ordem Terceira de São Francisco. Mas nunca deixou de ter na gaveta o revólver que havia recebido, menina-e-moça, das mãos do pai, e que empunhou no quintal noturno, perse guindo um ladrão, para espanto de meus cinco anos.\"}]},{\"type\":\"paragraph\",\"attrs\":{\"textAlign\":null},\"content\":[{\"type\":\"text\",\"text\":\"Já perto dos setenta anos, ela explicava para um amigo meu que tinha chegado à humildade da velhice; já não se importava com quem tentasse ofendê-la, mas conservava o revólver para a defesa dos filhos e dos netos.\"}]},{\"type\":\"paragraph\",\"attrs\":{\"textAlign\":null},\"content\":[{\"type\":\"text\",\"text\":\"Tratou-me com a dureza e o carinho que mere ciam a rebeldia e o verdor da minha meninice. Ensi nou-me a ler as primeiras sentenças; me falava do Cura d’Ars e nos dois Franciscos, o de Sales e o de Assis; apresentou-me aos contos de Edgar Poe e aos poemas de Baudelaire; dizia-me sorrindo versos de Antônio Nobre que havia decorado quando menina; discutia comigo as ideias finais de Tolstoi; escutava maternalmente meus contos toscos. Quando me desgarrei nos primeiros envolvimentos adolescentes, Maria José, com irônico afeto, me repetia a advertência de Drummond: “Paulo, sossegue, o amor é isso que você está vendo: hoje beija, amanhã não beija, depois de amanhã é domingo e segunda-feira ninguém sabe o que será”.\"}]},{\"type\":\"paragraph\",\"attrs\":{\"textAlign\":null},\"content\":[{\"type\":\"text\",\"text\":\"Logo que me fiz homenzinho, deixou a dureza e se fez minha amiga: nada me perguntava, adivinhava tudo.\"}]},{\"type\":\"paragraph\",\"attrs\":{\"textAlign\":null},\"content\":[{\"type\":\"text\",\"text\":\"Terna e firme, nunca lhe vi a fraqueza da pieguice. Com o gosto espontâneo da qualidade das coisas, renunciou às vaidades mais singelas. Sensível, alegre, aprendeu a encarar o sofrimento de olhos lúcidos. Fiel à disciplina religiosa, compreendia celestialmente as almas que perdiam o rumo. Fé, Esperança e Caridade eram para ela a flecha e o alvo das criaturas.\"}]},{\"type\":\"paragraph\",\"attrs\":{\"textAlign\":null},\"content\":[{\"type\":\"text\",\"text\":\"Tornara-se tão íntima da substância terrestre – a dor – que se fazia difícil para o médico saber o que sentia; acabava dizendo que doía um pouco, por delicadeza.\"}]},{\"type\":\"paragraph\",\"attrs\":{\"textAlign\":null},\"content\":[{\"type\":\"text\",\"text\":\"Capaz de longos jejuns e abstinências, já no final da vida, podia acompanhar um casal amigo a Copacabana, passar do bar da moda ao restaurante diferente, beber dois cafés ou três uísques em santa serenidade e aceitar com alegria o prato exótico.\"}]},{\"type\":\"paragraph\",\"attrs\":{\"textAlign\":null},\"content\":[{\"type\":\"text\",\"text\":\"Gostava das pessoas erradas, consumidas de paixão, admirava São Paulo e Santo Agostinho, acre ditava que era preciso se fazer violência para entrar no reino celeste.\"}]},{\"type\":\"paragraph\",\"attrs\":{\"textAlign\":null},\"content\":[{\"type\":\"text\",\"text\":\"Poucas horas antes de morrer, pediu um conhaque e sorriu, destemida e doce, como quem vai partir para o céu. Santificara-se. Deus era o dia e a noite de seu coração, o Pai, a piedade, o fogo do espírito. Per di quem me amava e perdoava, quem me encomendava à compaixão do Criador e me defendia contra o mundo de revólver na mão.\"}]},{\"type\":\"paragraph\",\"attrs\":{\"textAlign\":\"right\"},\"content\":[{\"type\":\"text\",\"text\":\"Disponível em: https://cronicabrasileira.org.br/cronicas/7173/ma ria-jose. Acesso em: 05 fev. 2022.\"}]}]},{\"type\":\"question_item\",\"attrs\":{\"answerKey\":{\"kind\":\"mcq\",\"correct\":\"A\"}},\"content\":[{\"type\":\"statement\",\"content\":[{\"type\":\"paragraph\",\"attrs\":{\"textAlign\":null},\"content\":[{\"type\":\"text\",\"text\":\"No texto, o narrador apresenta Maria José ao leitor, des crevendo-a a partir de aspectos subjetivos, como em:\"}]}]},{\"type\":\"options\",\"content\":[{\"type\":\"option\",\"attrs\":{\"letter\":\"A\"},\"content\":[{\"type\":\"paragraph\",\"attrs\":{\"textAlign\":null},\"content\":[{\"type\":\"text\",\"text\":\"“Faz um ano que Maria José morreu.” (parágrafo 1)\"}]}]},{\"type\":\"option\",\"attrs\":{\"letter\":\"B\"},\"content\":[{\"type\":\"paragraph\",\"attrs\":{\"textAlign\":null},\"content\":[{\"type\":\"text\",\"text\":\"\\\"Visitava os miseráveis, internava indigentes enfermos” (parágrafo 2)\"}]}]},{\"type\":\"option\",\"attrs\":{\"letter\":\"C\"},\"content\":[{\"type\":\"paragraph\",\"attrs\":{\"textAlign\":null},\"content\":[{\"type\":\"text\",\"text\":\"“comungava todos os dias” (parágrafo 2)\"}]}]},{\"type\":\"option\",\"attrs\":{\"letter\":\"D\"},\"content\":[{\"type\":\"paragraph\",\"attrs\":{\"textAlign\":null},\"content\":[{\"type\":\"text\",\"text\":\"\\\"apresentou-me aos contos de Edgar Poe e aos poemas de Baudelaire” (parágrafo 4)\"}]}]},{\"type\":\"option\",\"attrs\":{\"letter\":\"E\"},\"content\":[{\"type\":\"paragraph\",\"attrs\":{\"textAlign\":null},\"content\":[{\"type\":\"text\",\"text\":\"“Terna e firme, nunca lhe vi a fraqueza da pieguice.” (parágrafo 6)\"}]}]}]}]},{\"type\":\"question_item\",\"attrs\":{\"answerKey\":null},\"content\":[{\"type\":\"statement\",\"content\":[{\"type\":\"paragraph\",\"attrs\":{\"textAlign\":null},\"content\":[{\"type\":\"text\",\"text\":\"De acordo com o narrador, Maria José “Era meiga quase sempre, violenta quando necessário” (parágrafo 1)\"}]},{\"type\":\"paragraph\",\"attrs\":{\"textAlign\":null},\"content\":[{\"type\":\"text\",\"text\":\"Essa violência a que o narrador se refere pode ser com provada no trecho:\"}]}]},{\"type\":\"options\",\"content\":[{\"type\":\"option\",\"attrs\":{\"letter\":\"A\"},\"content\":[{\"type\":\"paragraph\",\"attrs\":{\"textAlign\":null},\"content\":[{\"type\":\"text\",\"text\":\"“ela me gritou da sacada se eu não via a pedra que mar cava o gol. Dei uma pedrada no outro” (parágrafo 1)\"}]}]},{\"type\":\"option\",\"attrs\":{\"letter\":\"B\"},\"content\":[{\"type\":\"paragraph\",\"attrs\":{\"textAlign\":null},\"content\":[{\"type\":\"text\",\"text\":\"\\\"Tratou-me com a dureza e o carinho que mereciam a rebeldia e o verdor da minha meninice.” (parágrafo 4)\"}]}]},{\"type\":\"option\",\"attrs\":{\"letter\":\"C\"},\"content\":[{\"type\":\"paragraph\",\"attrs\":{\"textAlign\":null},\"content\":[{\"type\":\"text\",\"text\":\"“Fé, Esperança e Caridade eram para ela a flecha e o alvo das criaturas.” (parágrafo 6)\"}]}]},{\"type\":\"option\",\"attrs\":{\"letter\":\"D\"},\"content\":[{\"type\":\"paragraph\",\"attrs\":{\"textAlign\":null},\"content\":[{\"type\":\"text\",\"text\":\"Tornara-se tão íntima da substância terrestre – a dor” (parágrafo 7)\"}]}]},{\"type\":\"option\",\"attrs\":{\"letter\":\"E\"},\"content\":[{\"type\":\"paragraph\",\"attrs\":{\"textAlign\":null},\"content\":[{\"type\":\"text\",\"text\":\"“Gostava das pessoas erradas, consumidas de paixão” (parágrafo 9)\"}]}]}]}]}]}]}', NULL),
('6e1ec70f0058f60c028df38a5b45e902', '5acb2baa-cc9f-458f-bcaf-515fa6be33e4', '2026-02-04 12:04:05', '2026-02-04 12:04:05', NULL, '[]', '{\"schemaVersion\":1,\"id\":\"5acb2baa-cc9f-458f-bcaf-515fa6be33e4\",\"createdAt\":\"2026-02-04T10:46:45.284Z\",\"updatedAt\":\"2026-02-04T12:04:00.073Z\",\"tipo\":\"Múltipla Escolha\",\"dificuldade\":\"Média\",\"tags\":[],\"source\":{\"kind\":\"original\"},\"disciplina\":\"Matemática\",\"assunto\":\"Porcentagem\"}', '{\"type\":\"doc\",\"content\":[{\"type\":\"set_questions\",\"content\":[{\"type\":\"base_text\",\"content\":[{\"type\":\"paragraph\",\"attrs\":{\"textAlign\":null},\"content\":[{\"type\":\"text\",\"text\":\"Antes de iniciar uma campanha publicitaria, um banco fez uma pesquisa entre 800 de seus clientes sobre sua intenção de adesão aos seus dois novos produtos. Dos clientes entrevistados, 240 mostraram-se interessados no primeiro produto, 400 mostraram-se interessados no segundo produto e alguns estavam interessados em ambos os produtos. A campanha publicitária só será iniciada caso pelo menos 70% dos entrevistados mostrarem-se interessados em pelo menos um dos produtos.\"}]}]},{\"type\":\"question_item\",\"attrs\":{\"answerKey\":null},\"content\":[{\"type\":\"statement\",\"content\":[{\"type\":\"paragraph\",\"attrs\":{\"textAlign\":null},\"content\":[{\"type\":\"text\",\"text\":\"Qual a porcentagem máxima do total de clientes pode mostrar-se interessados em ambos os produtos para que a campanha publicitária seja iniciada?\"}]}]},{\"type\":\"options\",\"content\":[{\"type\":\"option\",\"attrs\":{\"letter\":\"A\"},\"content\":[{\"type\":\"paragraph\",\"attrs\":{\"textAlign\":null},\"content\":[{\"type\":\"text\",\"text\":\"10%\"}]}]},{\"type\":\"option\",\"attrs\":{\"letter\":\"B\"},\"content\":[{\"type\":\"paragraph\",\"attrs\":{\"textAlign\":null},\"content\":[{\"type\":\"text\",\"text\":\"15%\"}]}]},{\"type\":\"option\",\"attrs\":{\"letter\":\"C\"},\"content\":[{\"type\":\"paragraph\",\"attrs\":{\"textAlign\":null},\"content\":[{\"type\":\"text\",\"text\":\"20%\"}]}]},{\"type\":\"option\",\"attrs\":{\"letter\":\"D\"},\"content\":[{\"type\":\"paragraph\",\"attrs\":{\"textAlign\":null},\"content\":[{\"type\":\"text\",\"text\":\"25%\"}]}]},{\"type\":\"option\",\"attrs\":{\"letter\":\"E\"},\"content\":[{\"type\":\"paragraph\",\"attrs\":{\"textAlign\":null},\"content\":[{\"type\":\"text\",\"text\":\"30%\"}]}]}]}]},{\"type\":\"question_item\",\"attrs\":{\"answerKey\":{\"kind\":\"mcq\",\"correct\":\"E\"}},\"content\":[{\"type\":\"statement\",\"content\":[{\"type\":\"paragraph\",\"attrs\":{\"textAlign\":null},\"content\":[{\"type\":\"text\",\"text\":\"O número de clientes interessados em ambos os produtos não pode ser igual a \"}]}]},{\"type\":\"options\",\"content\":[{\"type\":\"option\",\"attrs\":{\"letter\":\"A\"},\"content\":[{\"type\":\"paragraph\",\"attrs\":{\"textAlign\":null},\"content\":[{\"type\":\"text\",\"text\":\"75\"}]}]},{\"type\":\"option\",\"attrs\":{\"letter\":\"B\"},\"content\":[{\"type\":\"paragraph\",\"attrs\":{\"textAlign\":null},\"content\":[{\"type\":\"text\",\"text\":\"78\"}]}]},{\"type\":\"option\",\"attrs\":{\"letter\":\"C\"},\"content\":[{\"type\":\"paragraph\",\"attrs\":{\"textAlign\":null},\"content\":[{\"type\":\"text\",\"text\":\"79\"}]}]},{\"type\":\"option\",\"attrs\":{\"letter\":\"D\"},\"content\":[{\"type\":\"paragraph\",\"attrs\":{\"textAlign\":null},\"content\":[{\"type\":\"text\",\"text\":\"80\"}]}]},{\"type\":\"option\",\"attrs\":{\"letter\":\"E\"},\"content\":[{\"type\":\"paragraph\",\"attrs\":{\"textAlign\":null},\"content\":[{\"type\":\"text\",\"text\":\"82\"}]}]}]}]}]}]}', NULL),
