('77019731bdb8ba279de9cf155893f4b5', '5ac39756-f156-4a69-95dd-6614fdcbab23', '2026-02-06 12:44:48', '2026-02-06 12:44:48', NULL, '[]', '{\"schemaVersion\":1,\"id\":\"5ac39756-f156-4a69-95dd-6614fdcbab23\",\"createdAt\":\"2026-02-06T12:17:28.728Z\",\"updatedAt\":\"2026-02-06T12:44:32.972Z\",\"tipo\":\"Múltipla Escolha\",\"dificuldade\":\"Média\",\"tags\":[],\"gabarito\":{\"kind\":\"mcq\",\"correct\":\"A\",\"rubric\":null},\"source\":{\"kind\":\"original\"}}', '{\"type\":\"doc\",\"content\":[{\"type\":\"question\",\"content\":[{\"type\":\"statement\",\"content\":[{\"type\":\"paragraph\",\"attrs\":{\"textAlign\":null},\"content\":[{\"type\":\"text\",\"text\":\"No triângulo equilátero ABC, H corresponde ao ponto médio do lado AC. Desse modo, a área do triângulo ABH é igual à metade da área de ABC.\"}]},{\"type\":\"paragraph\",\"attrs\":{\"textAlign\":null},\"content\":[{\"type\":\"image\",\"attrs\":{\"id\":\"1eb02755-c317-48cd-8831-7258d7348d05\",\"src\":\"https://mpfaraujo.com.br/guardafiguras/uploads/12fd020bcdf366c7e80da5dd4ec1313f9916eff1206e0bab0847d48f209b5644.png\",\"width\":\"151\",\"align\":\"center\"}}]},{\"type\":\"paragraph\",\"attrs\":{\"textAlign\":null},\"content\":[{\"type\":\"text\",\"text\":\"Sendo W o perímetro do triângulo ABH e Y o perímetro do triângulo ABC, uma relação correta entre W e Y é:\"}]}]},{\"type\":\"options\",\"content\":[{\"type\":\"option\",\"attrs\":{\"letter\":\"A\"},\"content\":[{\"type\":\"paragraph\",\"attrs\":{\"textAlign\":null},\"content\":[{\"type\":\"math_inline\",\"attrs\":{\"latex\":\"0 < W < \\\\frac{Y}{2}\"}}]}]},{\"type\":\"option\",\"attrs\":{\"letter\":\"B\"},\"content\":[{\"type\":\"paragraph\",\"attrs\":{\"textAlign\":null},\"content\":[{\"type\":\"math_inline\",\"attrs\":{\"latex\":\"W = \\\\frac{Y}{2}\"}}]}]},{\"type\":\"option\",\"attrs\":{\"letter\":\"C\"},\"content\":[{\"type\":\"paragraph\",\"attrs\":{\"textAlign\":null},\"content\":[{\"type\":\"math_inline\",\"attrs\":{\"latex\":\"\\\\frac{Y}{2} < W < Y\"}}]}]},{\"type\":\"option\",\"attrs\":{\"letter\":\"D\"},\"content\":[{\"type\":\"paragraph\",\"attrs\":{\"textAlign\":null},\"content\":[{\"type\":\"text\",\"text\":\"W = Y\"}]}]}]}]}]}', NULL),
('7d26e3935a38787bbd2d13b5e8f8b058', '56fc0820-e5a8-4dce-9892-6d5d663dac6e', '2026-02-06 13:47:27', '2026-02-06 13:47:27', NULL, '[]', '{\"schemaVersion\":1,\"id\":\"56fc0820-e5a8-4dce-9892-6d5d663dac6e\",\"createdAt\":\"2026-02-05T18:24:50.607Z\",\"updatedAt\":\"2026-02-06T13:47:12.443Z\",\"tipo\":\"Múltipla Escolha\",\"dificuldade\":\"Média\",\"tags\":[],\"gabarito\":{\"kind\":\"mcq\",\"correct\":\"B\",\"rubric\":null},\"source\":{\"kind\":\"concurso\",\"concurso\":\"UERJ\",\"banca\":\"UERJ\",\"ano\":2025},\"disciplina\":\"Matemática\",\"assunto\":\"Geometria Espacial\"}', '{\"type\":\"doc\",\"content\":[{\"type\":\"question\",\"content\":[{\"type\":\"statement\",\"content\":[{\"type\":\"paragraph\",\"attrs\":{\"textAlign\":null},\"content\":[{\"type\":\"text\",\"text\":\"A imagem a seguir ilustra um prisma triangular regular. Sua aresta da base mede b e sua aresta lateral mede h.\"}]},{\"type\":\"paragraph\",\"attrs\":{\"textAlign\":null},\"content\":[{\"type\":\"image\",\"attrs\":{\"id\":\"75628bb0-3009-4ca7-921b-75810c1560a8\",\"src\":\"https://mpfaraujo.com.br/guardafiguras/uploads/a82e1527810b15daac2f84b3ec54f2914299f5758ff1d9828e094401faae650e.png\",\"width\":\"302\",\"align\":\"center\"}}]},{\"type\":\"paragraph\",\"attrs\":{\"textAlign\":null},\"content\":[{\"type\":\"text\",\"text\":\"Esse prisma é seccionado por um plano BCP, de modo que o volume da pirâmide ABCP seja exatamente \"},{\"type\":\"math_inline\",\"attrs\":{\"latex\":\"\\\\frac{1}{ 9}\"}},{\"type\":\"text\",\"text\":\" do volume total do prisma.\"}]},{\"type\":\"paragraph\",\"attrs\":{\"textAlign\":null},\"content\":[{\"type\":\"text\",\"text\":\"Logo, a medida de AP é igual a:\"}]}]},{\"type\":\"options\",\"content\":[{\"type\":\"option\",\"attrs\":{\"letter\":\"A\"},\"content\":[{\"type\":\"paragraph\",\"attrs\":{\"textAlign\":null},\"content\":[{\"type\":\"math_inline\",\"attrs\":{\"latex\":\"\\\\frac{h} {9}\"}}]}]},{\"type\":\"option\",\"attrs\":{\"letter\":\"B\"},\"content\":[{\"type\":\"paragraph\",\"attrs\":{\"textAlign\":null},\"content\":[{\"type\":\"math_inline\",\"attrs\":{\"latex\":\"\\\\frac{h}{3}\"}}]}]},{\"type\":\"option\",\"attrs\":{\"letter\":\"C\"},\"content\":[{\"type\":\"paragraph\",\"attrs\":{\"textAlign\":null},\"content\":[{\"type\":\"math_inline\",\"attrs\":{\"latex\":\"\\\\frac{2h}{3}\"}}]}]},{\"type\":\"option\",\"attrs\":{\"letter\":\"D\"},\"content\":[{\"type\":\"paragraph\",\"attrs\":{\"textAlign\":null},\"content\":[{\"type\":\"math_inline\",\"attrs\":{\"latex\":\"\\\\frac{5h}{6}\"}}]}]}]}]}]}', NULL),
('7e8af0961d206257a4bab11b0af2d59f', '5acb2baa-cc9f-458f-bcaf-515fa6be33e4', '2026-02-04 12:46:16', '2026-02-04 12:46:16', NULL, '[]', '{\"schemaVersion\":1,\"id\":\"5acb2baa-cc9f-458f-bcaf-515fa6be33e4\",\"createdAt\":\"2026-02-04T10:46:45.284Z\",\"updatedAt\":\"2026-02-04T12:46:10.949Z\",\"tipo\":\"Múltipla Escolha\",\"dificuldade\":\"Média\",\"tags\":[],\"source\":{\"kind\":\"original\"},\"disciplina\":\"Matemática\",\"assunto\":\"Porcentagem\"}', '{\"type\":\"doc\",\"content\":[{\"type\":\"set_questions\",\"content\":[{\"type\":\"base_text\",\"content\":[{\"type\":\"paragraph\",\"attrs\":{\"textAlign\":null},\"content\":[{\"type\":\"text\",\"text\":\"Antes de iniciar uma campanha publicitaria, um banco fez uma pesquisa entre 800 de seus clientes sobre sua intenção de adesão aos seus dois novos produtos. Dos clientes entrevistados, 240 mostraram-se interessados no primeiro produto, 400 mostraram-se interessados no segundo produto e alguns estavam interessados em ambos os produtos. A campanha publicitária só será iniciada caso pelo menos 70% dos entrevistados mostrarem-se interessados em pelo menos um dos produtos.\"}]}]},{\"type\":\"question_item\",\"attrs\":{\"answerKey\":null},\"content\":[{\"type\":\"statement\",\"content\":[{\"type\":\"paragraph\",\"attrs\":{\"textAlign\":null},\"content\":[{\"type\":\"text\",\"text\":\"Qual a porcentagem máxima do total de clientes pode mostrar-se interessados em ambos os produtos para que a campanha publicitária seja iniciada?\"}]}]},{\"type\":\"options\",\"content\":[{\"type\":\"option\",\"attrs\":{\"letter\":\"A\"},\"content\":[{\"type\":\"paragraph\",\"attrs\":{\"textAlign\":null},\"content\":[{\"type\":\"text\",\"text\":\"10%\"}]}]},{\"type\":\"option\",\"attrs\":{\"letter\":\"B\"},\"content\":[{\"type\":\"paragraph\",\"attrs\":{\"textAlign\":null},\"content\":[{\"type\":\"text\",\"text\":\"15%\"}]}]},{\"type\":\"option\",\"attrs\":{\"letter\":\"C\"},\"content\":[{\"type\":\"paragraph\",\"attrs\":{\"textAlign\":null},\"content\":[{\"type\":\"text\",\"text\":\"20%\"}]}]},{\"type\":\"option\",\"attrs\":{\"letter\":\"D\"},\"content\":[{\"type\":\"paragraph\",\"attrs\":{\"textAlign\":null},\"content\":[{\"type\":\"text\",\"text\":\"25%\"}]}]},{\"type\":\"option\",\"attrs\":{\"letter\":\"E\"},\"content\":[{\"type\":\"paragraph\",\"attrs\":{\"textAlign\":null},\"content\":[{\"type\":\"text\",\"text\":\"30%\"}]}]}]}]},{\"type\":\"question_item\",\"attrs\":{\"answerKey\":{\"kind\":\"mcq\",\"correct\":\"E\"}},\"content\":[{\"type\":\"statement\",\"content\":[{\"type\":\"paragraph\",\"attrs\":{\"textAlign\":null},\"content\":[{\"type\":\"text\",\"text\":\"O número de clientes interessados em ambos os produtos não pode ser igual a \"}]}]},{\"type\":\"options\",\"content\":[{\"type\":\"option\",\"attrs\":{\"letter\":\"A\"},\"content\":[{\"type\":\"paragraph\",\"attrs\":{\"textAlign\":null},\"content\":[{\"type\":\"text\",\"text\":\"75\"}]}]},{\"type\":\"option\",\"attrs\":{\"letter\":\"B\"},\"content\":[{\"type\":\"paragraph\",\"attrs\":{\"textAlign\":null},\"content\":[{\"type\":\"text\",\"text\":\"78\"}]}]},{\"type\":\"option\",\"attrs\":{\"letter\":\"C\"},\"content\":[{\"type\":\"paragraph\",\"attrs\":{\"textAlign\":null},\"content\":[{\"type\":\"text\",\"text\":\"79\"}]}]},{\"type\":\"option\",\"attrs\":{\"letter\":\"D\"},\"content\":[{\"type\":\"paragraph\",\"attrs\":{\"textAlign\":null},\"content\":[{\"type\":\"text\",\"text\":\"80\"}]}]},{\"type\":\"option\",\"attrs\":{\"letter\":\"E\"},\"content\":[{\"type\":\"paragraph\",\"attrs\":{\"textAlign\":null},\"content\":[{\"type\":\"text\",\"text\":\"82\"}]}]}]}]}]}]}', NULL),
('7fb911836b7d9f553066e84543c59a24', '7dfd937b-5d59-48a9-838f-bc6c7fb6d1c5', '2026-01-31 14:43:08', '2026-01-31 14:43:08', NULL, '[]', '{\"schemaVersion\":1,\"id\":\"7dfd937b-5d59-48a9-838f-bc6c7fb6d1c5\",\"createdAt\":\"2026-01-30T11:07:32.245Z\",\"updatedAt\":\"2026-01-31T14:43:03.619Z\",\"tipo\":\"Múltipla Escolha\",\"dificuldade\":\"Média\",\"tags\":[],\"gabarito\":{\"kind\":\"mcq\",\"correct\":\"A\"},\"source\":{\"kind\":\"original\"}}', '{\"type\":\"doc\",\"content\":[{\"type\":\"question\",\"content\":[{\"type\":\"statement\",\"content\":[{\"type\":\"paragraph\",\"attrs\":{\"textAlign\":null},\"content\":[{\"type\":\"text\",\"text\":\"Uma instituição de ensino superior ofereceu vagas em um processo seletivo de acesso a seus cursos. Finalizadas as inscrições, foi divulgada a relação do número de candidatos por vaga em cada um dos cursos oferecidos. Esses dados são apresentados no quadro.\"}]},{\"type\":\"paragraph\",\"attrs\":{\"textAlign\":null},\"content\":[{\"type\":\"image\",\"attrs\":{\"src\":\"https://mpfaraujo.com.br/guardafiguras/uploads/a0e96146111116b5c315ac46a9b09799ef52183b8a38017004f57960cad2f62e.png\",\"width\":\"227\",\"align\":\"center\"}},{\"type\":\"text\",\"text\":\"Qual foi o número total de candidatos inscritos nesse processo seletivo?\"}]}]},{\"type\":\"options\",\"content\":[{\"type\":\"option\",\"attrs\":{\"letter\":\"A\"},\"content\":[{\"type\":\"paragraph\",\"attrs\":{\"textAlign\":null},\"content\":[{\"type\":\"text\",\"text\":\"200\"}]}]},{\"type\":\"option\",\"attrs\":{\"letter\":\"B\"},\"content\":[{\"type\":\"paragraph\",\"attrs\":{\"textAlign\":null},\"content\":[{\"type\":\"text\",\"text\":\"400\"}]}]},{\"type\":\"option\",\"attrs\":{\"letter\":\"C\"},\"content\":[{\"type\":\"paragraph\",\"attrs\":{\"textAlign\":null},\"content\":[{\"type\":\"text\",\"text\":\"1 200\"}]}]},{\"type\":\"option\",\"attrs\":{\"letter\":\"D\"},\"content\":[{\"type\":\"paragraph\",\"attrs\":{\"textAlign\":null},\"content\":[{\"type\":\"text\",\"text\":\"1 235\"}]}]},{\"type\":\"option\",\"attrs\":{\"letter\":\"E\"},\"content\":[{\"type\":\"paragraph\",\"attrs\":{\"textAlign\":null},\"content\":[{\"type\":\"text\",\"text\":\"7 200\"}]}]}]}]}]}', NULL),
('82450183686e12088503d3a2ccbca78f', '17697546-c51e-4f22-9bbf-c0e2c4895260', '2026-02-04 01:07:56', '2026-02-04 01:07:56', NULL, '[]', '{\"schemaVersion\":1,\"id\":\"17697546-c51e-4f22-9bbf-c0e2c4895260\",\"createdAt\":\"2026-02-03T21:59:41.067Z\",\"updatedAt\":\"2026-02-04T01:07:51.592Z\",\"tipo\":\"Múltipla Escolha\",\"dificuldade\":\"Média\",\"tags\":[],\"gabarito\":{\"kind\":\"mcq\",\"correct\":\"A\"},\"source\":{\"kind\":\"original\"}}', '{\"type\":\"doc\",\"content\":[{\"type\":\"set_questions\",\"content\":[{\"type\":\"base_text\",\"content\":[{\"type\":\"paragraph\",\"attrs\":{\"textAlign\":\"center\"},\"content\":[{\"type\":\"text\",\"text\":\"Maria José \"}]},{\"type\":\"paragraph\",\"attrs\":{\"textAlign\":\"right\"},\"content\":[{\"type\":\"text\",\"text\":\"Paulo Mendes Campos \"}]},{\"type\":\"paragraph\",\"attrs\":{\"textAlign\":null},\"content\":[{\"type\":\"text\",\"text\":\"Faz um ano que Maria José morreu. Era meiga quase sempre, violenta quando necessário. Eu era menino e apanhava de um companheiro maior, quando ela me gritou da sacada se eu não via a pedra que marcava o gol. Dei uma pedrada no outro e acabei com a briga por milagre.\"}]},{\"type\":\"paragraph\",\"attrs\":{\"textAlign\":null},\"content\":[{\"type\":\"text\",\"text\":\"Visitava os miseráveis, internava indigentes enfermos, devotava-se ao alívio de misérias físicas e morais do próximo, estudava o mistério teológico, exigia sempre o mais difícil de si mesma, comungava todos os dias, ingressou na Ordem Terceira de São Francisco. Mas nunca deixou de ter na gaveta o revólver que havia recebido, menina-e-moça, das mãos do pai, e que empunhou no quintal noturno, perse guindo um ladrão, para espanto de meus cinco anos.\"}]},{\"type\":\"paragraph\",\"attrs\":{\"textAlign\":null},\"content\":[{\"type\":\"text\",\"text\":\"Já perto dos setenta anos, ela explicava para um amigo meu que tinha chegado à humildade da velhice; já não se importava com quem tentasse ofendê-la, mas conservava o revólver para a defesa dos filhos e dos netos.\"}]},{\"type\":\"paragraph\",\"attrs\":{\"textAlign\":null},\"content\":[{\"type\":\"text\",\"text\":\"Tratou-me com a dureza e o carinho que mere ciam a rebeldia e o verdor da minha meninice. Ensi nou-me a ler as primeiras sentenças; me falava do Cura d’Ars e nos dois Franciscos, o de Sales e o de Assis; apresentou-me aos contos de Edgar Poe e aos poemas de Baudelaire; dizia-me sorrindo versos de Antônio Nobre que havia decorado quando menina; discutia comigo as ideias finais de Tolstoi; escutava maternalmente meus contos toscos. Quando me desgarrei nos primeiros envolvimentos adolescentes, Maria José, com irônico afeto, me repetia a advertência de Drummond: “Paulo, sossegue, o amor é isso que você está vendo: hoje beija, amanhã não beija, depois de amanhã é domingo e segunda-feira ninguém sabe o que será”.\"}]},{\"type\":\"paragraph\",\"attrs\":{\"textAlign\":null},\"content\":[{\"type\":\"text\",\"text\":\"Logo que me fiz homenzinho, deixou a dureza e se fez minha amiga: nada me perguntava, adivinhava tudo.\"}]},{\"type\":\"paragraph\",\"attrs\":{\"textAlign\":null},\"content\":[{\"type\":\"text\",\"text\":\"Terna e firme, nunca lhe vi a fraqueza da pieguice. Com o gosto espontâneo da qualidade das coisas, renunciou às vaidades mais singelas. Sensível, alegre, aprendeu a encarar o sofrimento de olhos lúcidos. Fiel à disciplina religiosa, compreendia celestialmente as almas que perdiam o rumo. Fé, Esperança e Caridade eram para ela a flecha e o alvo das criaturas.\"}]},{\"type\":\"paragraph\",\"attrs\":{\"textAlign\":null},\"content\":[{\"type\":\"text\",\"text\":\"Tornara-se tão íntima da substância terrestre – a dor – que se fazia difícil para o médico saber o que sentia; acabava dizendo que doía um pouco, por delicadeza.\"}]},{\"type\":\"paragraph\",\"attrs\":{\"textAlign\":null},\"content\":[{\"type\":\"text\",\"text\":\"Capaz de longos jejuns e abstinências, já no final da vida, podia acompanhar um casal amigo a Copacabana, passar do bar da moda ao restaurante diferente, beber dois cafés ou três uísques em santa serenidade e aceitar com alegria o prato exótico.\"}]},{\"type\":\"paragraph\",\"attrs\":{\"textAlign\":null},\"content\":[{\"type\":\"text\",\"text\":\"Gostava das pessoas erradas, consumidas de paixão, admirava São Paulo e Santo Agostinho, acre ditava que era preciso se fazer violência para entrar no reino celeste.\"}]},{\"type\":\"paragraph\",\"attrs\":{\"textAlign\":null},\"content\":[{\"type\":\"text\",\"text\":\"Poucas horas antes de morrer, pediu um conhaque e sorriu, destemida e doce, como quem vai partir para o céu. Santificara-se. Deus era o dia e a noite de seu coração, o Pai, a piedade, o fogo do espírito. Per di quem me amava e perdoava, quem me encomendava à compaixão do Criador e me defendia contra o mundo de revólver na mão.\"}]},{\"type\":\"paragraph\",\"attrs\":{\"textAlign\":\"right\"},\"content\":[{\"type\":\"text\",\"text\":\"Disponível em: https://cronicabrasileira.org.br/cronicas/7173/ma ria-jose. Acesso em: 05 fev. 2022.\"}]}]},{\"type\":\"question_item\",\"content\":[{\"type\":\"statement\",\"content\":[{\"type\":\"paragraph\",\"attrs\":{\"textAlign\":null},\"content\":[{\"type\":\"text\",\"text\":\"No texto, o narrador apresenta Maria José ao leitor, des crevendo-a a partir de aspectos subjetivos, como em:\"}]}]},{\"type\":\"options\",\"content\":[{\"type\":\"option\",\"attrs\":{\"letter\":\"A\"},\"content\":[{\"type\":\"paragraph\",\"attrs\":{\"textAlign\":null},\"content\":[{\"type\":\"text\",\"text\":\"“Faz um ano que Maria José morreu.” (parágrafo 1)\"}]}]},{\"type\":\"option\",\"attrs\":{\"letter\":\"B\"},\"content\":[{\"type\":\"paragraph\",\"attrs\":{\"textAlign\":null},\"content\":[{\"type\":\"text\",\"text\":\"\\\"Visitava os miseráveis, internava indigentes enfermos” (parágrafo 2)\"}]}]},{\"type\":\"option\",\"attrs\":{\"letter\":\"C\"},\"content\":[{\"type\":\"paragraph\",\"attrs\":{\"textAlign\":null},\"content\":[{\"type\":\"text\",\"text\":\"“comungava todos os dias” (parágrafo 2)\"}]}]},{\"type\":\"option\",\"attrs\":{\"letter\":\"D\"},\"content\":[{\"type\":\"paragraph\",\"attrs\":{\"textAlign\":null},\"content\":[{\"type\":\"text\",\"text\":\"\\\"apresentou-me aos contos de Edgar Poe e aos poemas de Baudelaire” (parágrafo 4)\"}]}]},{\"type\":\"option\",\"attrs\":{\"letter\":\"E\"},\"content\":[{\"type\":\"paragraph\",\"attrs\":{\"textAlign\":null},\"content\":[{\"type\":\"text\",\"text\":\"“Terna e firme, nunca lhe vi a fraqueza da pieguice.” (parágrafo 6)\"}]}]}]}]},{\"type\":\"question_item\",\"content\":[{\"type\":\"statement\",\"content\":[{\"type\":\"paragraph\",\"attrs\":{\"textAlign\":null},\"content\":[{\"type\":\"text\",\"text\":\"De acordo com o narrador, Maria José “Era meiga quase sempre, violenta quando necessário” (parágrafo 1)\"}]},{\"type\":\"paragraph\",\"attrs\":{\"textAlign\":null},\"content\":[{\"type\":\"text\",\"text\":\"Essa violência a que o narrador se refere pode ser com provada no trecho:\"}]}]},{\"type\":\"options\",\"content\":[{\"type\":\"option\",\"attrs\":{\"letter\":\"A\"},\"content\":[{\"type\":\"paragraph\",\"attrs\":{\"textAlign\":null},\"content\":[{\"type\":\"text\",\"text\":\"“ela me gritou da sacada se eu não via a pedra que mar cava o gol. Dei uma pedrada no outro” (parágrafo 1)\"}]}]},{\"type\":\"option\",\"attrs\":{\"letter\":\"B\"},\"content\":[{\"type\":\"paragraph\",\"attrs\":{\"textAlign\":null},\"content\":[{\"type\":\"text\",\"text\":\"\\\"Tratou-me com a dureza e o carinho que mereciam a rebeldia e o verdor da minha meninice.” (parágrafo 4)\"}]}]},{\"type\":\"option\",\"attrs\":{\"letter\":\"C\"},\"content\":[{\"type\":\"paragraph\",\"attrs\":{\"textAlign\":null},\"content\":[{\"type\":\"text\",\"text\":\"“Fé, Esperança e Caridade eram para ela a flecha e o alvo das criaturas.” (parágrafo 6)\"}]}]},{\"type\":\"option\",\"attrs\":{\"letter\":\"D\"},\"content\":[{\"type\":\"paragraph\",\"attrs\":{\"textAlign\":null},\"content\":[{\"type\":\"text\",\"text\":\"Tornara-se tão íntima da substância terrestre – a dor” (parágrafo 7)\"}]}]},{\"type\":\"option\",\"attrs\":{\"letter\":\"E\"},\"content\":[{\"type\":\"paragraph\",\"attrs\":{\"textAlign\":null},\"content\":[{\"type\":\"text\",\"text\":\"“Gostava das pessoas erradas, consumidas de paixão” (parágrafo 9)\"}]}]}]}]}]}]}', NULL),
