('999741b17c2dc430102d42a03497605d', '81683cfe-f423-4c1f-a3b6-d93306088b8c', '2026-02-06 20:57:21', '2026-02-06 20:57:21', NULL, '[]', '{\"schemaVersion\":1,\"id\":\"81683cfe-f423-4c1f-a3b6-d93306088b8c\",\"createdAt\":\"2026-02-06T19:58:46.736Z\",\"updatedAt\":\"2026-02-06T20:57:05.898Z\",\"tipo\":\"Múltipla Escolha\",\"dificuldade\":\"Média\",\"tags\":[],\"gabarito\":{\"kind\":\"mcq\",\"correct\":\"B\",\"rubric\":null},\"source\":{\"kind\":\"concurso\",\"concurso\":\"ENEM\",\"banca\":\"INEP\"},\"assunto\":\"Análise Combinatória\",\"disciplina\":\"Matemática\"}', '{\"type\":\"doc\",\"content\":[{\"type\":\"question\",\"content\":[{\"type\":\"statement\",\"content\":[{\"type\":\"paragraph\",\"attrs\":{\"textAlign\":null},\"content\":[{\"type\":\"text\",\"text\":\"Uma montadora de automóveis divulgou que oferta a seus clientes mais de 1.000 configurações diferentes de carro, variando o modelo, a motorização, os opcionais e a cor do veículo. Atualmente, ela oferece 7 modelos de carros com 2 tipos de motores: 1.0 e 1.6. Já em relação aos opcionais, existem 3 escolhas possíveis: central multimídia, rodas de liga leve e bancos de couro, podendo o cliente optar por incluir um, dois, três ou nenhum dos opcionais disponíveis.\"}]},{\"type\":\"paragraph\",\"attrs\":{\"textAlign\":null},\"content\":[{\"type\":\"text\",\"text\":\"Para ser fiel à divulgação feita, a quantidade mínima de cores que a montadora deverá disponibilizar a seus clientes é\"}]}]},{\"type\":\"options\",\"content\":[{\"type\":\"option\",\"attrs\":{\"letter\":\"A\"},\"content\":[{\"type\":\"paragraph\",\"attrs\":{\"textAlign\":null},\"content\":[{\"type\":\"text\",\"text\":\"8.\"}]}]},{\"type\":\"option\",\"attrs\":{\"letter\":\"B\"},\"content\":[{\"type\":\"paragraph\",\"attrs\":{\"textAlign\":null},\"content\":[{\"type\":\"text\",\"text\":\"9.\"}]}]},{\"type\":\"option\",\"attrs\":{\"letter\":\"C\"},\"content\":[{\"type\":\"paragraph\",\"attrs\":{\"textAlign\":null},\"content\":[{\"type\":\"text\",\"text